import type { NextConfig } from "next";
import withPWAInit from "@ducanh2912/next-pwa";

const withPWA = withPWAInit({
  dest: "public",
  cacheOnFrontEndNav: true,
  aggressiveFrontEndNavCaching: true,
  reloadOnOnline: true,
  disable: process.env.NODE_ENV === "development",
  workboxOptions: {
    disableDevLogs: true,
  },
});

const nextConfig: NextConfig = {
  output: 'standalone',
  /* config options here */
  transpilePackages: ["@ducanh2912/next-pwa"],
  // @ts-ignore
  turbopack: {},
};

export default withPWA(nextConfig);

'use client';
import { useState, useEffect } from 'react';
import { TrendingUp, TrendingDown, DollarSign, Receipt, Calculator, ArrowUpRight, ArrowDownRight, Briefcase, FileText, Download, ChartBar } from 'lucide-react';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';
import { utils, writeFile } from 'xlsx';
import { formatCurrency as curr } from '@/utils/formatters';


interface Summary {
  totalRevenue: number;
  totalCashRevenue: number;
  accountsReceivable: number;
  totalExpenses: number;
  grossProfit: number;
  taxBalance: number;
  salesCount: number;
  purchasesCount: number;
}

export default function AccountingPage() {
  const [summary, setSummary] = useState<Summary | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchSummary();
  }, []);

  const fetchSummary = async () => {
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/accounting/summary`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      if (res.ok) {
        const data = await res.json();
        setSummary(data);
      }
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const exportToPDF = () => {
    if (!summary) return;
    const doc = new jsPDF();
    
    // Header
    doc.setFontSize(20);
    doc.setTextColor(40);
    doc.text('TIENDEO POS - REPORTE CONTABLE', 14, 22);
    
    doc.setFontSize(10);
    doc.setTextColor(100);
    doc.text(`Fecha de generación: ${new Date().toLocaleString('es-CO')}`, 14, 30);
    
    // Summary Data
    autoTable(doc, {
      startY: 40,
      head: [['Indicador', 'Valor']],
      body: [
        ['Total Facturado (Revenue)', `$${curr(summary.totalRevenue)}`],
        ['Ingresos en Efectivo/Tarjeta', `$${curr(summary.totalCashRevenue)}`],
        ['Cuentas por Cobrar (Créditos)', `$${curr(summary.accountsReceivable)}`],
        ['Egresos Totales (Compras)', `$${curr(summary.totalExpenses)}`],
        ['Utilidad Bruta', `$${curr(summary.grossProfit)}`],
        ['IVA por Pagar (Ventas 19%)', `$${curr(summary.totalRevenue * 0.19)}`],
        ['IVA a Favor (Compras)', `$${curr(summary.taxBalance + (summary.totalRevenue * 0.19))}`],
        ['Saldo IVA Neto', `${curr(Math.abs(summary.taxBalance))} (${summary.taxBalance >= 0 ? 'Por Pagar' : 'A Favor'})`],
      ],
      theme: 'striped',
      headStyles: { fillColor: [37, 99, 235] }
    });
    
    doc.save(`Reporte_Contable_${new Date().getTime()}.pdf`);
  };

  const exportToExcel = () => {
    if (!summary) return;
    const data = [
      { Concepto: 'Total Facturado (Revenue)', Valor: summary.totalRevenue },
      { Concepto: 'Ingresos Efectivo/Tarjeta', Valor: summary.totalCashRevenue },
      { Concepto: 'Cuentas por Cobrar (Crédito)', Valor: summary.accountsReceivable },
      { Concepto: 'Egresos Totales (Compras)', Valor: summary.totalExpenses },
      { Concepto: 'Utilidad Bruta', Valor: summary.grossProfit },
      { Concepto: 'IVA por Pagar (Ventas 19%)', Valor: Math.round(summary.totalRevenue * 0.19) },
      { Concepto: 'IVA a Favor (Compras)', Valor: Math.round(summary.taxBalance + (summary.totalRevenue * 0.19)) },
      { Concepto: 'Saldo IVA Neto', Valor: summary.taxBalance },
    ];
    
    const ws = utils.json_to_sheet(data);
    const wb = utils.book_new();
    utils.book_append_sheet(wb, ws, 'Resumen Contable');
    writeFile(wb, `Contabilidad_Tiendeo_${new Date().getTime()}.xlsx`);
  };

  if (loading) return <div className="p-8 text-center text-slate-500">Cargando contabilidad...</div>;
  if (!summary) return <div className="p-8 text-center text-red-500">Error al cargar el resumen financiero.</div>;

  return (
    <div className="space-y-8 max-w-7xl mx-auto pb-12 animate-in fade-in duration-700">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
          <h2 className="text-3xl font-extrabold tracking-tight text-slate-900 dark:text-white">
            Contabilidad y Finanzas
          </h2>
          <p className="mt-1 text-sm text-slate-500 dark:text-slate-400">
            Resumen ejecutivo digital. Exporta tus datos para tu contador.
          </p>
        </div>
        
        <div className="flex gap-3 flex-wrap">
          <button 
            onClick={exportToPDF}
            className="flex items-center gap-2 bg-blue-600 text-white px-5 py-3 rounded-2xl font-bold hover:bg-blue-700 transition-all shadow-lg shadow-blue-500/20 active:scale-95"
          >
            <FileText className="w-5 h-5" />
            Descargar PDF
          </button>
          <button 
            onClick={exportToExcel}
            className="flex items-center gap-2 bg-emerald-600 text-white px-5 py-3 rounded-2xl font-bold hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-500/20 active:scale-95"
          >
            <Download className="w-5 h-5" />
            Exportar Excel
          </button>
        </div>
      </div>

      {/* Tarjetas de Resumen */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm transition-all hover:scale-[1.02]">
          <div className="flex justify-between items-start mb-4">
            <div className="p-3 bg-blue-50 dark:bg-blue-900/20 rounded-2xl text-blue-600">
              <TrendingUp className="w-6 h-6" />
            </div>
            <span className="flex items-center text-xs font-bold text-blue-600 bg-blue-50 dark:bg-blue-900/20 px-2 py-1 rounded-lg">
              Total
            </span>
          </div>
          <p className="text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Total Facturado</p>
          <h3 className="text-2xl font-black text-slate-900 dark:text-white mt-1">
            ${curr(summary.totalRevenue)}
          </h3>
        </div>

        <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm transition-all hover:scale-[1.02]">
          <div className="flex justify-between items-start mb-4">
            <div className="p-3 bg-green-50 dark:bg-green-900/20 rounded-2xl text-green-600">
              <DollarSign className="w-6 h-6" />
            </div>
            <span className="flex items-center text-xs font-bold text-green-600 bg-green-50 dark:bg-green-900/20 px-2 py-1 rounded-lg">
              Caja
            </span>
          </div>
          <p className="text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Ingresos Efectivo</p>
          <h3 className="text-2xl font-black text-slate-900 dark:text-white mt-1">
            ${curr(summary.totalCashRevenue)}
          </h3>
        </div>

        <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm transition-all hover:scale-[1.02]">
          <div className="flex justify-between items-start mb-4">
            <div className="p-3 bg-orange-50 dark:bg-orange-900/20 rounded-2xl text-orange-600">
              <ArrowUpRight className="w-6 h-6" />
            </div>
            <span className="flex items-center text-xs font-bold text-orange-600 bg-orange-50 dark:bg-orange-900/20 px-2 py-1 rounded-lg">
              Crédito
            </span>
          </div>
          <p className="text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Cuentas por Cobrar</p>
          <h3 className="text-2xl font-black text-slate-900 dark:text-white mt-1">
            ${curr(summary.accountsReceivable)}
          </h3>
        </div>

        <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm transition-all hover:scale-[1.02]">
          <div className="flex justify-between items-start mb-4">
            <div className="p-3 bg-rose-50 dark:bg-rose-900/20 rounded-2xl text-rose-600">
              <TrendingDown className="w-6 h-6" />
            </div>
            <span className="flex items-center text-xs font-bold text-rose-600 bg-rose-50 dark:bg-rose-900/20 px-2 py-1 rounded-lg">
              <ArrowDownRight className="w-3 h-3 mr-1" /> Gastos
            </span>
          </div>
          <p className="text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Egresos Totales (Compras)</p>
          <h3 className="text-3xl font-black text-slate-900 dark:text-white mt-1">
            ${curr(summary.totalExpenses)}
          </h3>
          <p className="text-[10px] text-slate-400 mt-2 font-bold uppercase">{summary.purchasesCount} facturas de proveedores</p>
        </div>

        <div className="bg-emerald-600 p-6 rounded-3xl shadow-xl shadow-emerald-500/20 transition-all hover:scale-[1.02]">
          <div className="flex justify-between items-start mb-4">
            <div className="p-3 bg-white/20 rounded-2xl text-white">
              <DollarSign className="w-6 h-6" />
            </div>
            <Briefcase className="w-5 h-5 text-white/40" />
          </div>
          <p className="text-sm font-bold text-emerald-100 uppercase tracking-wider">Utilidad Bruta</p>
          <h3 className="text-3xl font-black text-white mt-1">
            ${curr(summary.grossProfit)}
          </h3>
          <p className="text-[10px] text-white/60 mt-2 font-bold uppercase">Rentabilidad calculada</p>
        </div>
      </div>

      {/* Detalle Contable Adicional */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800">
          <h4 className="flex items-center gap-2 text-lg font-bold text-slate-900 dark:text-white mb-6">
            <Calculator className="text-blue-600 w-5 h-5" /> Balance Tributario Estimado
          </h4>
          <div className="space-y-4">
            <div className="flex justify-between items-center p-4 bg-slate-50 dark:bg-slate-800/40 rounded-2xl">
              <span className="text-sm font-bold text-slate-600 dark:text-slate-400">IVA por Pagar (Ventas 19%)</span>
              <span className="text-sm font-black text-rose-600">${curr(summary.totalRevenue * 0.19)}</span>
            </div>
            <div className="flex justify-between items-center p-4 bg-slate-50 dark:bg-slate-800/40 rounded-2xl">
              <span className="text-sm font-bold text-slate-600 dark:text-slate-400">IVA a Favor (Compras)</span>
              <span className="text-sm font-black text-emerald-600">${curr(summary.taxBalance + (summary.totalRevenue * 0.19))}</span>
            </div>
            <div className="pt-4 flex justify-between items-center">
              <span className="text-md font-extrabold text-slate-900 dark:text-white uppercase tracking-widest">Saldo IVA Neto</span>
              <span className={`text-xl font-black ${summary.taxBalance >= 0 ? 'text-rose-600' : 'text-emerald-600'}`}>
                ${curr(Math.abs(summary.taxBalance))}
                <span className="text-[10px] ml-1 uppercase">{summary.taxBalance >= 0 ? 'por pagar' : 'a favor'}</span>
              </span>
            </div>
          </div>
          <p className="text-[10px] text-slate-400 mt-6 leading-relaxed">
            * Este balance es informativo basado en las facturas y ventas registradas. Consulta con tu contador para una declaración oficial de impuestos.
          </p>
        </div>

        <div className="bg-slate-900 dark:bg-slate-950 p-8 rounded-3xl relative overflow-hidden group">
          <div className="relative z-10">
            <h4 className="flex items-center gap-2 text-lg font-bold text-white mb-2">
              <TrendingUp className="text-emerald-400 w-5 h-5" /> Análisis de Margen
            </h4>
            <p className="text-slate-400 text-sm mb-8">Rendimiento porcentual sobre tus costos de compra.</p>
            
            <div className="flex items-end gap-2 mb-2">
              <span className="text-5xl font-black text-white">
                {summary.totalExpenses > 0 
                  ? Math.round((summary.grossProfit / summary.totalExpenses) * 100) 
                  : 0}%
              </span>
              <span className="text-emerald-400 font-bold mb-2">Margen Global</span>
            </div>
            
            <div className="w-full bg-slate-800 h-3 rounded-full overflow-hidden mt-4">
              <div 
                className="bg-gradient-to-r from-emerald-600 to-emerald-400 h-full transition-all duration-1000"
                style={{ width: `${Math.min(100, Math.max(0, summary.totalExpenses > 0 ? (summary.grossProfit / summary.totalExpenses) * 100 : 0))}%` }}
              ></div>
            </div>
          </div>
          
          {/* Decoración de fondo */}
          <div className="absolute top-0 right-0 -mr-16 -mt-16 w-64 h-64 bg-emerald-500/10 rounded-full blur-3xl group-hover:bg-emerald-500/20 transition-all"></div>
        </div>
      </div>
    </div>
  );
}

'use client';
import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { 
  ClipboardCheck, 
  CircleDollarSign, 
  CheckCircle2, 
  AlertCircle,
  Clock,
  User as UserIcon,
  Search,
  ArrowRightLeft,
  Banknote,
  FileText,
  PlusCircle,
  Wallet
} from 'lucide-react';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';
import { formatCurrency, parseCurrency } from '@/utils/formatters';

interface Sale {
  id: string;
  totalAmount: number;
  paymentMethod: string;
  customerName?: string;
  createdAt: string;
}

interface ClosureStatus {
  closure: {
    id: string;
    userName: string;
    openedAt: string;
    openingAmount: number;
  };
  openingAmount: number;
  totalCash: number;
  totalCredit: number;
  totalPayments?: number;
  totalToDeliver: number;
  salesCount: number;
}

export default function ClosurePage() {
  const router = useRouter();
  const [status, setStatus] = useState<ClosureStatus | null>(null);
  const [sales, setSales] = useState<Sale[]>([]);
  const [loading, setLoading] = useState(true);
  const [closing, setClosing] = useState(false);
  const [payments, setPayments] = useState<any[]>([]);
  const [openingAmount, setOpeningAmount] = useState<string>('');
  const [opening, setOpening] = useState(false);
  const [sortKey, setSortKey] = useState<string>('createdAt');
  const [sortDir, setSortDir] = useState<'asc' | 'desc'>('desc');

  const handleSort = (key: string) => {
    if (sortKey === key) {
      setSortDir(d => d === 'asc' ? 'desc' : 'asc');
    } else {
      setSortKey(key);
      setSortDir('desc');
    }
  };

  const sortedSales = [...sales].sort((a: any, b: any) => {
    let av = a[sortKey];
    let bv = b[sortKey];
    if (sortKey === 'totalAmount') { av = Number(av); bv = Number(bv); }
    if (av < bv) return sortDir === 'asc' ? -1 : 1;
    if (av > bv) return sortDir === 'asc' ? 1 : -1;
    return 0;
  });

  const fetchStatus = async () => {
    try {
      const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/closure/status`, {
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('access_token')}`
        }
      });
      const data = await response.json();
      setStatus(data);
    } catch (error) {
      console.error('Error fetching closure status:', error);
    }
  };

  const fetchSales = async () => {
    try {
      const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/closure/sales`, {
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('access_token')}`
        }
      });
      const data = await response.json();
      setSales(data);
    } catch (error) {
      console.error('Error fetching closure sales:', error);
    } finally {
      setLoading(false);
    }
  };

  const fetchPayments = async () => {
    try {
      const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/closure/payments`, {
        headers: { 'Authorization': `Bearer ${localStorage.getItem('access_token')}` }
      });
      const data = await response.json();
      setPayments(data);
    } catch (error) {
      console.error('Error fetching closure payments:', error);
    }
  };

  useEffect(() => {
    fetchStatus();
    fetchSales();
    fetchPayments();
  }, []);

  const handlePayCredit = async (saleId: string) => {
    if (!confirm('¿Marcar esta venta a crédito como pagada en efectivo?')) {
      return;
    }

    try {
      const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/${saleId}/pay-from-closure`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('access_token')}`
        }
      });

      if (response.ok) {
        alert('Pago registrado con éxito. Te redirigiremos al módulo de créditos para verificar.');
        router.push('/dashboard/credits');
      }
    } catch (error) {
      console.error('Error paying credit:', error);
    }
  };

  const handleOpenBox = async (e: React.FormEvent) => {
    e.preventDefault();
    const amountNum = parseCurrency(openingAmount);
    if (!openingAmount || amountNum < 0) return;

    setOpening(true);
    try {
      const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/closure/open`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${localStorage.getItem('access_token')}`
        },
        body: JSON.stringify({ openingAmount: amountNum })
      });

      if (response.ok) {
        window.location.reload();
      } else {
        alert('Error al abrir la caja');
      }
    } catch (error) {
      console.error('Error opening box:', error);
    } finally {
      setOpening(false);
    }
  };

  const handleCloseBox = async () => {
    if (!confirm('¿Está seguro de que desea realizar el cierre de caja? Esto finalizará su turno actual.')) {
      return;
    }

    setClosing(true);
    try {
      const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/closure/close`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('access_token')}`
        }
      });

      if (response.ok) {
          // Generar PDF antes de recargar si es posible, o avisar
          alert('Cierre de caja realizado con éxito. El turno ha sido guardado.');
          window.location.reload();
      }
    } catch (error) {
      console.error('Error performing closure:', error);
    } finally {
      setClosing(false);
    }
  };

  const exportToPDF = () => {
    if (!status) return;
    const doc = new jsPDF();
    
    // Header
    doc.setFillColor(30, 41, 59); // Slate 800
    doc.rect(0, 0, 210, 40, 'F');
    doc.setTextColor(255, 255, 255);
    doc.setFontSize(22);
    doc.text('COMPROBANTE DE ARQUEO', 105, 20, { align: 'center' });
    doc.setFontSize(10);
    doc.text(`Tiendeo POS - ${status.closure.userName}`, 105, 30, { align: 'center' });

    // Summary Info
    doc.setTextColor(0, 0, 0);
    doc.setFontSize(12);
    doc.text('RESUMEN DE TURNO', 14, 50);
    
    const summaryData = [
      ['Cajero:', status.closure.userName],
      ['Apertura:', new Date().toLocaleString('es-CO')],
      ['Cierre (Generado):', new Date().toLocaleString('es-CO')],
      ['Base de Caja:', `$${formatCurrency(status.openingAmount)}`],
      ['Ventas Efectivo:', `$${formatCurrency(status.totalCash)}`],
      ['Abonos Crédito:', `$${formatCurrency(status.totalPayments)}`],
      ['TOTAL EFECTIVO A ENTREGAR:', `$${formatCurrency(status.totalToDeliver)}`]
    ];

    autoTable(doc, {
      startY: 55,
      body: summaryData,
      theme: 'plain',
      styles: { fontSize: 10, cellPadding: 2 },
      columnStyles: { 0: { fontStyle: 'bold', cellWidth: 60 } }
    });

    // Sales Detail
    doc.setFontSize(12);
    doc.text('DETALLE DE VENTAS', 14, (doc as any).lastAutoTable.finalY + 15);

    const salesData = sales.map(s => [
      `#${s.id.split('-')[0]}`,
      new Date(s.createdAt).toLocaleTimeString(),
      s.paymentMethod.toUpperCase(),
      s.customerName || 'Contado',
      `$${formatCurrency(s.totalAmount)}`
    ]);

    autoTable(doc, {
      startY: (doc as any).lastAutoTable.finalY + 20,
      head: [['Ticket', 'Hora', 'Método', 'Cliente', 'Monto']],
      body: salesData,
      headStyles: { fillColor: [59, 130, 246] } // Blue 500
    });

    if (payments && payments.length > 0) {
      doc.setFontSize(12);
      doc.text('DETALLE DE ABONOS A CRÉDITOS', 14, (doc as any).lastAutoTable.finalY + 15);

      const paymentsData = payments.map(p => [
        `#${p.id.split('-')[0]}`,
        new Date(p.paymentDate).toLocaleTimeString(),
        (p.paymentMethod || 'efectivo').toUpperCase(),
        p.creditSale?.customerName || 'Cliente No Ident.',
        `$${formatCurrency(p.amount)}`
      ]);

      autoTable(doc, {
        startY: (doc as any).lastAutoTable.finalY + 20,
        head: [['Op. ID', 'Hora', 'Método', 'Cliente', 'Abono']],
        body: paymentsData,
        headStyles: { fillColor: [249, 115, 22] } // Orange 500
      });
    }

    doc.save(`Arqueo_${status.closure.userName}_${new Date().toLocaleDateString()}.pdf`);
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[60vh]">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  if (!status || !status.closure) {
    return (
      <div className="p-8 max-w-2xl mx-auto animate-in zoom-in-95 duration-500">
        <div className="bg-slate-900 border border-slate-800 rounded-[3rem] p-12 shadow-2xl text-center space-y-8">
          <div className="bg-blue-600/10 w-24 h-24 rounded-full flex items-center justify-center mx-auto">
            <PlusCircle className="w-12 h-12 text-blue-500" />
          </div>
          <div>
            <h2 className="text-3xl font-black text-white mb-2 italic uppercase tracking-tighter">Apertura de Caja</h2>
            <p className="text-slate-400 font-medium">Inicie su turno definiendo el monto base de la caja</p>
          </div>

          <form onSubmit={handleOpenBox} className="space-y-6">
            <div className="relative">
              <CircleDollarSign className="absolute left-6 top-5 w-6 h-6 text-blue-500" />
              <input
                required
                type="text"
                placeholder="0"
                className="w-full bg-slate-950 border-2 border-slate-800 rounded-3xl pl-16 pr-6 py-5 text-3xl font-black text-white focus:border-blue-500 outline-none transition-all placeholder:text-slate-800"
                value={formatCurrency(openingAmount)}
                onChange={(e) => setOpeningAmount(parseCurrency(e.target.value).toString())}
                autoFocus
              />
            </div>
            
            <button
              disabled={opening}
              type="submit"
              className="w-full bg-blue-600 hover:bg-blue-500 text-white py-5 rounded-3xl font-black text-xl shadow-xl shadow-blue-900/30 active:scale-95 transition-all disabled:opacity-50"
            >
              {opening ? 'Abriendo Turno...' : 'Iniciar Turno de Trabajo'}
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="p-8 max-w-6xl mx-auto space-y-8 animate-in fade-in duration-500">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-4xl font-black text-white flex items-center gap-3 tracking-tight italic uppercase">
            <ClipboardCheck className="w-10 h-10 text-blue-500" />
            Cierre de Caja
          </h1>
          <p className="text-slate-400 mt-2 font-bold uppercase tracking-widest text-[10px]">Gestión de Arqueo y Conciliación Actual</p>
        </div>
        <div className="flex items-center gap-3">
          <button
            onClick={exportToPDF}
            className="bg-slate-800 hover:bg-slate-700 text-slate-300 px-6 py-4 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-2 transition-all active:scale-95"
          >
            <FileText className="w-4 h-4" />
            Informe Arqueo
          </button>
          <button
            onClick={handleCloseBox}
            disabled={closing}
            className="bg-red-600 hover:bg-red-500 text-white px-8 py-4 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-2 shadow-lg shadow-red-900/20 transition-all active:scale-95 disabled:opacity-50"
          >
            {closing ? 'Procesando...' : 'Finalizar Turno'}
            <CheckCircle2 className="w-5 h-5" />
          </button>
        </div>
      </div>

      {/* Summary Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-6">
        <div className="bg-slate-900 border border-slate-800 p-8 rounded-[2.5rem] shadow-xl">
          <div className="flex items-center gap-3 mb-6">
            <div className="bg-blue-500/10 p-2 rounded-xl">
              <UserIcon className="w-5 h-5 text-blue-400" />
            </div>
            <span className="text-slate-500 font-black text-[10px] uppercase tracking-widest">Responsable</span>
          </div>
          <p className="text-2xl font-black text-white uppercase tracking-tighter italic">{status.closure?.userName || 'Cajero'}</p>
          <div className="flex items-center gap-2 mt-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest">
            <Clock className="w-3 h-3 text-blue-500" />
            {status.closure?.openedAt ? new Date(status.closure.openedAt).toLocaleTimeString() : '---'}
          </div>
        </div>

        <div className="bg-slate-900 border border-slate-800 p-8 rounded-[2.5rem] shadow-xl">
          <div className="flex items-center gap-3 mb-6">
            <div className="bg-orange-500/10 p-2 rounded-xl">
              <Wallet className="w-5 h-5 text-orange-400" />
            </div>
            <span className="text-slate-500 font-black text-[10px] uppercase tracking-widest">Base Inicial</span>
          </div>
          <p className="text-3xl font-black text-white tracking-tighter">${formatCurrency(status.openingAmount)}</p>
          <p className="text-[10px] font-bold text-slate-600 mt-4 uppercase tracking-widest">Efectivo declarado al abrir</p>
        </div>

        <div className="bg-slate-900 border border-slate-800 p-8 rounded-[2.5rem] shadow-xl">
          <div className="flex items-center gap-3 mb-6">
            <div className="bg-green-500/10 p-2 rounded-xl">
              <CircleDollarSign className="w-5 h-5 text-green-400" />
            </div>
            <span className="text-slate-500 font-black text-[10px] uppercase tracking-widest">Ventas Efectivo</span>
          </div>
          <p className="text-3xl font-black text-white tracking-tighter">${formatCurrency(status.totalCash)}</p>
          <p className="text-[10px] font-bold text-slate-600 mt-4 uppercase tracking-widest">Pagos de Contado</p>
        </div>

        <div className="bg-slate-900 border border-slate-800 p-8 rounded-[2.5rem] shadow-xl">
          <div className="flex items-center gap-3 mb-6">
            <div className="bg-orange-500/10 p-2 rounded-xl">
              <ArrowRightLeft className="w-5 h-5 text-orange-400" />
            </div>
            <span className="text-slate-500 font-black text-[10px] uppercase tracking-widest">Abonos Créditos</span>
          </div>
          <p className="text-3xl font-black text-white tracking-tighter">${formatCurrency(status.totalPayments || 0)}</p>
          <p className="text-[10px] font-bold text-slate-600 mt-4 uppercase tracking-widest">Cartera Recaudada</p>
        </div>

        <div className="bg-blue-600 p-8 rounded-[2.5rem] shadow-2xl border border-blue-500/50 relative overflow-hidden group">
          <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full -mr-16 -mt-16 transition-all group-hover:scale-110"></div>
          <div className="flex items-center gap-3 mb-6">
            <div className="bg-white/20 p-2 rounded-xl">
              <CheckCircle2 className="w-5 h-5 text-white" />
            </div>
            <span className="text-blue-100 font-black text-[10px] uppercase tracking-widest">Total a Entregar</span>
          </div>
          <p className="text-4xl font-black text-white tracking-tighter">${formatCurrency(status.totalToDeliver)}</p>
          <p className="text-[11px] font-bold text-blue-100 mt-4 uppercase tracking-widest">DINERO REAL QUE DEBE HABER EN CAJA</p>
        </div>
      </div>

      {/* Sales Table */}
      <div className="bg-slate-900 border border-slate-800 rounded-3xl overflow-hidden shadow-2xl">
        <div className="px-8 py-6 border-b border-slate-800 bg-slate-950/50 flex items-center justify-between">
          <h2 className="text-xl font-bold text-white flex items-center gap-2">
            Ventas del Turno Actual
          </h2>
          <span className="text-xs font-bold text-slate-500 bg-slate-800 px-3 py-1 rounded-full uppercase tracking-tighter">
            En Tiempo Real
          </span>
        </div>
          <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="border-b border-slate-800/50">
                {([
                  { key: 'createdAt', label: 'Ticket / Hora' },
                  { key: 'totalAmount', label: 'Monto' },
                  { key: 'paymentMethod', label: 'Método' },
                  { key: 'customerName', label: 'Cliente / Deuda' },
                ] as { key: string; label: string }[]).map(col => (
                  <th
                    key={col.key}
                    onClick={() => handleSort(col.key)}
                    className="px-8 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest cursor-pointer hover:text-blue-400 hover:bg-slate-800/30 select-none transition-colors"
                  >
                    {col.label}{' '}
                    <span className="text-slate-600">
                      {sortKey === col.key ? (sortDir === 'asc' ? '↑' : '↓') : '↕'}
                    </span>
                  </th>
                ))}
                <th className="px-8 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest text-right">Acción</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-800/50">
              {sortedSales.map((sale) => (
                <tr key={sale.id} className="hover:bg-slate-800/30 transition-colors group">
                  <td className="px-8 py-4">
                    <p className="text-sm font-bold text-white uppercase tracking-tighter">#{sale.id.split('-')[0]}</p>
                    <p className="text-[10px] text-slate-500">{new Date(sale.createdAt).toLocaleTimeString()}</p>
                  </td>
                  <td className="px-8 py-4">
                    <span className="text-sm font-black text-white">${formatCurrency(sale.totalAmount)}</span>
                  </td>
                  <td className="px-8 py-4">
                    <span className={`text-[10px] font-black uppercase px-2 py-1 rounded-full ${
                      sale.paymentMethod === 'credito' 
                      ? 'bg-orange-900/40 text-orange-400' 
                      : 'bg-green-900/40 text-green-400'
                    }`}>
                      {sale.paymentMethod}
                    </span>
                  </td>
                  <td className="px-8 py-4">
                    {sale.paymentMethod === 'credito' ? (
                      <span className="text-sm font-bold text-white underline decoration-orange-500/50 underline-offset-4">
                        {sale.customerName || 'Cliente Genérico'}
                      </span>
                    ) : (
                      <span className="text-xs text-slate-600 italic">Pago al contado</span>
                    )}
                  </td>
                  <td className="px-8 py-4 text-right">
                    {sale.paymentMethod === 'credito' && (
                      <button
                        onClick={() => handlePayCredit(sale.id)}
                        className="p-2 hover:bg-green-500/20 text-slate-500 hover:text-green-400 rounded-xl transition-all"
                        title="Marcar como Pagado"
                      >
                        <Banknote className="w-5 h-5" />
                      </button>
                    )}
                  </td>
                </tr>
              ))}
              {sales.length === 0 && (
                <tr>
                  <td colSpan={5} className="px-8 py-12 text-center text-slate-500 italic">
                    No hay ventas registradas en este turno aún.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

'use client';
import { useState, useEffect } from 'react';
import { 
  ArrowRightLeft, 
  Search, 
  User, 
  Calendar, 
  CheckCircle2, 
  Banknote,
  Loader2,
  AlertCircle,
  FileText,
  Download,
  History,
  ArrowDownCircle
} from 'lucide-react';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';
import { utils, writeFile } from 'xlsx';
import AbonoModal from '@/components/customers/AbonoModal';
import { useOfflineStore } from '@/store/useOfflineStore';
import { formatCurrency, parseCurrency } from '@/utils/formatters';

interface CreditSale {
  id: string;
  customerName: string;
  amount: number;
  remainingAmount: number;
  status: string;
  createdAt: string;
  sale?: {
    id: string;
    totalAmount: number;
    invoiceNumber?: string;
  }
}

export default function CreditsPage() {
  const { isOnline, rawCredits: cachedCredits, setCache } = useOfflineStore();
  const [credits, setCredits] = useState<CreditSale[]>([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('');
  const [sortConfig, setSortConfig] = useState<{ key: string; direction: 'ascending' | 'descending' } | null>(null);
  const [processingId, setProcessingId] = useState<string | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);
  const [selectedCredit, setSelectedCredit] = useState<CreditSale | null>(null);
  const [isAbonoModalOpen, setIsAbonoModalOpen] = useState(false);

  const requestSort = (key: string) => {
    let direction: 'ascending' | 'descending' = 'ascending';
    if (sortConfig && sortConfig.key === key && sortConfig.direction === 'ascending') {
      direction = 'descending';
    }
    setSortConfig({ key, direction });
  };

  useEffect(() => {
    if (isOnline) {
      fetchCredits();
    } else {
      setCredits(cachedCredits || []);
      setLoading(false);
    }
  }, [isOnline, cachedCredits]);

  const fetchCredits = async () => {
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/credits/pending`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      if (res.ok) {
        const data = await res.json();
        setCredits(data);
        setCache({ rawCredits: data });
      }
    } catch (e) {
      console.error(e);
      setCredits(cachedCredits || []);
    } finally {
      setLoading(false);
    }
  };

  const handlePay = async (creditId: string) => {
    if (!confirm('¿Confirmar que el cliente ha pagado este crédito en efectivo?')) return;
    
    setProcessingId(creditId);
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/credits/${creditId}/pay`, {
        method: 'POST',
        headers: { Authorization: `Bearer ${token}` }
      });

      if (res.ok) {
        alert('Pago registrado correctamente. El ingreso aparecerá ahora en la contabilidad como efectivo.');
        fetchCredits();
      } else {
        alert('Error al procesar el pago');
      }
    } catch (e) {
      console.error(e);
      alert('Error de conexión');
    } finally {
      setProcessingId(null);
    }
  };

  const handleSync = async () => {
    if (!confirm('¿Deseas sincronizar las ventas antiguas con el módulo de créditos? Esto buscará ventas de crédito que no aparezcan aquí.')) return;
    setIsSyncing(true);
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/sync-credits`, {
        method: 'POST',
        headers: { Authorization: `Bearer ${token}` }
      });
      if (res.ok) {
        const result = await res.json();
        alert(`Sincronización completada.\nNuevos créditos: ${result.created}\nNombres actualizados: ${result.updated}`);
        fetchCredits();
      } else {
        alert('Error al sincronizar');
      }
    } catch (e) {
      console.error(e);
      alert('Error de conexión');
    } finally {
      setIsSyncing(false);
    }
  };

  const exportToPDF = () => {
    const doc = new jsPDF();
    doc.setFontSize(18);
    doc.text('TIENDEO POS - CUENTAS POR COBRAR', 14, 20);
    doc.setFontSize(10);
    doc.text(`Generado: ${new Date().toLocaleString('es-CO')}`, 14, 28);
    
    const tableData = filteredCredits.map(c => [
      c.sale?.invoiceNumber || 'N/A',
      c.customerName,
      new Date(c.createdAt).toLocaleDateString(),
      `$${formatCurrency(c.amount)}`,
      'PENDIENTE'
    ]);
    
    autoTable(doc, {
      startY: 35,
      head: [['Factura #', 'Cliente', 'Fecha Deuda', 'Monto', 'Estado']],
      body: tableData,
      headStyles: { fillColor: [249, 115, 22] } // Orange
    });
    
    doc.save('Cuentas_Por_Cobrar.pdf');
  };

  const exportToExcel = () => {
    const data = filteredCredits.map(c => ({
      'Factura #': c.sale?.invoiceNumber || 'N/A',
      Cliente: c.customerName,
      Fecha: new Date(c.createdAt).toLocaleDateString(),
      Monto: Number(c.amount),
      Estado: 'PENDIENTE'
    }));
    
    const ws = utils.json_to_sheet(data);
    const wb = utils.book_new();
    utils.book_append_sheet(wb, ws, 'Créditos');
    writeFile(wb, 'Cuentas_Por_Cobrar.xlsx');
  };

  const sortedCredits = [...credits].sort((a, b) => {
    if (!sortConfig) return 0;
    
    let aValue: any = a[sortConfig.key as keyof CreditSale];
    let bValue: any = b[sortConfig.key as keyof CreditSale];

    if (sortConfig.key === 'invoice') {
      aValue = a.sale?.invoiceNumber || '';
      bValue = b.sale?.invoiceNumber || '';
    } else if (sortConfig.key === 'remaining') {
       aValue = Number(a.remainingAmount || a.amount);
       bValue = Number(b.remainingAmount || b.amount);
    } else if (sortConfig.key === 'amount') {
       aValue = Number(a.amount);
       bValue = Number(b.amount);
    }
    
    if (aValue < bValue) return sortConfig.direction === 'ascending' ? -1 : 1;
    if (aValue > bValue) return sortConfig.direction === 'ascending' ? 1 : -1;
    return 0;
  });

  const filteredCredits = sortedCredits.filter(c => 
    c.customerName.toLowerCase().includes(filter.toLowerCase())
  );

  const totalOwed = filteredCredits.reduce((sum, c) => {
    const val = Number(c.remainingAmount);
    return sum + (val > 0 ? val : Number(c.amount));
  }, 0);

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[60vh]">
        <Loader2 className="w-12 h-12 text-blue-600 animate-spin" />
      </div>
    );
  }

  return (
    <div className="p-4 md:p-8 max-w-6xl mx-auto space-y-8 animate-in fade-in duration-500">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-4xl font-black text-white flex items-center gap-3 tracking-tight">
            <ArrowRightLeft className="w-10 h-10 text-orange-500" />
            Cuentas por Cobrar
          </h1>
          <p className="text-slate-400 mt-2 font-medium">Gestiona las deudas de tus clientes y registra sus pagos</p>
        </div>
        
        <div className="bg-slate-900 border border-slate-800 px-4 sm:px-6 py-4 rounded-3xl shadow-xl flex flex-wrap items-center justify-center gap-2 sm:gap-4 shrink-0">
          <div>
            <p className="text-[10px] font-black uppercase text-slate-500 tracking-widest">Total por Cobrar</p>
            <p className="text-3xl font-black text-orange-500">${formatCurrency(totalOwed)}</p>
          </div>
          <div className="h-10 w-px bg-slate-800 mx-2" />
          <div className="text-center">
             <p className="text-[10px] font-black uppercase text-slate-500 tracking-widest">Clientes</p>
             <p className="text-2xl font-black text-white">{filteredCredits.length}</p>
          </div>
        </div>

        <div className="flex flex-wrap gap-3">
          <button 
            onClick={exportToPDF}
            className="flex items-center gap-2 bg-slate-100 dark:bg-slate-800 text-slate-700 dark:text-slate-200 px-4 py-2.5 rounded-xl font-bold border border-slate-200 dark:border-slate-700 hover:bg-slate-200 transition-all active:scale-95"
          >
            <FileText className="w-4 h-4 text-rose-500" />
            PDF
          </button>
          <button 
            onClick={exportToExcel}
            className="flex items-center gap-2 bg-slate-100 dark:bg-slate-800 text-slate-700 dark:text-slate-200 px-4 py-2.5 rounded-xl font-bold border border-slate-200 dark:border-slate-700 hover:bg-slate-200 transition-all active:scale-95"
          >
            <Download className="w-4 h-4 text-emerald-500" />
            Excel
          </button>
          <button 
            onClick={handleSync}
            disabled={isSyncing}
            className="flex items-center gap-2 bg-orange-600 hover:bg-orange-500 text-white px-4 py-2.5 rounded-xl font-bold shadow-lg shadow-orange-900/20 transition-all active:scale-95 disabled:opacity-50"
            title="Sincronizar créditos de ventas antiguas"
          >
            <ArrowRightLeft className={`w-4 h-4 ${isSyncing ? 'animate-spin' : ''}`} />
            {isSyncing ? 'Sincronizando...' : 'Sincronizar Datos'}
          </button>
        </div>
      </div>

      {/* Filter and Content */}
      <div className="bg-slate-900 border border-slate-800 rounded-3xl overflow-hidden shadow-2xl">
        <div className="px-8 py-6 border-b border-slate-800 bg-slate-950/50 flex flex-col md:flex-row md:items-center justify-between gap-4">
          <h2 className="text-xl font-bold text-white flex items-center gap-2">
            Deudas Pendientes
          </h2>
          <div className="relative w-full md:w-80">
            <Search className="absolute left-4 top-3 w-5 h-5 text-slate-500" />
            <input 
              type="text" 
              placeholder="Buscar cliente..."
              value={filter}
              onChange={(e) => setFilter(e.target.value)}
              className="w-full bg-slate-950 border border-slate-800 rounded-2xl pl-12 pr-4 py-2.5 text-white focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all font-bold"
            />
          </div>
        </div>

        <div className="overflow-x-auto pb-4">
          <table className="w-full text-left">
            <thead>
              <tr className="border-b border-slate-800/50">
                <th 
                  onClick={() => requestSort('invoice')}
                  className="px-8 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest min-w-[120px] cursor-pointer hover:text-blue-500 transition-colors"
                >
                  <div className="flex items-center gap-2">
                    Factura #
                    {sortConfig?.key === 'invoice' && (sortConfig.direction === 'ascending' ? '↑' : '↓')}
                  </div>
                </th>
                <th 
                  onClick={() => requestSort('customerName')}
                  className="px-8 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest min-w-[180px] cursor-pointer hover:text-blue-500 transition-colors"
                >
                  <div className="flex items-center gap-2">
                    Cliente
                    {sortConfig?.key === 'customerName' && (sortConfig.direction === 'ascending' ? '↑' : '↓')}
                  </div>
                </th>
                <th 
                  onClick={() => requestSort('createdAt')}
                  className="px-8 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest text-center min-w-[140px] cursor-pointer hover:text-blue-500 transition-colors"
                >
                  <div className="flex items-center gap-2 justify-center">
                    Fecha Deuda
                    {sortConfig?.key === 'createdAt' && (sortConfig.direction === 'ascending' ? '↑' : '↓')}
                  </div>
                </th>
                <th 
                  onClick={() => requestSort('amount')}
                  className="px-8 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest min-w-[140px] cursor-pointer hover:text-blue-500 transition-colors"
                >
                  <div className="flex items-center gap-2">
                    Monto Original
                    {sortConfig?.key === 'amount' && (sortConfig.direction === 'ascending' ? '↑' : '↓')}
                  </div>
                </th>
                <th 
                  onClick={() => requestSort('remaining')}
                  className="px-8 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest min-w-[160px] cursor-pointer hover:text-blue-500 transition-colors"
                >
                  <div className="flex items-center gap-2">
                    Saldo Pendiente
                    {sortConfig?.key === 'remaining' && (sortConfig.direction === 'ascending' ? '↑' : '↓')}
                  </div>
                </th>
                <th className="px-8 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest min-w-[120px]">Estado</th>
                <th className="px-8 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest text-right min-w-[180px]">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-800/50">
              {filteredCredits.map((credit) => (
                <tr key={credit.id} className="hover:bg-slate-800/30 transition-colors group">
                  <td className="px-8 py-4">
                    <span className="text-xs font-black text-blue-500 bg-blue-500/10 px-2 py-1 rounded-lg">
                      {credit.sale?.invoiceNumber || 'S/N'}
                    </span>
                  </td>
                  <td className="px-8 py-4">
                    <div className="flex items-center gap-3">
                      <div className="bg-slate-800 p-2 rounded-xl group-hover:bg-slate-700 transition-colors">
                        <User className="w-5 h-5 text-slate-400" />
                      </div>
                      <span className="text-sm font-black text-white">{credit.customerName}</span>
                    </div>
                  </td>
                  <td className="px-8 py-4 text-center">
                    <div className="inline-flex items-center gap-2 text-xs text-slate-500 font-bold bg-slate-950/50 px-3 py-1 rounded-full">
                      <Calendar className="w-3 h-3" />
                      {new Date(credit.createdAt).toLocaleDateString()}
                    </div>
                  </td>
                  <td className="px-8 py-4">
                    <span className="text-sm font-bold text-slate-400">${formatCurrency(credit.amount)}</span>
                  </td>
                  <td className="px-8 py-4">
                    <span className="text-xl font-black text-rose-500 shadow-rose-900/10">${formatCurrency(Number(credit.remainingAmount) || Number(credit.amount))}</span>
                  </td>
                  <td className="px-8 py-4">
                    <span className={`text-[10px] font-black uppercase px-2.5 py-1 rounded-full border ${
                      credit.status === 'PARTIAL' 
                      ? 'bg-blue-900/40 text-blue-400 border-blue-500/20' 
                      : 'bg-orange-900/40 text-orange-400 border-orange-500/20'
                    }`}>
                      {credit.status === 'PARTIAL' ? 'Abonado' : 'Pendiente'}
                    </span>
                  </td>
                  <td className="px-8 py-4 text-right">
                    <div className="flex items-center justify-end gap-2">
                      <button
                        onClick={() => { setSelectedCredit(credit); setIsAbonoModalOpen(true); }}
                        className="bg-blue-600 hover:bg-blue-500 text-white px-4 py-2 rounded-xl font-bold text-xs flex items-center gap-2 shadow-lg shadow-blue-900/20 transition-all active:scale-95"
                      >
                        <ArrowDownCircle className="w-4 h-4" />
                        Abonar
                      </button>
                      <button
                        onClick={() => handlePay(credit.id)}
                        disabled={processingId === credit.id}
                        className="bg-green-600 hover:bg-green-500 text-white p-2 rounded-xl font-bold text-sm flex items-center gap-2 shadow-lg shadow-green-900/20 transition-all active:scale-95 disabled:opacity-50"
                        title="Marcar como pagado totalmente"
                      >
                        {processingId === credit.id ? (
                          <Loader2 className="w-4 h-4 animate-spin" />
                        ) : (
                          <Banknote className="w-5 h-5" />
                        )}
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
              {filteredCredits.length === 0 && (
                <tr>
                  <td colSpan={5} className="px-8 py-16 text-center text-slate-500 italic">
                    <div className="flex flex-col items-center gap-4">
                       <CheckCircle2 className="w-12 h-12 text-slate-700" />
                       <p className="text-lg font-bold">No hay deudas pendientes</p>
                       <p className="text-sm">¡Buen trabajo! Todo está al día.</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Info Alert */}
      <div className="bg-blue-600/10 border border-blue-500/20 rounded-3xl p-6 flex items-start gap-4">
        <AlertCircle className="w-6 h-6 text-blue-500 shrink-0 mt-0.5" />
        <div>
          <h4 className="text-white font-bold mb-1">Impacto en Contabilidad</h4>
          <p className="text-sm text-slate-400">
            Al marcar un crédito como pagado, el monto se moverá automáticamente de "Cuentas por Cobrar" a "Ingresos Efectivo". 
            Esto afectará tus balances globales inmediatamente.
          </p>
        </div>
      </div>
      <AbonoModal 
        isOpen={isAbonoModalOpen}
        onClose={() => setIsAbonoModalOpen(false)}
        onSave={fetchCredits}
        credit={selectedCredit}
      />
    </div>
  );
}

'use client';
import { useState, useEffect } from 'react';
import { 
  UserPlus, 
  Search, 
  User, 
  Phone, 
  Mail, 
  MapPin, 
  ChevronRight, 
  Loader2,
  AlertCircle,
  CreditCard,
  History,
  Trash2,
  Settings,
  Wifi,
  WifiOff,
  CloudSync,
  FileDown
} from 'lucide-react';
import CustomerModal from '@/components/customers/CustomerModal';
import CustomerHistoryModal from '@/components/customers/CustomerHistoryModal';
import { useOfflineStore } from '@/store/useOfflineStore';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';
import { formatCurrency as curr } from '@/utils/formatters';


export default function CustomersPage() {
  const { isOnline, customers: cachedCustomers, setCache } = useOfflineStore();
  const [customers, setCustomers] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [isExporting, setIsExporting] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedCustomer, setSelectedCustomer] = useState<any>(null);
  const [isHistoryModalOpen, setIsHistoryModalOpen] = useState(false);
  const [sortConfig, setSortConfig] = useState<{ key: string; direction: 'ascending' | 'descending' } | null>(null);

  const requestSort = (key: string) => {
    let direction: 'ascending' | 'descending' = 'ascending';
    if (sortConfig && sortConfig.key === key && sortConfig.direction === 'ascending') {
      direction = 'descending';
    }
    setSortConfig({ key, direction });
  };

  useEffect(() => {
    if (isOnline) {
      fetchCustomers();
    } else {
      setCustomers(cachedCustomers);
      setLoading(false);
    }
  }, [isOnline, cachedCustomers]);

  const fetchCustomers = async () => {
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/customers`, {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      if (res.ok) {
        const data = await res.json();
        setCustomers(data);
        setCache({ customers: data });
      }
    } catch (error) {
      console.error(error);
      setCustomers(cachedCustomers);
    } finally {
      setLoading(false);
    }
  };

  const generatePDF = async () => {
    setIsExporting(true);
    try {
      const token = localStorage.getItem('access_token');
      // Fetch full data with relations
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/customers?full=true`, {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      
      if (!res.ok) throw new Error('Error fetching data');
      const fullCustomers = await res.json();
      
      const doc = new jsPDF();
      
      // Header
      doc.setFillColor(37, 99, 235); // Blue 600
      doc.rect(0, 0, 210, 40, 'F');
      
      doc.setTextColor(255, 255, 255);
      doc.setFontSize(22);
      doc.text('REPORTE GENERAL DE CARTERA', 14, 25);
      
      doc.setFontSize(10);
      doc.text(`TIENDEO POS - Gestión de Cobros`, 150, 22);
      doc.text(`Generado: ${new Date().toLocaleString('es-CO')}`, 150, 28);
      doc.text(`Clientes Activos: ${fullCustomers.length}`, 150, 34);

      // Summary
      const totalCartera = fullCustomers.reduce((acc: number, c: any) => acc + (c.totalDebt || 0), 0);
      doc.setTextColor(30, 41, 59);
      doc.setFontSize(14);
      doc.text('RESUMEN FINANCIERO', 14, 50);
      doc.setFontSize(11);
      doc.text(`Total Cartera por Cobrar: $${curr(totalCartera)}`, 14, 60);

      // Table
      const tableData = fullCustomers
        .filter((c: any) => c.totalDebt > 0)
        .map((c: any) => [
          c.name,
          c.idNumber || 'S/I',
          c.phone || 'N/R',
          c.pendingInvoices,
          `$${curr(c.totalDebt)}`
        ]);

      autoTable(doc, {
        startY: 70,
        head: [['Cliente', 'Identificación', 'Teléfono', 'Facturas', 'Deuda Total']],
        body: tableData,
        headStyles: { fillColor: [37, 99, 235] },
        alternateRowStyles: { fillColor: [248, 250, 252] },
        styles: { fontSize: 9 }
      });

      doc.save(`Reporte_Cartera_${new Date().toISOString().split('T')[0]}.pdf`);
    } catch (error) {
      console.error(error);
      alert('Error generando el reporte PDF');
    } finally {
      setIsExporting(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm('¿Estás seguro de eliminar este cliente? No se podrá eliminar si tiene créditos asociados.')) return;
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/customers/${id}`, {
        method: 'DELETE',
        headers: { 'Authorization': `Bearer ${token}` }
      });
      if (res.ok) {
        fetchCustomers();
      } else {
        alert('No se puede eliminar el cliente (posiblemente tiene deudas registradas)');
      }
    } catch (error) {
      console.error(error);
    }
  };

  const sortedCustomers = [...customers].sort((a, b) => {
    if (!sortConfig) return 0;
    let aValue = a[sortConfig.key];
    let bValue = b[sortConfig.key];
    
    if (aValue < bValue) return sortConfig.direction === 'ascending' ? -1 : 1;
    if (aValue > bValue) return sortConfig.direction === 'ascending' ? 1 : -1;
    return 0;
  });

  const filteredCustomers = sortedCustomers.filter(c => {
    const s = searchTerm.toLowerCase();
    return (
      c.name.toLowerCase().includes(s) || 
      (c.idNumber && c.idNumber.toLowerCase().includes(s)) ||
      (c.phone && c.phone.toLowerCase().includes(s)) ||
      (c.email && c.email.toLowerCase().includes(s))
    );
  });

  const totalOwedByAll = filteredCustomers.reduce((sum, c) => sum + (c.totalDebt || 0), 0);

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[60vh]">
        <Loader2 className="w-12 h-12 text-blue-600 animate-spin" />
      </div>
    );
  }

  return (
    <div className="p-4 md:p-8 max-w-7xl mx-auto space-y-8 animate-in fade-in duration-500">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-black text-gray-900 dark:text-white flex items-center gap-3 tracking-tight">
            <User className="w-10 h-10 text-blue-600" />
            Gestión de Clientes
          </h1>
          <p className="text-gray-500 dark:text-slate-400 mt-2 font-medium">Administra tu base de datos de clientes y controla sus créditos</p>
        </div>

        <div className="flex items-center gap-4">
          <div className="bg-white dark:bg-slate-900 border border-gray-100 dark:border-slate-800 px-6 py-4 rounded-3xl shadow-xl hidden md:flex items-center gap-4">
            <div>
              <p className="text-[10px] font-black uppercase text-gray-400 dark:text-slate-500 tracking-widest">Cartera Total</p>
              <p className="text-2xl font-black text-rose-600 dark:text-rose-500">${curr(totalOwedByAll)}</p>
            </div>
            <div className="h-10 w-[1px] bg-gray-100 dark:bg-slate-800 mx-2" />
            <button 
              onClick={generatePDF}
              disabled={isExporting}
              className="group flex flex-col items-center gap-1 hover:text-blue-600 transition-colors"
            >
              <div className="bg-blue-50 dark:bg-blue-900/20 p-2 rounded-xl group-hover:bg-blue-600 group-hover:text-white transition-all">
                {isExporting ? <Loader2 className="w-5 h-5 animate-spin" /> : <FileDown className="w-5 h-5" />}
              </div>
              <span className="text-[9px] font-black uppercase tracking-tighter">Informe PDF</span>
            </button>
          </div>
          <button 
            onClick={() => { setSelectedCustomer(null); setIsModalOpen(true); }}
            className="bg-blue-600 hover:bg-blue-500 text-white px-6 py-4 rounded-2xl font-black flex items-center gap-2 shadow-lg shadow-blue-600/20 transition-all active:scale-95"
          >
            <UserPlus className="w-5 h-5" />
            <span className="hidden sm:inline">Nuevo Cliente</span>
          </button>
        </div>
      </div>

      {/* Main Content */}
      <div className="bg-white dark:bg-slate-900 border border-gray-100 dark:border-slate-800 rounded-[2.5rem] overflow-hidden shadow-2xl">
        <div className="px-8 py-6 border-b border-gray-100 dark:border-slate-800 bg-gray-50/50 dark:bg-slate-950/50 flex flex-col md:flex-row md:items-center justify-between gap-4">
          <h2 className="text-xl font-bold text-gray-900 dark:text-white flex items-center gap-2">
            Clientes Registrados
            <span className="text-xs font-black bg-blue-100 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 px-3 py-1 rounded-full uppercase">
              {filteredCustomers.length}
            </span>
          </h2>
          <div className="relative w-full md:w-96">
            <Search className="absolute left-4 top-3.5 w-5 h-5 text-gray-400" />
            <input 
              type="text" 
              placeholder="Buscar por nombre, ID, teléfono o correo..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full bg-white text-black border border-gray-200 rounded-2xl pl-12 pr-4 py-3.5 focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all font-bold"
            />
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="border-b border-gray-100 dark:border-slate-800/50">
                <th 
                  onClick={() => requestSort('name')}
                  className="px-8 py-5 text-xs font-black text-gray-400 dark:text-slate-500 uppercase tracking-widest min-w-[200px] cursor-pointer hover:text-blue-600 transition-colors"
                >
                  <div className="flex items-center gap-2">
                    Información Cliente
                    {sortConfig?.key === 'name' && (sortConfig.direction === 'ascending' ? '↑' : '↓')}
                  </div>
                </th>
                <th className="px-8 py-5 text-xs font-black text-gray-400 dark:text-slate-500 uppercase tracking-widest min-w-[150px]">Contacto</th>
                <th 
                  onClick={() => requestSort('totalDebt')}
                  className="px-8 py-5 text-xs font-black text-gray-400 dark:text-slate-500 uppercase tracking-widest text-center min-w-[160px] cursor-pointer hover:text-blue-600 transition-colors"
                >
                  <div className="flex items-center gap-2 justify-center">
                    Estado Crédito
                    {sortConfig?.key === 'totalDebt' && (sortConfig.direction === 'ascending' ? '↑' : '↓')}
                  </div>
                </th>
                <th className="px-8 py-5 text-xs font-black text-gray-400 dark:text-slate-500 uppercase tracking-widest text-right min-w-[160px]">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 dark:divide-slate-800/50">
              {filteredCustomers.map((c) => (
                <tr key={c.id} className="hover:bg-gray-50 dark:hover:bg-slate-800/30 transition-colors group">
                  <td className="px-8 py-6">
                    <div className="flex items-center gap-4">
                      <div className="bg-gray-100 dark:bg-slate-800 p-3 rounded-2xl group-hover:bg-blue-100 dark:group-hover:bg-blue-900/30 group-hover:text-blue-600 dark:group-hover:text-blue-400 transition-all">
                        <User className="w-6 h-6" />
                      </div>
                      <div>
                        <div className="flex items-center gap-2">
                          <p className="text-lg font-black text-gray-900 dark:text-white leading-tight">{c.name}</p>
                          {(c as any).localId && (
                            <span className="px-1.5 py-0.5 bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400 text-[10px] font-black rounded uppercase">Pendiente</span>
                          )}
                        </div>
                        <div className="flex items-center gap-2 mt-1">
                          <CreditCard className="w-3.5 h-3.5 text-gray-400" />
                          <p className="text-xs font-bold text-gray-400 dark:text-slate-500 uppercase tracking-tighter">
                            {c.idNumber || 'Sin Identificación'}
                          </p>
                        </div>
                      </div>
                    </div>
                  </td>
                  <td className="px-8 py-6">
                    <div className="space-y-1.5 text-sm font-medium text-gray-600 dark:text-slate-400">
                      <div className="flex items-center gap-2">
                        <Phone className="w-3.5 h-3.5 text-blue-500" />
                        <span>{c.phone || 'No registrado'}</span>
                      </div>
                      <div className="flex items-center gap-2 overflow-hidden max-w-[200px]">
                        <Mail className="w-3.5 h-3.5 text-blue-500" />
                        <span className="truncate">{c.email || 'No registrado'}</span>
                      </div>
                    </div>
                  </td>
                  <td className="px-8 py-6">
                    <div className="flex flex-col items-center">
                      <div className={`px-4 py-2 rounded-2xl flex flex-col items-center min-w-[140px] border shadow-sm ${
                        c.totalDebt > 0 
                        ? 'bg-rose-50 dark:bg-rose-900/20 border-rose-100 dark:border-rose-900/30 text-rose-600 dark:text-rose-400' 
                        : 'bg-green-50 dark:bg-green-900/20 border-green-100 dark:border-green-900/30 text-green-600 dark:text-green-400'
                      }`}>
                        <span className="text-xs font-black uppercase tracking-widest opacity-80 mb-1">
                          {c.totalDebt > 0 ? 'Deuda Activa' : 'Al Día'}
                        </span>
                        <span className="text-lg font-black">${curr(c.totalDebt)}</span>
                        {c.pendingInvoices > 0 && (
                          <span className="text-[10px] font-bold mt-0.5 opacity-70">
                            {c.pendingInvoices} Facturas pendientes
                          </span>
                        )}
                      </div>
                    </div>
                  </td>
                  <td className="px-8 py-6 text-right">
                    <div className="flex items-center justify-end gap-2">
                      <button 
                        onClick={() => { setSelectedCustomer(c); setIsModalOpen(true); }}
                        className="p-3 bg-gray-100 dark:bg-slate-800 text-gray-600 dark:text-slate-400 hover:bg-blue-600 hover:text-white rounded-xl transition-all shadow-sm"
                        title="Editar Datos"
                      >
                        <Settings className="w-5 h-5" />
                      </button>
                      <button 
                        onClick={() => { setSelectedCustomer(c); setIsHistoryModalOpen(true); }}
                        className="p-3 bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400 hover:bg-blue-600 hover:text-white rounded-xl transition-all shadow-sm"
                        title="Ver Historial y Reporte"
                      >
                        <History className="w-5 h-5" />
                      </button>
                      <button 
                        onClick={() => handleDelete(c.id)}
                        className="p-3 bg-gray-100 dark:bg-slate-800 text-gray-600 dark:text-slate-400 hover:bg-rose-600 hover:text-white rounded-xl transition-all shadow-sm"
                        title="Eliminar"
                        disabled={c.totalDebt > 0}
                      >
                        <Trash2 className="w-5 h-5" />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
              {filteredCustomers.length === 0 && (
                <tr>
                  <td colSpan={4} className="px-8 py-20 text-center">
                    <div className="bg-gray-50 dark:bg-slate-950/50 rounded-3xl p-10 border border-dashed border-gray-200 dark:border-slate-800 inline-block">
                      <AlertCircle className="w-16 h-16 text-gray-300 mx-auto mb-4" />
                      <p className="text-xl font-bold text-gray-900 dark:text-white">No se encontraron clientes</p>
                      <p className="text-gray-500 dark:text-slate-500 mt-1">Intenta buscar con otros términos o registra uno nuevo.</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      <CustomerModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        onSave={fetchCustomers}
        customer={selectedCustomer}
      />

      <CustomerHistoryModal 
        isOpen={isHistoryModalOpen}
        onClose={() => setIsHistoryModalOpen(false)}
        customerId={selectedCustomer?.id}
        customerName={selectedCustomer?.name}
      />
    </div>
  );
}

'use client';
import { useState, useEffect, useRef } from 'react';
import { Plus, Search, Edit2, Trash2, Barcode, Download, Upload, FileSpreadsheet, CloudSync, Wifi, WifiOff } from 'lucide-react';
import * as XLSX from 'xlsx';
import { useOfflineStore } from '@/store/useOfflineStore';
import { formatCurrency, parseCurrency } from '@/utils/formatters';

interface Category {
  id: string;
  name: string;
}

interface Product {
  id: string;
  name: string;
  barcode: string | null;
  price: number;
  cost: number | null;
  profitMargin: number | null;
  stock: number;
  lowStockThreshold: number;
  categoryId: string | null;
  category?: Category;
  isActive: boolean;
  sellByWeight: boolean;
  unit: string;
}

export default function InventoryPage() {
  const { 
    isOnline, 
    products: cachedProducts, 
    categories: cachedCategories,
    setCache,
    addPendingProduct,
    addPendingCategory,
    pendingProducts,
    pendingCategories
  } = useOfflineStore();

  const [products, setProducts] = useState<Product[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [sortConfig, setSortConfig] = useState<{ key: keyof Product | 'category'; direction: 'asc' | 'desc' } | null>(null);
  
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isCategoryModalOpen, setIsCategoryModalOpen] = useState(false);
  
  // Estado para el modal de productos
  const [editingId, setEditingId] = useState<string | null>(null);
  const [name, setName] = useState('');
  const [barcode, setBarcode] = useState('');
  const [cost, setCost] = useState('');
  const [profitMargin, setProfitMargin] = useState('');
  const [price, setPrice] = useState('');
  const [stock, setStock] = useState('0');
  const [categoryId, setCategoryId] = useState('');
  const [lowStockThreshold, setLowStockThreshold] = useState('5');
  const [sellByWeight, setSellByWeight] = useState(false);
  const [unit, setUnit] = useState('UND'); // Default UND for unit-based items

  // Estado para el modal de categorías
  const [editingCategory, setEditingCategory] = useState<Category | null>(null);
  const [newCategoryName, setNewCategoryName] = useState('');
  const [categoryDescription, setCategoryDescription] = useState('');

  // Estado para gestión de productos dentro de categoría
  const [isManagingProducts, setIsManagingProducts] = useState(false);
  const [activeCategory, setActiveCategory] = useState<Category | null>(null);
  const [productSearchTerm, setProductSearchTerm] = useState('');

  // Referencia para input de archivo
  const fileInputRef = useRef<HTMLInputElement>(null);
  const searchInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    // 1. Carga inmediata del caché
    if (cachedProducts.length > 0) setProducts(cachedProducts);
    if (cachedCategories.length > 0) setCategories(cachedCategories);

    // 2. Lógica de Sincronización Inteligente
    const { lastSyncTime } = useOfflineStore.getState();
    const lastSync = lastSyncTime || 0;
    const oneHour = 60 * 60 * 1000;
    const shouldSync = Date.now() - lastSync > oneHour;

    if (isOnline) {
      if (shouldSync || cachedProducts.length === 0) {
        fetchAllData();
      } else {
        setLoading(false);
      }
    } else {
      setLoading(false);
    }

    // Si ya tenemos productos en caché, quitamos el loading inicial para mostrar datos YA
    if (cachedProducts.length > 0) {
      setLoading(false);
    }

    // Listener para refresco manual desde el Header
    const handleForceSync = () => fetchAllData();
    window.addEventListener('force-sync', handleForceSync);

    return () => window.removeEventListener('force-sync', handleForceSync);
  }, [isOnline]);

  const fetchAllData = async () => {
    setLoading(true);
    await Promise.all([
      fetchProducts(),
      fetchCategories()
    ]);
    useOfflineStore.getState().setLastSyncTime(Date.now());
    setLoading(false);
  };

  const fetchCategories = async () => {
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/categories`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      if (res.ok) {
        const data = await res.json();
        setCategories(data);
        setCache({ categories: data });
      }
    } catch (error) {
      console.error("Error fetching categories", error);
      setCategories(cachedCategories);
    }
  };

  const fetchProducts = async () => {
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/products`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      if (res.ok) {
        const data = await res.json();
        setProducts(data);
        setCache({ products: data });
      }
    } catch (error) {
      console.error("Error fetching products", error);
      setProducts(cachedProducts);
    } finally {
      setLoading(false);
    }
  };

  // Autocalculador: Cuando cambia el Costo, calcular el Precio de Venta Sugerido (Costo / 0.8)
  const handleCostChange = (newCostValue: string) => {
    const c = parseCurrency(newCostValue);
    setCost(c.toString());
    
    if (c >= 0) {
      // Precio sugerido = Costo / 0.8 (Markup del 25% sobre costo / 20% margen sobre venta)
      const calculatedPrice = c / 0.8;
      setPrice(Math.round(calculatedPrice).toString());
      
      // Margen = ((calculatedPrice - c) / c) * 100
      const calculatedMargin = c > 0 ? ((calculatedPrice - c) / c) * 100 : 0;
      setProfitMargin(Math.round(calculatedMargin).toString());
    }
  };


  // Cuando cambian utilidad manualmente
  const handleMarginChange = (newMargin: string) => {
    setProfitMargin(newMargin);
    const c = parseCurrency(cost);
    const m = parseFloat(newMargin);
    if (!isNaN(c) && !isNaN(m)) {
      const calculatedPrice = c * (1 + (m / 100));
      setPrice(Math.round(calculatedPrice).toString());
    }
  };

  // Autocalculador inverso: Si cambian el Precio de Venta directamente, ajustar el Margen
  const handlePriceChange = (newPriceValue: string) => {
    const p = parseCurrency(newPriceValue);
    setPrice(p.toString());
    
    const c = parseCurrency(cost);
    
    if (p >= 0 && c > 0) {
      // Margen = ((Precio - Costo) / Costo) * 100
      const calculatedMargin = ((p - c) / c) * 100;
      setProfitMargin(Math.round(calculatedMargin).toString());
    }
  };

  const handleCreateProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const token = localStorage.getItem('access_token');
      const payload = {
        name,
        barcode: barcode || null,
        price: parseCurrency(price),
        cost: cost ? parseCurrency(cost) : null,
        profitMargin: profitMargin ? parseFloat(profitMargin) : null,
        stock: parseFloat(stock),
        lowStockThreshold: parseInt(lowStockThreshold),
        categoryId: categoryId || null,
        sellByWeight,
        unit,
      };

      const url = editingId ? `${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/products/${editingId}` : `${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/products`;
      const method = editingId ? 'PATCH' : 'POST';

      if (!isOnline && !editingId) {
        // MODO OFFLINE - CREACIÓN
        const uuid = crypto.randomUUID();
        const localId = `temp-prod-${uuid}`;
        const newProduct = {
          ...payload,
          id: localId,
          localId,
          category: categories.find(c => c.id === categoryId),
          isActive: true
        };
        addPendingProduct(newProduct);
        setIsModalOpen(false);
        setEditingId(null); setName(''); setBarcode(''); setCost(''); setProfitMargin(''); setPrice(''); setStock('0');
        setCategoryId(''); setLowStockThreshold('5');
        setSellByWeight(false); setUnit('UND');
        return;
      }

      if (!isOnline && editingId) {
          alert('No se pueden editar productos existentes en modo offline todavía.');
          return;
      }

      const res = await fetch(url, {
        method,
        headers: { 
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}` 
        },
        body: JSON.stringify(payload)
      });

      if (res.ok) {
        setIsModalOpen(false);
        // Reset
        setEditingId(null); setName(''); setBarcode(''); setCost(''); setProfitMargin(''); setPrice(''); setStock('0');
        setCategoryId(''); setLowStockThreshold('5');
        setSellByWeight(false); setUnit('UND');
        fetchProducts();
      } else {
        const err = await res.json();
        alert(`Error: ${err.message || 'No se pudo guardar el producto'}`);
      }
    } catch (error) {
      console.error(error);
    }
  };

  const handleEdit = (product: Product) => {
    setEditingId(product.id);
    setName(product.name);
    setBarcode(product.barcode || '');
    setCost(product.cost !== null ? product.cost.toString() : '');
    setProfitMargin(product.profitMargin !== null ? product.profitMargin.toString() : '');
    setPrice(Math.round(product.price).toString());
    setStock(product.stock.toString());
    setCategoryId(product.categoryId || '');
    setLowStockThreshold(product.lowStockThreshold?.toString() || '5');
    setSellByWeight(product.sellByWeight || false);
    setUnit(product.unit || 'UND');
    setIsModalOpen(true);
  };

  const handleDelete = async (id: string, productName: string) => {
    if (window.confirm(`¿Estás seguro de que deseas eliminar permanentemente "${productName}"?`)) {
      try {
        const token = localStorage.getItem('access_token');
        const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/products/${id}`, {
          method: 'DELETE',
          headers: { Authorization: `Bearer ${token}` }
        });
        if (res.ok) {
          fetchProducts();
        } else {
          alert('Hubo un error al eliminar el producto.');
        }
      } catch (error) {
        console.error(error);
      }
    }
  };

  const openCreateModal = () => {
    setEditingId(null);
    setName(''); setBarcode(''); setCost(''); setProfitMargin(''); setPrice(''); setStock('0');
    setCategoryId(''); setLowStockThreshold('5');
    setSellByWeight(false); setUnit('UND');
    setIsModalOpen(true);
  };

  const handleScannerInput = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') {
      console.log('Escaneado:', searchTerm);
    }
  };

  const handleCreateCategory = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const token = localStorage.getItem('access_token');
      const payload = { name: newCategoryName, description: categoryDescription };
      const url = editingCategory ? `${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/categories/${editingCategory.id}` : `${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/categories`;
      const method = editingCategory ? 'PATCH' : 'POST';

      if (!isOnline && !editingCategory) {
        const uuid = crypto.randomUUID();
        const localId = `temp-cat-${uuid}`;
        const newCat = { id: localId, name: newCategoryName, localId };
        addPendingCategory(newCat);
        setNewCategoryName('');
        setCategoryDescription('');
        return;
      }

      if (!isOnline && editingCategory) {
          alert('No se puede editar categorías en modo offline.');
          return;
      }

      const res = await fetch(url, {
        method,
        headers: { 
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}` 
        },
        body: JSON.stringify(payload)
      });
      if (res.ok) {
        setNewCategoryName('');
        setCategoryDescription('');
        setEditingCategory(null);
        fetchCategories();
      }
    } catch (error) {
      console.error(error);
    }
  };

  const handleEditCategory = (category: Category) => {
    setEditingCategory(category);
    setNewCategoryName(category.name);
  };

  const handleDeleteCategory = async (id: string, catName: string) => {
    if (window.confirm(`¿Seguro que quieres borrar la categoría "${catName}"? Los productos asociados quedarán "Sin Categoría".`)) {
      try {
        const token = localStorage.getItem('access_token');
        const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/categories/${id}`, {
          method: 'DELETE',
          headers: { Authorization: `Bearer ${token}` }
        });
        if (res.ok) {
          fetchCategories();
          fetchProducts(); // Para actualizar los nombres de categorías en la tabla
        }
      } catch (error) {
        console.error(error);
      }
    }
  };

  const openManageCategoryProducts = (category: Category) => {
    setActiveCategory(category);
    setIsManagingProducts(true);
    setProductSearchTerm('');
  };

  const closeManageCategoryProducts = () => {
    setIsManagingProducts(false);
    setActiveCategory(null);
  };

  const assignProductToCategory = async (productId: string, catId: string | null) => {
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/products/${productId}`, {
        method: 'PATCH',
        headers: { 
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}` 
        },
        body: JSON.stringify({ categoryId: catId })
      });
      if (res.ok) {
        fetchProducts(); // Refrescar lista
      }
    } catch (error) {
      console.error(error);
    }
  };

  const openCreateModalWithCategory = (catId: string) => {
    openCreateModal();
    setCategoryId(catId);
    setIsCategoryModalOpen(false);
    closeManageCategoryProducts();
  };

  // --- Funciones de Import/Export ---
  const handleExport = () => {
    const dataToExport = sortedProducts.map((p: Product) => ({
      'Código de Barras': p.barcode || 'Manual',
      'Nombre': p.name,
      'Categoría': p.category?.name || 'Sin Categoría',
      'Precio Compra': p.cost || 0,
      'Utilidad (%)': p.profitMargin || 0,
      'Precio Venta': p.price,
      'Stock Actual': p.stock,
      'Mínimo Stock': p.lowStockThreshold
    }));

    const ws = XLSX.utils.json_to_sheet(dataToExport);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'Inventario');
    XLSX.writeFile(wb, `Inventario_Tiendeo_${new Date().toLocaleDateString()}.xlsx`);
  };

  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const dataBuffer = evt.target?.result as ArrayBuffer;
        const wb = XLSX.read(dataBuffer, { type: 'array' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        // Forzamos raw: false para obtener el texto formateado (ej: "$ 3,000" como string)
        // en lugar de dejar que XLSX lo convierta a número basándose en locale (que convertiría 3,000 a 3)
        const data = XLSX.utils.sheet_to_json(ws, { raw: false, defval: '' }) as any[];

        // Mapear datos a CreateProductDto
        const productsToImport = data.map((row: any) => {
          // Buscar categoría por nombre
          const catName = row['Categoría'] || row['Categoria'];
          const category = categories.find((c: Category) => c.name.toLowerCase() === String(catName || '').toLowerCase().trim());
          
          // Helper para limpiar números (moneda, stock, etc.)
          const cleanNumeric = (val: any, isDecimal = false) => {
            if (val === undefined || val === null || val === '') return null;
            // Convertir a string y quitar símbolos de moneda, espacios y letras
            let s = String(val).replace(/[$\sA-Za-z]/g, '');
            
            // Si tiene decimales ".00" o ",00" al final, los quitamos antes de procesar miles
            // para evitar que "25.00" se convierta en "2500"
            s = s.replace(/[,.]00$/, '');

            // Tal como solicita el usuario: Comma o Punto son MILES, no decimales.
            // Por lo tanto, eliminamos ambos para obtener el número limpio.
            // 3,000 -> 3000 | 3.000 -> 3000
            const cleanString = s.replace(/\./g, '').replace(/,/g, '');
            return parseFloat(cleanString) || 0;
          };

          const rawBarcode = row['Código'] || row['Código de Barras'] || row['Codigo'];

          return {
            name: String(row['Producto'] || row['Nombre'] || '').trim(),
            barcode: (rawBarcode === 'Manual' || !rawBarcode) ? null : String(rawBarcode).trim(),
            price: cleanNumeric(row['Precio Venta'] || row['Precio de Venta']) || 0,
            cost: cleanNumeric(row['Precio Compra'] || row['Precio de Compra']),
            profitMargin: cleanNumeric(row['Utilidad (%)'] || row['Utilidad'], true),
            stock: cleanNumeric(row['Stock Actual'] || row['Stock']) || 0,
            lowStockThreshold: parseInt(String(row['Mínimo Stock'] || row['Minimo Stock'] || '5')),
            categoryId: category?.id || null,
          };
        }).filter(p => p.name); // Solo productos con nombre

        console.log("Productos a importar:", productsToImport);

        if (productsToImport.length > 0) {
          const token = localStorage.getItem('access_token');
          const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/products/bulk`, {
            method: 'POST',
            headers: { 
              'Content-Type': 'application/json',
              Authorization: `Bearer ${token}` 
            },
            body: JSON.stringify(productsToImport)
          });

          if (res.ok) {
            const summary = await res.json();
            alert(`¡Éxito! Importación finalizada:\n\n- Total procesados: ${summary.total}\n- Nuevos importados: ${summary.imported}\n- Omitidos (ya existían): ${summary.skipped}`);
            fetchProducts();
          } else {
            const responseText = await res.text().catch(() => '');
            let errorMsg = 'Error desconocido en el servidor';
            try {
              const errorData = JSON.parse(responseText);
              errorMsg = Array.isArray(errorData.message) ? errorData.message.join(', ') : errorData.message;
            } catch {
              errorMsg = responseText || 'El servidor no respondió con un formato de error válido.';
            }
            alert(`Hubo un error al realizar la importación masiva:\n\n${errorMsg}`);
          }
        }
      } catch (error) {
        console.error("Error parsing excel", error);
        alert(`Formato de archivo inválido o error de procesamiento:\n${error instanceof Error ? error.message : 'Error desconocido'}`);
      }
    };
    reader.readAsArrayBuffer(file);
    // Limpiar input
    e.target.value = '';
  };

  const requestSort = (key: keyof Product | 'category') => {
    let direction: 'asc' | 'desc' = 'asc';
    if (sortConfig && sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
  };

  const sortedProducts = [...products].filter((p: Product) => {
    const term = searchTerm.toLowerCase().trim();
    const nameMatch = p.name.toLowerCase().includes(term);
    const barcodeMatch = p.barcode && p.barcode.toLowerCase().includes(term);
    return nameMatch || barcodeMatch;
  }).sort((a, b) => {
    if (!sortConfig) return 0;
    
    let aValue: any = a[sortConfig.key as keyof Product];
    let bValue: any = b[sortConfig.key as keyof Product];

    if (sortConfig.key === 'category') {
      aValue = a.category?.name || '';
      bValue = b.category?.name || '';
    }

    if (aValue === null || aValue === undefined) aValue = '';
    if (bValue === null || bValue === undefined) bValue = '';

    if (aValue < bValue) return sortConfig.direction === 'asc' ? -1 : 1;
    if (aValue > bValue) return sortConfig.direction === 'asc' ? 1 : -1;
    return 0;
  });

  const filteredProducts = sortedProducts;

  return (
    <div className="space-y-6 max-w-7xl mx-auto pb-12">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
           <h2 className="text-2xl font-bold leading-7 text-gray-900 dark:text-white sm:truncate sm:text-3xl sm:tracking-tight">
             Inventario de Productos
           </h2>
           <p className="mt-1 text-sm text-gray-500 dark:text-gray-400">
             Administra tu catálogo. Escanea códigos o crea productos manuales.
           </p>
        </div>
        
        <div className="flex flex-wrap gap-2">
          <button 
            onClick={handleExport}
            title="Exportar inventario a Excel"
            className="inline-flex items-center rounded-xl bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 px-4 py-2.5 text-sm font-semibold text-emerald-600 dark:text-emerald-400 shadow-sm hover:bg-emerald-50 dark:hover:bg-emerald-900/10 transition-colors"
          >
            <Download className="mr-2 h-4 w-4" />
            Exportar
          </button>
          <button 
            onClick={handleImportClick}
            title="Importar productos desde Excel"
            className="inline-flex items-center rounded-xl bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 px-4 py-2.5 text-sm font-semibold text-blue-600 dark:text-blue-400 shadow-sm hover:bg-blue-50 dark:hover:bg-blue-900/10 transition-colors"
          >
            <Upload className="mr-2 h-4 w-4" />
            Importar
          </button>
          <input 
            type="file" 
            ref={fileInputRef} 
            title="Seleccionar archivo para importar"
            className="hidden" 
            accept=".xlsx, .xls, .csv" 
            onChange={handleFileImport}
          />
          <button 
            onClick={() => setIsCategoryModalOpen(true)}
            title="Gestionar categorías"
            className="inline-flex items-center rounded-xl bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 px-4 py-2.5 text-sm font-semibold text-gray-700 dark:text-gray-300 shadow-sm hover:bg-gray-50 dark:hover:bg-slate-700 transition-colors"
          >
            Categorías
          </button>
          <button 
            onClick={openCreateModal}
            className="inline-flex items-center rounded-xl bg-blue-600 px-4 py-2.5 text-sm font-semibold text-white shadow-sm hover:bg-blue-500 transition-colors"
          >
            <Plus className="-ml-1 mr-2 h-5 w-5" />
            Añadir Producto
          </button>
        </div>
      </div>

      <div className="flex bg-white dark:bg-slate-900 p-4 rounded-xl border border-gray-200 dark:border-slate-800 shadow-sm transition-colors">
        <div className="relative flex-1 max-w-md">
          <div className="pointer-events-none absolute inset-y-0 left-0 flex items-center pl-3">
            <Barcode className="h-5 w-5 text-gray-400" />
          </div>
          <input
            ref={searchInputRef}
            type="text"
            className="block w-full rounded-lg border-0 py-2.5 pl-10 text-gray-900 dark:text-white ring-1 ring-inset ring-gray-300 dark:ring-slate-700 placeholder:text-gray-400 focus:ring-2 focus:ring-inset focus:ring-blue-600 dark:bg-slate-800 sm:text-sm sm:leading-6 transition-colors"
            placeholder="Pistolear código o buscar por nombre..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            onKeyDown={handleScannerInput}
            autoFocus
          />
        </div>
      </div>

      <div className="bg-white dark:bg-slate-900 rounded-xl shadow-sm border border-gray-200 dark:border-slate-800 overflow-hidden transition-colors">
        <div className="overflow-x-auto scrollbar-hide">
          <table className="min-w-full divide-y divide-gray-200 dark:divide-slate-800">
            <thead className="bg-gray-50 dark:bg-slate-800/50 sticky top-0 z-10">
              <tr>
                <th 
                  scope="col" 
                  className="px-6 py-3 text-left text-xs font-black text-gray-500 dark:text-gray-400 uppercase tracking-wider min-w-[120px] cursor-pointer hover:bg-gray-100 dark:hover:bg-slate-700 transition-colors"
                  onClick={() => requestSort('barcode')}
                >
                  Código {sortConfig?.key === 'barcode' && (sortConfig.direction === 'asc' ? '↑' : '↓')}
                </th>
                <th 
                  scope="col" 
                  className="px-6 py-3 text-left text-xs font-black text-gray-500 dark:text-gray-400 uppercase tracking-wider min-w-[200px] cursor-pointer hover:bg-gray-100 dark:hover:bg-slate-700 transition-colors"
                  onClick={() => requestSort('name')}
                >
                  Producto {sortConfig?.key === 'name' && (sortConfig.direction === 'asc' ? '↑' : '↓')}
                </th>
                <th 
                  scope="col" 
                  className="px-6 py-3 text-left text-xs font-black text-gray-500 dark:text-gray-400 uppercase tracking-wider min-w-[150px] cursor-pointer hover:bg-gray-100 dark:hover:bg-slate-700 transition-colors"
                  onClick={() => requestSort('category')}
                >
                  Categoría {sortConfig?.key === 'category' && (sortConfig.direction === 'asc' ? '↑' : '↓')}
                </th>
                <th 
                  scope="col" 
                  className="px-6 py-3 text-left text-xs font-black text-gray-500 dark:text-gray-400 uppercase tracking-wider min-w-[150px] cursor-pointer hover:bg-gray-100 dark:hover:bg-slate-700 transition-colors"
                  onClick={() => requestSort('price')}
                >
                  Precio de Venta {sortConfig?.key === 'price' && (sortConfig.direction === 'asc' ? '↑' : '↓')}
                </th>
                <th 
                  scope="col" 
                  className="px-6 py-3 text-left text-xs font-black text-gray-500 dark:text-gray-400 uppercase tracking-wider min-w-[100px] cursor-pointer hover:bg-gray-100 dark:hover:bg-slate-700 transition-colors"
                  onClick={() => requestSort('stock')}
                >
                  Stock {sortConfig?.key === 'stock' && (sortConfig.direction === 'asc' ? '↑' : '↓')}
                </th>
                <th scope="col" className="relative px-6 py-3"><span className="sr-only">Acciones</span></th>
              </tr>
            </thead>
            <tbody className="bg-white dark:bg-slate-900 divide-y divide-gray-200 dark:divide-slate-800">
              {loading && products.length === 0 ? (
                <tr>
                  <td colSpan={5} className="px-6 py-10 text-center text-gray-500 dark:text-gray-400">Cargando inventario...</td>
                </tr>
              ) : filteredProducts.length === 0 ? (
                <tr>
                  <td colSpan={6} className="px-6 py-10 text-center text-gray-500 dark:text-gray-400">No hay productos. ¡Agrega el primero!</td>
                </tr>
              ) : (
                filteredProducts.map((product: Product) => {
                  const isLowStock = product.stock <= (product.lowStockThreshold || 5);
                  return (
                    <tr key={product.id} className="hover:bg-gray-50 dark:hover:bg-slate-800/50 transition-colors">
                      <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900 dark:text-gray-200">
                        {product.barcode || <span className="text-gray-400 italic">Manual</span>}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm">
                        <span className="font-semibold text-gray-900 dark:text-white leading-tight">{product.name}</span>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm">
                        <span className="text-[11px] font-bold text-gray-400 dark:text-gray-500 uppercase tracking-wide bg-gray-100 dark:bg-slate-800 px-2.5 py-1 rounded-lg">
                          {product.category?.name || 'Sin Categoría'}
                        </span>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-green-600 dark:text-green-400 font-black">
                        ${formatCurrency(product.price)}
                        {product.sellByWeight && (
                          <span className="text-[10px] text-gray-400 ml-1 font-bold uppercase">/ {product.unit}</span>
                        )}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm">
                        <span className={`px-2 py-1 rounded-full font-bold ${
                          isLowStock 
                            ? 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400 animate-pulse' 
                            : 'text-gray-900 dark:text-gray-300'
                        }`}>
                          {product.stock} {product.sellByWeight ? product.unit : ''}
                        </span>
                        {(product as any).localId && (
