                      <Plus className="h-3 w-3" /> Crear Nuevo Producto aquí
                    </button>
                  </div>
                </div>
              )}
            </div>

            <div className="px-6 py-4 bg-gray-50 dark:bg-slate-800/30 border-t border-gray-100 dark:border-slate-800 flex justify-end gap-2">
