  const [selectedOrderId, setSelectedOrderId] = useState<string | null>(null);
  const [expandedOrderId, setExpandedOrderId] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [notification, setNotification] = useState<{message: string, type: 'error' | 'success'} | null>(null);

  // Numpad State (Quantity Editing)
  const [showNumpad, setShowNumpad] = useState<{
    orderId: string,
    itemId: string,
    title: string,
    initialValue: string
  } | null>(null);
  const [numpadValue, setNumpadValue] = useState('0');

  // Payment Modal State
  const [showPaymentModal, setShowPaymentModal] = useState(false);
  const [payingOrder, setPayingOrder] = useState<OpenSale | null>(null);
  const [payingItem, setPayingItem] = useState<{orderId: string, itemId: string, itemSubtotal: number} | null>(null);
  const [cashReceived, setCashReceived] = useState('');
  const [paymentFinished, setPaymentFinished] = useState(false);
  const [changeAmount, setChangeAmount] = useState(0);

  const searchInputRef = useRef<HTMLInputElement>(null);
  const closeButtonRef = useRef<HTMLButtonElement>(null);

  useEffect(() => {
    fetchInitialData();
  }, []);

  // Auto-hide notification
  useEffect(() => {
    if (notification) {
      const timer = setTimeout(() => setNotification(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [notification]);

  // Persistent Focus Logic
  useEffect(() => {
    const focusTimer = setTimeout(() => {
      if (!showPaymentModal && !isProcessing) {
        searchInputRef.current?.focus();
      }
    }, 100);
    return () => clearTimeout(focusTimer);
  }, [showPaymentModal, isProcessing, orders.length]);

  // Focus on Close button after payment success
  useEffect(() => {
    if (paymentFinished) {
      setTimeout(() => closeButtonRef.current?.focus(), 100);
    }
  }, [paymentFinished]);

  const fetchInitialData = async () => {
    try {
      const token = localStorage.getItem('access_token');
      const [resOrders, resWaiters, resProducts] = await Promise.all([
        fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/restaurant/open`, {
          headers: { Authorization: `Bearer ${token}` }
        }),
        fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/waiters`, {
          headers: { Authorization: `Bearer ${token}` }
        }),
        fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/products`, {
          headers: { Authorization: `Bearer ${token}` }
        })
      ]);

      if (resOrders.ok) {
        const data = await resOrders.json();
        setOrders(data);
        if (data.length > 0) {
           setSelectedOrderId(data[0].id);
           setExpandedOrderId(data[0].id);
        }
      }
      if (resWaiters.ok) setWaiters(await resWaiters.json());
      if (resProducts.ok) setProducts(await resProducts.json());
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleCreateOrder = async (waiterId?: string) => {
    setIsProcessing(true);
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/restaurant/order`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`
        },
        body: JSON.stringify({ 
          tableName: 'Barra',
          waiterId: waiterId || waiters[0]?.id,
          items: [] 
        })
      });

      if (res.ok) {
        const newOrder = await res.json();
        setOrders(prev => [newOrder, ...prev]);
        setSelectedOrderId(newOrder.id);
        setExpandedOrderId(newOrder.id);
      }
    } catch (err) {
      console.error(err);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleCancelOrder = async (orderId: string) => {
    if (!confirm('¿Estás seguro de cancelar todo este pedido? Los productos regresarán al inventario.')) return;

    setIsProcessing(true);
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/restaurant/order/${orderId}`, {
        method: 'DELETE',
        headers: { Authorization: `Bearer ${token}` }
      });

      if (res.ok) {
        setOrders(prev => prev.filter(o => o.id !== orderId));
        setNotification({ message: 'Pedido cancelado', type: 'success' });
        if (selectedOrderId === orderId) {
          setSelectedOrderId(null);
          setExpandedOrderId(null);
        }
      } else {
        setNotification({ message: 'No se pudo cancelar el pedido', type: 'error' });
      }
    } catch (err) {
      console.error(err);
      setNotification({ message: 'Error de red al cancelar', type: 'error' });
    } finally {
      setIsProcessing(false);
    }
  };


  const handleAddItemToOrder = async (orderId: string, product: Product) => {
    setIsProcessing(true);
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/restaurant/order/${orderId}/items`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`
        },
        body: JSON.stringify({ 
          items: [{
            productId: product.id,
            productName: product.name,
            quantity: 1,
            unitPrice: product.price
          }] 
        })
      });

      if (res.ok) {
        const updatedOrder = await res.json();
        console.log("[DEBUG] Pedido Actualizado (Add):", updatedOrder);
        // Forzar clonado profundo para asegurar re-render de items anidados
        setOrders(prev => prev.map(o => o.id === orderId ? { ...JSON.parse(JSON.stringify(updatedOrder)) } : o));
        setNotification({ message: `${product.name} añadido`, type: 'success' });
      }
    } catch (err) {
      console.error(err);
    } finally {
      setIsProcessing(false);
      setSearchQuery('');
    }
  };

  const handleSearchChange = (value: string) => {
    setSearchQuery(value);

    // Auto-Add Logic for Barcode
    if (value.length >= 6 && !isProcessing) {
      const exactMatch = products.find(p => p.barcode === value);
      if (exactMatch) {
         if (selectedOrderId) {
            // Limpiar inmediatamente para evitar múltiples peticiones del lector
            setSearchQuery('');
            handleAddItemToOrder(selectedOrderId, exactMatch);
         } else {
            setNotification({ message: 'Por favor, selecciona un pedido primero', type: 'error' });
            setSearchQuery('');
         }
      }
    }
  };

  const handleUpdateQuantity = async (orderId: string, itemId: string, newQuantity: number) => {
    if (newQuantity <= 0) return handleRemoveItem(orderId, itemId);

    setIsProcessing(true);
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/restaurant/order/${orderId}/items/${itemId}`, {
        method: 'PATCH',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`
        },
        body: JSON.stringify({ quantity: newQuantity })
      });

      if (res.ok) {
        const updatedOrder = await res.json();
        console.log("[DEBUG] Pedido Actualizado (Qty):", updatedOrder);
        // Clonado forzado
        setOrders(prev => prev.map(o => o.id === orderId ? { ...JSON.parse(JSON.stringify(updatedOrder)) } : o));
      }
    } catch (err) {
      console.error(err);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleRemoveItem = async (orderId: string, itemId: string) => {
    setIsProcessing(true);
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/restaurant/order/${orderId}/items/${itemId}`, {
        method: 'DELETE',
        headers: { Authorization: `Bearer ${token}` }
      });

      if (res.ok) {
        const updatedOrder = await res.json();
        console.log("[DEBUG] Pedido Actualizado (Remove):", updatedOrder);
        setOrders(prev => prev.map(o => o.id === orderId ? { ...JSON.parse(JSON.stringify(updatedOrder)) } : o));
      }
    } catch (err) {
      console.error(err);
    } finally {
      setIsProcessing(false);
    }
  };

  const handlePayOrder = (order: OpenSale) => {
    setPayingOrder(order);
    setPayingItem(null);
    setCashReceived('');
    setPaymentFinished(false);
    setShowPaymentModal(true);
  };

  const handlePayItem = (order: OpenSale, item: any) => {
    setPayingOrder(order);
    setPayingItem({
      orderId: order.id,
      itemId: item.id,
      itemSubtotal: Number(item.subtotal)
    });
    setCashReceived('');
    setPaymentFinished(false);
    setShowPaymentModal(true);
  };

  const confirmPayment = async () => {
    if (!payingOrder) return;

    // Si estamos pagando un item solo, el total es su subtotal
    const targetTotal = payingItem ? payingItem.itemSubtotal : payingOrder.totalAmount;

    const received = parseCurrency(cashReceived);
    const amountToReturn = received - targetTotal;

    setIsProcessing(true);
    try {
      const token = localStorage.getItem('access_token');

      let url = `${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/restaurant/order/${payingOrder.id}/close`;
      if (payingItem) {
        url = `${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/restaurant/order/${payingItem.orderId}/items/${payingItem.itemId}/pay`;
      }

      const res = await fetch(url, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`
        },
        body: JSON.stringify({ paymentMethod: 'efectivo' })
      });

      if (res.ok) {
        const result = await res.json();
        setChangeAmount(amountToReturn);
        setPaymentFinished(true);

        if (payingItem) {
          // El backend devuelve el pedido actualizado tras retirar el item
          setOrders(prev => prev.map(o => o.id === payingOrder.id ? result : o));
        } else {
          // Si era el pedido completo, lo quitamos de la lista
          setOrders(prev => prev.filter(o => o.id !== payingOrder.id));
        }
      }
    } catch (err) {
      console.error(err);
    } finally {
      setIsProcessing(false);
    }
  };

  const filteredProducts = searchQuery.length > 1 
    ? products.filter(p => 
        p.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
        (p.barcode && p.barcode.includes(searchQuery))
      ).slice(0, 5)
    : [];

  return (
    <div className="max-w-full mx-auto space-y-6 animate-in fade-in duration-500 pb-20 relative">

      {/* Notifications */}
      {notification && (
        <div className={`fixed top-24 right-8 z-[100] p-4 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-right duration-300 ${notification.type === 'error' ? 'bg-rose-600 text-white' : 'bg-emerald-600 text-white'}`}>
           {notification.type === 'error' ? <AlertCircle className="w-6 h-6" /> : <CheckCircle2 className="w-6 h-6" />}
           <p className="font-black text-sm">{notification.message}</p>
        </div>
      )}

      {/* Search Header (Sticky) */}
      <div className="sticky top-0 z-40 -mt-2 bg-slate-950/80 backdrop-blur-xl border-b border-slate-800 p-6 -mx-8 px-8 mb-6 flex flex-col md:flex-row items-center justify-between gap-6 shadow-xl">
        <div className="flex items-center gap-4">
          <div className="bg-blue-600 p-4 rounded-2xl shadow-lg shadow-blue-500/20">
             <ClipboardCheck className="w-8 h-8 text-white" />
          </div>
          <div>
            <h1 className="text-3xl font-black text-white tracking-tight">Caja Registradora</h1>
            <p className="text-slate-400 text-sm font-bold uppercase tracking-widest">Gestión de Pedidos en Barra</p>
          </div>
        </div>

        <div className="flex-1 max-w-2xl w-full relative">
          <div className="relative group">
            <Search className="absolute left-6 top-1/2 -translate-y-1/2 w-6 h-6 text-slate-500 group-focus-within:text-blue-500 transition-colors" />
            <input
              ref={searchInputRef}
              type="text"
              placeholder="Escanea el código o busca por nombre..."
              value={searchQuery}
              onChange={(e) => handleSearchChange(e.target.value)}
              className="w-full bg-slate-950 border-2 border-slate-800 rounded-3xl py-5 pl-16 pr-8 text-white font-black placeholder-slate-600 focus:outline-none focus:ring-4 focus:ring-blue-500/20 focus:border-blue-500 transition-all text-xl shadow-inner min-h-[70px]"
              onBlur={(e) => {
                // Solo re-enfocar si no estamos intentando interactuar con otro elemento importante (como el modal o el selector de mesero)
                if (!showPaymentModal && !isProcessing) {
                  const timer = setTimeout(() => {
                    const activeEl = document.activeElement as HTMLElement | null;
                    if (activeEl?.tagName !== 'INPUT' && 
                        activeEl?.tagName !== 'SELECT' && 
                        activeEl?.contentEditable !== 'true') {
                      searchInputRef.current?.focus();
                    }
                  }, 150);
                  return () => clearTimeout(timer);
                }
              }}
            />
          </div>

          {/* Search Dropdown */}
          {filteredProducts.length > 0 && (
            <div className="absolute top-full left-0 right-0 mt-3 bg-slate-900 border-2 border-slate-800 rounded-[2.5rem] shadow-2xl overflow-hidden z-50 animate-in zoom-in-95 duration-200">
              {filteredProducts.map(product => (
                <button
                  key={product.id}
                  onClick={() => {
                    if (selectedOrderId) {
                      handleAddItemToOrder(selectedOrderId, product);
                    } else {
                      setNotification({ message: 'Selecciona un pedido primero', type: 'error' });
                      setSearchQuery('');
                    }
                  }}
                  className="w-full flex items-center justify-between p-6 hover:bg-slate-800 text-left transition-colors border-b-2 border-slate-800/50 last:border-0"
                >
                  <div className="flex items-center gap-5">
                    <div className="bg-slate-800 p-3 rounded-2xl">
                      <ShoppingCart className="w-6 h-6 text-slate-400" />
                    </div>
                    <div>
                      <p className="text-white font-black text-lg">{product.name}</p>
                      <div className="flex items-center gap-3">
                        <p className="text-blue-500 font-bold">${formatCurrency(product.price)}</p>
                        {product.barcode && <p className="text-slate-500 text-xs font-mono">{product.barcode}</p>}
                      </div>
                    </div>
                  </div>
                  <div className="bg-blue-600/20 text-blue-500 p-3 rounded-full hover:bg-blue-600 hover:text-white transition-all">
                    <Plus className="w-6 h-6" />
                  </div>
                </button>
              ))}
            </div>
          )}
        </div>

        <button 
          onClick={() => handleCreateOrder()}
          className="bg-blue-600 hover:bg-blue-500 text-white px-10 py-5 rounded-[2rem] font-black flex items-center gap-3 transition-all shadow-xl shadow-blue-900/40 active:scale-95 whitespace-nowrap min-h-[70px] text-lg"
        >
          <Plus className="w-7 h-7" />
          Nuevo Pedido
        </button>
      </div>

      {/* Orders List (Rows) */}
      <div className="space-y-6">
        {isLoading ? (
          <div className="flex flex-col items-center justify-center py-40 space-y-4">
            <Loader2 className="w-16 h-16 text-blue-500 animate-spin" />
            <p className="text-slate-500 font-black tracking-widest uppercase">Consultando pedidos abiertos...</p>
          </div>
        ) : (
          orders.map((order) => {
            const isExpanded = expandedOrderId === order.id;
            const isSelected = selectedOrderId === order.id;

            return (
              <div 
                key={order.id}
                className={`
                  group bg-slate-900/40 border-2 rounded-[2.5rem] transition-all overflow-hidden relative
                  ${isSelected ? 'border-blue-600/50 bg-slate-800/60 shadow-2xl' : 'border-slate-800 hover:border-slate-700 hover:bg-slate-900/60 shadow-lg'}
                `}
              >
                {/* Header of Row */}
                <div 
                  className="p-6 flex flex-col md:flex-row items-center gap-6 md:gap-10 cursor-pointer"
                  onClick={() => {
                    setSelectedOrderId(order.id);
                    setExpandedOrderId(isExpanded ? null : order.id);
                  }}
                >
                  {/* Selection Indicator */}
                  <div className={`
                    absolute left-0 top-0 bottom-0 w-3 transition-all
                    ${isSelected ? 'bg-blue-600' : 'bg-transparent'}
                  `} />

                  {/* Waiter Information */}
                  <div className="min-w-[180px] w-full md:w-auto">
                    <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 flex items-center gap-2 mb-2">
                       Mesero
                    </p>
                    <div className="flex items-center gap-3">
                       <div className={`p-3 rounded-2xl ${isSelected ? 'bg-blue-600 text-white shadow-lg' : 'bg-slate-800 text-slate-400'}`}>
                          <User className="w-6 h-6" />
                       </div>
                       <select 
                        value={order.waiterId}
                        onClick={(e) => e.stopPropagation()}
                        onChange={(e) => {
                          fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/restaurant/order/${order.id}/waiter`, {
                            method: 'PATCH',
                            headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${localStorage.getItem('access_token')}` },
                            body: JSON.stringify({ waiterId: e.target.value })
                          });
                          setOrders(prev => prev.map(o => o.id === order.id ? { ...o, waiterId: e.target.value } : o));
                        }}
                        className="bg-transparent text-white font-black focus:outline-none cursor-pointer text-lg flex-1 md:w-32"
                      >
                        {waiters.map(w => <option key={w.id} value={w.id} className="bg-slate-900">{w.name}</option>)}
                      </select>
                    </div>
                  </div>

                  {/* Order Summary Label */}
                  <div className="flex-1 w-full text-center md:text-left">
                     <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-1">Items en pedido</p>
                     <p className="text-xl font-black text-white">
                        {order.items?.length || 0} productos registrados
                     </p>
                     <p className="text-slate-500 text-sm font-medium mt-1">
                        Toca para ver el detalle {isExpanded ? '▲' : '▼'}
                     </p>
                  </div>

                  {/* Total Financial Section */}
                  <div className="text-right min-w-[200px] w-full md:w-auto">
                    <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500">Total a Cobrar</p>
                    <p className="text-5xl font-black text-rose-500 tracking-tighter drop-shadow-sm">
                      ${formatCurrency(order.totalAmount)}
                    </p>
                  </div>

                  {/* Pay Button & Delete Button Container */}
                  <div className="flex gap-2 w-full md:w-auto mt-4 md:mt-0">
                    <button 
                      onClick={(e) => {
                         e.stopPropagation();
                         handlePayOrder(order);
                      }}
                      className="flex-1 md:flex-none bg-[#10b981] hover:bg-[#059669] text-white px-8 py-5 rounded-[2rem] font-black text-xl uppercase tracking-wider flex items-center justify-center gap-3 transition-all shadow-xl shadow-emerald-500/20 active:scale-95 min-h-[80px]"
                    >
                      Pagar Pedido
                    </button>
                    <button
                      disabled={isProcessing}
                      onClick={(e) => { e.stopPropagation(); handleCancelOrder(order.id); }}
                      className="w-[80px] bg-rose-600 hover:bg-rose-500 text-white rounded-[2rem] flex items-center justify-center transition-all shadow-xl shadow-rose-500/20 active:scale-95 disabled:opacity-30"
                      title="Cancelar Pedido Completo"
                    >
                      <Trash2 className="w-8 h-8" />
                    </button>
                  </div>
                </div>

                {/* Expanded Item List (Vertical Accordion) */}
                <div className={`
                    border-t-2 border-slate-800/50 bg-slate-950/30 overflow-hidden transition-all duration-300 ease-in-out
                    ${isExpanded ? 'max-h-[1000px] opacity-100' : 'max-h-0 opacity-0'}
                `}>
                   <div className="p-6 space-y-4">
                      {order.items?.map((item) => (
                        <div key={item.id} className="bg-slate-900/40 border border-slate-800 rounded-3xl p-5 flex flex-col sm:flex-row items-center justify-between gap-6 hover:bg-slate-800/40 transition-colors">
                           <div className="flex items-center gap-5 flex-1 min-w-0">
                              <div className="w-12 h-12 bg-slate-800 rounded-2xl flex items-center justify-center flex-shrink-0">
                                 <ShoppingCart className="w-6 h-6 text-slate-500" />
                              </div>
                              <div className="truncate">
                                 <p className="text-white font-black text-lg truncate uppercase tracking-tight">{item.productName}</p>
                                 <p className="text-blue-500 font-bold">${formatCurrency(item.unitPrice)} p/u</p>
                              </div>
                           </div>

                           <div className="flex items-center gap-10">
                              {/* Quantity Controls - Optimized for Touch */}
                              <div className="flex items-center bg-slate-950 p-2 rounded-2xl border-2 border-slate-800">
                                <button 
                                  disabled={isProcessing}
                                  onClick={(e) => { e.stopPropagation(); handleUpdateQuantity(order.id, item.id, item.quantity - 1); }}
                                  className="p-4 text-slate-400 hover:text-white hover:bg-slate-800 rounded-xl transition-all active:scale-90 disabled:opacity-30 disabled:pointer-events-none"
                                >
                                  <Minus className="w-6 h-6" />
                                </button>
                                <span 
                                  onClick={(e) => { 
                                    e.stopPropagation(); 
                                    setNumpadValue(String(item.quantity));
                                    setShowNumpad({
                                      orderId: order.id,
                                      itemId: item.id,
                                      title: `Cantidad: ${item.productName}`,
                                      initialValue: String(item.quantity)
                                    });
                                  }}
                                  className="px-6 text-center text-white font-black text-2xl min-w-[60px] cursor-pointer hover:text-emerald-400 active:scale-90 transition-all select-none bg-slate-900 mx-2 py-4 rounded-xl shadow-inner border border-slate-800"
                                >
                                  {item.quantity}
                                </span>
                                <button 
                                  disabled={isProcessing}
                                  onClick={(e) => { e.stopPropagation(); handleUpdateQuantity(order.id, item.id, item.quantity + 1); }}
                                  className="p-4 text-slate-400 hover:text-white hover:bg-slate-800 rounded-xl transition-all active:scale-90 disabled:opacity-30 disabled:pointer-events-none"
                                >
                                  <Plus className="w-6 h-6" />
                                </button>
                              </div>

                              <div className="text-right min-w-[120px]">
                                 <p className="text-[10px] font-black text-slate-600 uppercase mb-1">Subtotal</p>
                                 <p className="text-2xl font-black text-white">${formatCurrency(item.subtotal)}</p>
                              </div>

                            <div className="flex items-center gap-3">
                              <button 
                                disabled={isProcessing}
                                onClick={(e) => { e.stopPropagation(); handlePayItem(order, item); }}
                                className="p-5 text-emerald-600 hover:text-emerald-500 hover:bg-emerald-500/10 rounded-2xl transition-all active:scale-95 disabled:opacity-30"
                                title="Pagar este item"
                              >
                                <Banknote className="w-7 h-7" />
                              </button>

                              <button 
                                disabled={isProcessing}
                                onClick={(e) => { e.stopPropagation(); handleRemoveItem(order.id, item.id); }}
                                className="p-5 text-slate-600 hover:text-rose-500 hover:bg-rose-500/10 rounded-2xl transition-all active:scale-95 disabled:opacity-30"
                                title="Eliminar del pedido"
                              >
                                <Trash2 className="w-7 h-7" />
                              </button>
                            </div>
                           </div>
                        </div>
                      ))}
                      {order.items?.length === 0 && (
                        <div className="text-center py-10">
                           <ShoppingCart className="w-16 h-16 text-slate-800 mx-auto mb-4" />
                           <p className="text-slate-600 font-bold uppercase tracking-widest text-sm">Este pedido no tiene productos registrados</p>
                        </div>
                      )}
                   </div>
                </div>
              </div>
            )
          })
        )}
      </div>

      {/* Payment Modal */}
      {showPaymentModal && payingOrder && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/90 backdrop-blur-xl animate-in fade-in duration-300" onClick={() => !isProcessing && setShowPaymentModal(false)} />

          <div className="relative w-full max-w-2xl bg-white dark:bg-slate-900 rounded-[3.5rem] shadow-[0_0_100px_rgba(0,0,0,0.5)] overflow-hidden animate-in zoom-in-95 duration-200">
             {!paymentFinished ? (
               <div className="p-10 md:p-14 flex flex-col items-center">
                  <div className="w-24 h-24 bg-emerald-100 dark:bg-emerald-900/30 rounded-3xl flex items-center justify-center mb-8 shadow-inner">
                    <Banknote className="w-12 h-12 text-emerald-600" />
                  </div>
                  <h2 className="text-4xl font-black text-slate-900 dark:text-white mb-3">{payingItem ? 'Pago de Producto' : 'Proceso de Pago'}</h2>
                  <p className="text-slate-500 font-bold mb-10 uppercase tracking-[0.2em] text-sm">
                    {payingItem ? 'Subtotal Item: ' : 'Total a pagar: '}
                    <span className="text-rose-500 text-lg"> ${formatCurrency(payingItem ? payingItem.itemSubtotal : payingOrder.totalAmount)}</span>
                  </p>

                  <div className="w-full space-y-6">
                    <div className="bg-slate-50 dark:bg-slate-950 p-6 rounded-[2.5rem] border-2 border-slate-100 dark:border-slate-800 shadow-inner">
                       <p className="text-xs font-black text-slate-400 mb-4 uppercase tracking-widest text-center">Efectivo Recibido</p>
                       <div className="w-full bg-slate-900 rounded-3xl py-4 flex items-center justify-center border border-slate-800 shadow-inner mb-6">
                          <span className="text-5xl font-black text-slate-300 mr-2">$</span>
                          <span className="text-6xl font-black text-emerald-400 tracking-tighter">
                            {formatCurrency(cashReceived || '0')}
                          </span>
                       </div>

                       {/* Touch Numpad for Payment */}
                       <div className="grid grid-cols-3 gap-3">
                          {[7, 8, 9, 4, 5, 6, 1, 2, 3].map(num => (
                            <button
                              key={num}
                              onClick={() => setCashReceived(prev => prev === '0' ? String(num) : prev + num)}
                              className="bg-slate-800 hover:bg-slate-700 text-white text-3xl font-black py-4 rounded-2xl active:scale-95 transition-all shadow-md"
                            >
                              {num}
                            </button>
                          ))}
                          <button
                            onClick={() => setCashReceived('0')}
                            className="bg-slate-800/60 hover:bg-rose-500/20 text-rose-500 text-2xl font-black py-4 rounded-2xl active:scale-95 transition-all shadow-md uppercase"
                          >
                            Borrar
                          </button>
                          <button
                            onClick={() => setCashReceived(prev => prev === '0' ? '0' : prev + '0')}
                            className="bg-slate-800 hover:bg-slate-700 text-white text-3xl font-black py-4 rounded-2xl active:scale-95 transition-all shadow-md"
                          >
                            0
                          </button>
                          <button
                            onClick={() => setCashReceived(prev => prev === '0' ? '0' : prev + '000')}
                            className="bg-slate-800 hover:bg-emerald-500/20 text-emerald-400 text-xl font-black py-4 rounded-2xl active:scale-95 transition-all shadow-md"
                          >
                            000
                          </button>
                       </div>
                    </div>

                    {parseCurrency(cashReceived) > 0 && (
                      <div className={`p-8 rounded-[2.5rem] flex justify-between items-center animate-in slide-in-from-top-4 ${parseCurrency(cashReceived) >= (payingItem ? payingItem.itemSubtotal : payingOrder.totalAmount) ? 'bg-emerald-600' : 'bg-rose-600'} text-white shadow-2xl transition-all duration-300`}>
                        <span className="font-black uppercase tracking-widest text-sm">
                          {parseCurrency(cashReceived) >= (payingItem ? payingItem.itemSubtotal : payingOrder.totalAmount) ? 'Vueltas a devolver' : 'Faltan fondos'}
                        </span>
                        <span className="text-4xl font-black">
                           ${formatCurrency(Math.abs(parseCurrency(cashReceived) - (payingItem ? payingItem.itemSubtotal : payingOrder.totalAmount)))}
                        </span>
                      </div>
                    )}

                    <div className="flex gap-6">
                      <button 
                        disabled={isProcessing}
                        onClick={() => setShowPaymentModal(false)}
                        className="flex-1 py-6 rounded-[2rem] bg-slate-100 dark:bg-slate-800 text-slate-400 font-black uppercase text-lg hover:bg-slate-200 dark:hover:bg-slate-700 transition-all active:scale-95 disabled:opacity-30"
                      >
                        Cancelar
                      </button>
                      <button 
                         disabled={isProcessing || parseCurrency(cashReceived) < (payingItem ? payingItem.itemSubtotal : payingOrder.totalAmount)}
                         onClick={confirmPayment}
                         className="flex-1 py-6 rounded-[2rem] bg-emerald-600 text-white font-black uppercase text-lg hover:bg-emerald-500 shadow-[0_15px_30px_rgba(16,185,129,0.3)] disabled:opacity-30 transition-all active:scale-95"
                      >
                         {isProcessing ? 'Procesando...' : 'Confirmar Venta'}
                      </button>
                    </div>
                  </div>
               </div>
             ) : (
               <div className="p-16 flex flex-col items-center text-center animate-in zoom-in-95 duration-500">
                  <div className="w-32 h-32 bg-emerald-100 dark:bg-emerald-900/30 rounded-full flex items-center justify-center mb-10 shadow-2xl">
                     <CheckCircle2 className="w-16 h-16 text-emerald-600" />
                  </div>
                  <h2 className="text-5xl font-black text-slate-900 dark:text-white mb-4 tracking-tight">¡Venta Exitosa!</h2>
                  <p className="text-slate-500 font-bold uppercase tracking-[0.3em] text-sm mb-12">Toda la orden ha sido liquidada</p>

                  <div className="w-full bg-emerald-600 text-white p-10 rounded-[3rem] mb-12 shadow-[0_25px_50px_rgba(16,185,129,0.4)] relative overflow-hidden">
                     <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full blur-3xl -translate-y-1/2 translate-x-1/2"></div>
                     <p className="text-xs font-black uppercase tracking-widest opacity-80 mb-3">Entregar Vueltas</p>
                     <p className="text-7xl font-black tracking-tighter">${formatCurrency(changeAmount)}</p>
                  </div>

                  <button 
                    ref={closeButtonRef}
                    onClick={() => {
                      setShowPaymentModal(false);
                      setPayingOrder(null);
                    }}
                    className="w-full py-7 rounded-[2.5rem] bg-slate-900 text-white font-black uppercase text-2xl hover:bg-black transition-all shadow-xl active:scale-95 focus:ring-4 focus:ring-emerald-500 outline-none"
                  >
                    CERRAR
                  </button>
               </div>
             )}
          </div>
        </div>
      )}

      {/* Touch Numpad Modal for Quantity */}
      {showNumpad && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/90 backdrop-blur-md animate-in fade-in" onClick={() => !isProcessing && setShowNumpad(null)} />
          <div className="relative w-full max-w-sm bg-slate-900 rounded-[3rem] p-8 shadow-2xl border-2 border-slate-800 animate-in zoom-in-95">
            <h3 className="text-xl font-black text-white text-center mb-6 truncate px-4">{showNumpad.title}</h3>

            <div className="bg-slate-950 rounded-3xl p-6 mb-6 border border-slate-800 flex items-center justify-center shadow-inner">
               <span className="text-6xl font-black text-emerald-400">{numpadValue || '0'}</span>
            </div>

            <div className="grid grid-cols-3 gap-4 mb-8">
              {[7, 8, 9, 4, 5, 6, 1, 2, 3].map(num => (
                <button
                  key={num}
                  onClick={() => setNumpadValue(prev => (prev === '0' ? String(num) : prev + num).slice(0, 4))}
                  className="bg-slate-800 hover:bg-slate-700 text-white text-3xl font-black py-6 rounded-2xl active:scale-95 transition-all shadow-md"
                >
                  {num}
                </button>
              ))}
              <button
                onClick={() => setNumpadValue('0')}
                className="bg-slate-800/50 hover:bg-rose-500/20 text-rose-500 text-lg font-black py-6 rounded-2xl active:scale-95 transition-all shadow-md uppercase"
              >
                Borrar
              </button>
              <button
                onClick={() => setNumpadValue(prev => (prev === '0' ? '0' : prev + '0').slice(0, 4))}
                className="bg-slate-800 hover:bg-slate-700 text-white text-3xl font-black py-6 rounded-2xl active:scale-95 transition-all shadow-md"
              >
                0
              </button>
              <button
                onClick={() => setNumpadValue(prev => prev.slice(0, -1) || '0')}
                className="bg-slate-800 hover:bg-slate-700 text-slate-400 flex flex-col items-center justify-center text-xl font-black py-6 rounded-2xl active:scale-95 transition-all shadow-md"
              >
                <Minus className="w-8 h-8" />
              </button>
            </div>

            <div className="flex gap-4">
              <button
                disabled={isProcessing}
                onClick={() => setShowNumpad(null)}
                className="flex-1 bg-slate-800 text-white font-black uppercase py-5 rounded-2xl hover:bg-slate-700 active:scale-95 transition-all"
              >
                Cancelar
              </button>
              <button
                disabled={isProcessing}
                onClick={() => {
                   const val = parseInt(numpadValue || '0');
                   if (val >= 0) {
                      handleUpdateQuantity(showNumpad.orderId, showNumpad.itemId, val);
                      setShowNumpad(null);
                   }
                }}
                className="flex-1 bg-emerald-600 text-white font-black uppercase py-5 rounded-2xl hover:bg-emerald-500 active:scale-95 shadow-lg shadow-emerald-500/20 disabled:opacity-30 transition-all"
              >
                Guardar
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

'use client';
import { useState, useEffect, useRef } from 'react';
import { useRouter } from 'next/navigation';
import { Search, Plus, Minus, Trash2, ShoppingCart, CreditCard, Banknote, Tag, Wifi, WifiOff, CloudSync, ArrowRightLeft, AlertCircle, Utensils } from 'lucide-react';
import { useOfflineStore } from '@/store/useOfflineStore';
import { formatCurrency, parseCurrency } from '@/utils/formatters';

interface Product {
  id: string;
  name: string;
  barcode: string | null;
  price: number;
  stock: number;
  sellByWeight?: boolean;
  unit?: string;
}

interface CartItem {
  product: Product;
  quantity: number;
}

export default function PosPage() {
  const router = useRouter();
  const [allProducts, setAllProducts] = useState<Product[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [posState, setPosState] = useState<'billing' | 'payment'>('billing');
  const [completedSale, setCompletedSale] = useState<any>(null);
  const [paymentMethod, setPaymentMethod] = useState<'efectivo' | 'credito'>('efectivo');
  const [customerName, setCustomerName] = useState('');
  const [selectedCustomerId, setSelectedCustomerId] = useState('');
  const [isNewCustomer, setIsNewCustomer] = useState(false);
  const [newCustomerPhone, setNewCustomerPhone] = useState('');
  const [customers, setCustomers] = useState<any[]>([]);
  const [activeTab, setActiveTab] = useState<'products' | 'cart'>('products');
  const [isProcessing, setIsProcessing] = useState(false);
  const [lastCheckoutTime, setLastCheckoutTime] = useState(0); 
  const [selectedSuggestionIndex, setSelectedSuggestionIndex] = useState(-1);
  const [userName, setUserName] = useState('Usuario');
  const [userRole, setUserRole] = useState('CASHIER');
  const [hasOpenClosure, setHasOpenClosure] = useState<boolean | null>(null);
  const [tenantModules, setTenantModules] = useState<string[]>([]);
  
  const offlineStore = useOfflineStore();
  const [cashReceived, setCashReceived] = useState<string>('');
  const [showChangeModal, setShowChangeModal] = useState(false);
  const [selectedCartIndex, setSelectedCartIndex] = useState(0);
  // Store info state (Dynamic from DB)
  const [tenantData, setTenantData] = useState({
    name: 'TIENDA LAS MARGARITAS',
    phone: '+573207095554',
    location: 'Don Matías - Antioquia',
    rutNit: '',
    ticketPaperSize: '58mm',
    ticketAutoPrint: false,
    ticketHeaderMessage: '',
    ticketFooterMessage: ''
  });
  
  // Reference for scanner focus
  const searchInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    // 1. Carga inmediata desde el caché (Instantánea)
    if (offlineStore.products.length > 0) setAllProducts(offlineStore.products);
    if (offlineStore.customers.length > 0) setCustomers(offlineStore.customers);

    // 2. Lógica de Sincronización Inteligente
    const lastSync = offlineStore.lastSyncTime || 0;
    const oneHour = 60 * 60 * 1000;
    const shouldSync = Date.now() - lastSync > oneHour;

    if (offlineStore.isOnline) {
      fetchTenantData();
      checkClosureStatus();
      if (shouldSync || offlineStore.products.length === 0) {
        fetchAllData();
      }
    }
    
    // Listener para refresco manual desde el Header
    const handleForceSync = () => fetchAllData();
    window.addEventListener('force-sync', handleForceSync);

    const focusTimer = setTimeout(() => {
      searchInputRef.current?.focus();
    }, 100);

    // Identity update
    const savedName = localStorage.getItem('user_name');
    const savedRole = localStorage.getItem('user_role');
    if (savedName) setUserName(savedName);
    if (savedRole) setUserRole(savedRole);

    return () => window.removeEventListener('force-sync', handleForceSync);
  }, []);

  useEffect(() => {
    const handleGlobalKeyDown = (e: KeyboardEvent) => {
      // Evitar atajos si se está escribiendo en un input
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) {
        if (e.key === 'Escape') searchInputRef.current?.focus();
        return;
      }

      if (cart.length === 0) return;

      const currentIndex = selectedCartIndex;
      const item = cart[currentIndex];

      if (!item) {
        if (cart.length > 0) setSelectedCartIndex(0);
        return;
      }

      // Atajos de Cantidad (+ / -)
      if (e.key === '+' || e.key === 'Add') {
        e.preventDefault();
        const increment = item.product.sellByWeight ? 0.1 : 1;
        updateQuantity(currentIndex, item.quantity + increment);
      } else if (e.key === '-' || e.key === 'Subtract') {
        e.preventDefault();
        const decrement = item.product.sellByWeight ? 0.1 : 1;
        updateQuantity(currentIndex, item.quantity - decrement);
      }

      // Eliminar Item (Suprimir)
      if (e.key === 'Delete' || e.key === 'Backspace') {
        e.preventDefault();
        removeFromCart(currentIndex);
      }

      // Navegar entre items (Flechas)
      if (e.key === 'ArrowUp') {
        e.preventDefault();
        setSelectedCartIndex(Math.max(0, currentIndex - 1));
      } else if (e.key === 'ArrowDown') {
        e.preventDefault();
        setSelectedCartIndex(Math.min(cart.length - 1, currentIndex + 1));
      }
      
      // Ir a Pago (Enter)
      if (e.key === 'Enter' && cart.length > 0 && posState === 'billing') {
        const target = e.target as HTMLElement;
        // Solo ir a pago si NO está en el buscador con texto (para no interferir con añadir productos)
        if (target === searchInputRef.current && searchTerm.trim() !== '') return;
        
        e.preventDefault();
        setPosState('payment');
      }
    };

    window.addEventListener('keydown', handleGlobalKeyDown);
    return () => window.removeEventListener('keydown', handleGlobalKeyDown);
  }, [cart, selectedCartIndex, posState]);

  const fetchAllData = async () => {
    await Promise.all([
      fetchProducts(),
      fetchCustomers()
    ]);
    offlineStore.setLastSyncTime(Date.now());
  };

  const fetchTenantData = async () => {
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/tenants/me`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      if (res.ok) {
        const data = await res.json();
        setTenantData({
          name: data.name,
          phone: data.phone || '+573207095554',
          location: data.location || 'Don Matías - Antioquia',
          rutNit: data.rutNit || '',
          ticketPaperSize: data.ticketPaperSize || '58mm',
          ticketAutoPrint: data.ticketAutoPrint || false,
          ticketHeaderMessage: data.ticketHeaderMessage || '',
          ticketFooterMessage: data.ticketFooterMessage || '',
        });
      }
    } catch (error) {
      console.error("Error fetching tenant data", error);
    }
  };

  const checkClosureStatus = async () => {
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/closure/status`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      if (res.ok) {
        const data = await res.json();
        setHasOpenClosure(!!data?.closure);
      } else {
        setHasOpenClosure(false);
      }
    } catch (error) {
      console.error("Error checking closure status", error);
      setHasOpenClosure(true); // Permitir acceso en caso de error de red
    }
  };

  const fetchProducts = async () => {
    if (!offlineStore.isOnline) {
      setAllProducts(offlineStore.products);
      return;
    }
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/products`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      if (res.ok) {
        const data = await res.json();
        setAllProducts(data);
        offlineStore.setCache({ products: data });
      } else {
        setAllProducts(offlineStore.products);
      }
    } catch (error) {
      console.error("Error fetching products", error);
      setAllProducts(offlineStore.products);
    }
  };

  const fetchCustomers = async () => {
    if (!offlineStore.isOnline) {
      setCustomers(offlineStore.customers);
      return;
    }
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/customers`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      if (res.ok) {
        const data = await res.json();
        setCustomers(data);
        offlineStore.setCache({ customers: data });
      } else {
        setCustomers(offlineStore.customers);
      }
    } catch (error) {
      console.error("Error fetching customers", error);
      setCustomers(offlineStore.customers);
    }
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.product.id === product.id);
      if (existing) {
        return prev.map(item => 
          item.product.id === product.id 
            ? { ...item, quantity: item.quantity + 1 } 
            : item
        );
      }
      return [{ product, quantity: 1 }, ...prev];
    });
    setSelectedCartIndex(0); // Enfocar el nuevo item o el actualizado
    setSearchTerm(''); // Clear scanner input
    
    // Foco Inteligente: Si es fruver, saltar al cuadro de peso
    if (product.sellByWeight) {
      setTimeout(() => {
        const input = document.getElementById(`cart-item-input-0`) as HTMLInputElement;
        input?.focus();
        input?.select();
      }, 50);
    } else {
      searchInputRef.current?.focus();
    }
  };

  const handleScannerInput = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'ArrowDown') {
      e.preventDefault();
      setSelectedSuggestionIndex(prev => 
        prev < filteredSuggestions.length - 1 ? prev + 1 : prev
      );
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      setSelectedSuggestionIndex(prev => prev > 0 ? prev - 1 : 0);
    } else if (e.key === 'Tab') {
      if (filteredSuggestions.length > 0) {
        e.preventDefault();
        setSelectedSuggestionIndex(0);
      }
    } else if (e.key === 'Enter') {
      if (selectedSuggestionIndex >= 0 && filteredSuggestions[selectedSuggestionIndex]) {
        e.preventDefault();
        e.stopPropagation();
        addToCart(filteredSuggestions[selectedSuggestionIndex]);
        setSelectedSuggestionIndex(-1);
      } else if (searchTerm.trim() !== '') {
        e.preventDefault();
        e.stopPropagation();
        
        const term = searchTerm.toLowerCase().trim();
        // Solo auto-agregar si el código de barras coincide exactamente al 100%
        const found = allProducts.find(p => 
          (p.barcode && p.barcode.toLowerCase() === term)
        );
        
        if (found) {
          addToCart(found);
        } else {
          // Si no es un código exacto, no agregamos "basura". 
          // El usuario puede elegir de la lista de sugerencias que se muestra abajo.
          console.log('No barcode match for:', term);
        }
      } else if (cart.length > 0) {
        e.preventDefault();
        e.stopPropagation();
        handleCheckout();
      }
    }
  };

  const updateQuantity = (index: number, newQty: number) => {
    // Ya no borramos automáticamente al llegar a <= 0 para evitar errores de teclado
    setCart(prev => prev.map((item, i) => i === index ? { ...item, quantity: newQty } : item));
  };

  const updatePrice = (productId: string, newPrice: string) => {
    // Permitir borrar completamente el campo (valor vacío)
    if (newPrice === '') {
      setCart(prev => prev.map(item => {
        if (item.product.id === productId) {
          return { ...item, product: { ...item.product, price: 0 } };
        }
        return item;
      }));
      return;
    }
    const price = parseCurrency(newPrice);
    
    setCart(prev => prev.map(item => {
      if (item.product.id === productId) {
        return { 
          ...item, 
          product: { ...item.product, price } 
        };
      }
      return item;
    }));
  };

  const removeFromCart = (index: number) => {
    setCart(prev => {
      const newCart = prev.filter((_, i) => i !== index);
      if (newCart.length === 0) {
        setTimeout(() => searchInputRef.current?.focus(), 50);
      } else if (selectedCartIndex >= newCart.length) {
        setSelectedCartIndex(newCart.length - 1);
      }
      return newCart;
    });
  };

  const calculateTotal = () => {
    return cart.reduce((total, item) => total + (item.product.price * item.quantity), 0);
  };

  const calculateRoundedTotal = () => {
    const rawTotal = calculateTotal();
    // Redondear ARRIBA al múltiplo de 50 más cercano
    return Math.ceil(rawTotal / 50) * 50;
  };

  const calculateRoundingAdjustment = () => {
    return calculateRoundedTotal() - calculateTotal();
  };

  const handleCheckout = () => {
    if (cart.length === 0) return;
    setPaymentMethod('efectivo'); 
    setCustomerName('');
    setNewCustomerPhone('');
    setIsNewCustomer(false);
    setSelectedCustomerId('');
    setPosState('payment');
    setCashReceived('');
    setLastCheckoutTime(Date.now()); // Cooldown start
    searchInputRef.current?.blur();
    setTimeout(() => document.getElementById('cash-received-input')?.focus(), 200);
  };

  const processSale = async () => {
    if (cart.length === 0 || isProcessing) return;
    setIsProcessing(true);
    let finalCustomerId = selectedCustomerId;
    let finalCustomerName = customerName || (selectedCustomerId ? customers.find(c => c.id === selectedCustomerId)?.name : undefined);

    const rawTotal = calculateTotal();
    const roundedTotal = calculateRoundedTotal();
    const adjustment = calculateRoundingAdjustment();

    const saleItems = cart.map(i => ({
      productId: i.product.id,
      productName: i.product.name,
      quantity: i.quantity,
      unitPrice: i.product.price,
      subtotal: i.product.price * i.quantity
    }));

    // Si hay ajuste, inyectarlo como un item virtual para que cuadre la contabilidad
    if (adjustment > 0) {
      saleItems.push({
        productId: 'rounding-adjustment',
        productName: 'Ajuste por Redondeo',
        quantity: 1,
        unitPrice: adjustment,
        subtotal: adjustment
      } as any);
    }

    const payload = {
      totalAmount: roundedTotal,
      paymentMethod: paymentMethod,
      customerName: paymentMethod === 'credito' ? finalCustomerName : undefined,
      customerId: (paymentMethod === 'credito' && finalCustomerId) ? finalCustomerId : undefined,
      items: saleItems
    };

    try {
      const token = localStorage.getItem('access_token');
      
      // Si es un cliente nuevo, lo creamos primero
      if (paymentMethod === 'credito' && isNewCustomer && customerName) {
        if (offlineStore.isOnline) {
          const custRes = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/customers`, {
            method: 'POST',
            headers: { 
              'Content-Type': 'application/json',
              Authorization: `Bearer ${token}` 
            },
            body: JSON.stringify({
              name: customerName,
              phone: newCustomerPhone,
              isCreditActive: true
            })
          });
          if (custRes.ok) {
            const newCust = await custRes.json();
            payload.customerId = newCust.id;
            payload.customerName = newCust.name;
          }
        } else {
          // OFFLINE - Creación de cliente temporal
          const uuid = crypto.randomUUID();
          const tempCustId = `temp-cust-${uuid}`;
          const newTempCust = {
            id: tempCustId,
            localId: tempCustId,
            name: customerName,
            phone: newCustomerPhone,
            totalDebt: calculateTotal(),
            pendingInvoices: 1
          };
          offlineStore.addPendingCustomer(newTempCust);
          payload.customerId = tempCustId;
          payload.customerName = customerName;
        }
      }

      if (offlineStore.isOnline) {
        const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales`, {
          method: 'POST',
          headers: { 
             'Content-Type': 'application/json',
             Authorization: `Bearer ${token}` 
          },
          body: JSON.stringify(payload)
        });
        if(res.ok) {
          const savedSale = await res.json();
          const saleWithItems = { 
            ...savedSale, 
            items: saleItems, // Usar saleItems que ya incluye el ajuste
            customerName: paymentMethod === 'credito' ? finalCustomerName : undefined,
            receivedAmount: paymentMethod === 'efectivo' ? Number(cashReceived) : 0,
            changeAmount: paymentMethod === 'efectivo' ? Math.max(0, Number(cashReceived) - roundedTotal) : 0
          };
          setCompletedSale(saleWithItems);
          setCart([]);
          setPosState('billing');
          fetchProducts();

          // Auto-print will be handled by useEffect watching completedSale
        } else {
          const err = await res.json();
          alert('Error al procesar la venta: ' + (err.message || 'Error desconocido'));
        }
      } else {
        queueOfflineSale(payload);
      }
    } catch (e) { 
      console.error(e);
      queueOfflineSale(payload);
    } finally {
      setIsProcessing(false);
    }
  };

  const queueOfflineSale = (payload: any) => {
    const uuid = crypto.randomUUID();
    const offlineId = 'off-' + uuid;
    const saleToStore = { 
      ...payload, 
      id: offlineId, 
      localId: offlineId,
      timestamp: Date.now(),
      isCredit: payload.paymentMethod === 'credito',
      createdAt: new Date().toISOString(), 
      offline: true,
      receivedAmount: paymentMethod === 'efectivo' ? Number(cashReceived) : 0,
      changeAmount: paymentMethod === 'efectivo' ? Math.max(0, Number(cashReceived) - calculateTotal()) : 0
    };
    offlineStore.addPendingSale(saleToStore);
    
    // UI Feedback
    const saleWithItems = { ...saleToStore, items: [...cart] };
    setCompletedSale(saleWithItems);
    setCart([]);
    setPosState('billing');
    setIsProcessing(false);
  };

  const syncPendingSales = async () => {
    const items = offlineStore.pendingSales;
    if (items.length === 0) return;

    const token = localStorage.getItem('access_token');

    for (const sale of [...items]) {
      try {
        const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales`, {
          method: 'POST',
          headers: { 
            'Content-Type': 'application/json',
            Authorization: `Bearer ${token}` 
          },
          body: JSON.stringify(sale)
        });
        if (res.ok) {
           offlineStore.removePendingSale(sale.localId);
        }
      } catch (err) {
         console.error("Error syncing sale", sale.localId, err);
      }
    }
    fetchProducts();
  };

  // Auto-sync effect - DELEGADO AL SyncManager
  /* useEffect(() => {
    if (offlineStore.isOnline && offlineStore.pendingSales.length > 0) {
      syncPendingSales();
    }
  }, [offlineStore.isOnline]); */

  const handlePrintAndReset = () => {
    window.print();
    setCompletedSale(null);
    setShowChangeModal(false);
    setTimeout(() => searchInputRef.current?.focus(), 100);
  };

  const handlePrintWithChangeModal = () => {
    // Convertir a número por seguridad y redondear para evitar problemas de coma flotante
    const change = Math.round(Number(completedSale?.changeAmount || 0));

    if (completedSale?.paymentMethod?.toLowerCase() === 'efectivo' && change > 0) {
      setShowChangeModal(true);
      // Esperar 4 segundos antes de imprimir automáticamente
      setTimeout(() => {
        handlePrintAndReset();
      }, 1500);
    } else {
      handlePrintAndReset();
    }
  };

  // Autocaptura global para usar TODO con 'ENTER'
  useEffect(() => {
    const handleGlobalKeyDown = (e: KeyboardEvent) => {
      // Evitar conflictos si el usuario está en un input pero NO es el de búsqueda o el de nombre de cliente
      if (document.activeElement?.tagName === 'INPUT' && 
          document.activeElement !== searchInputRef.current && 
          !(posState === 'payment' && paymentMethod === 'credito') &&
          document.activeElement?.id !== 'cash-received-input') {
        return;
      }

      if (e.key === 'Enter') {
        if (completedSale) {
          e.preventDefault();
          handlePrintWithChangeModal();
        } else if (posState === 'payment' && !isProcessing) {
          // No procesar si acaba de entrar en modo pago (cooldown 800ms para evitar doble enter)
          if (Date.now() - lastCheckoutTime < 800) return; 
          
          // Si estamos en el input de efectivo, el primer Enter solo muestra el cambio (ya se muestra en tiempo real)
          // Pero si queremos ser extra seguros, podemos pedir un segundo Enter.
          // Por ahora, permitimos Enter pero aseguramos que el usuario sepa que CONFIRMA.
          
          e.preventDefault();
          processSale();
        }
      } else if (e.key === 'Escape') {
        if (completedSale) {
          setCompletedSale(null);
          setTimeout(() => searchInputRef.current?.focus(), 100);
        } else if (posState === 'payment') {
          setPosState('billing');
          setTimeout(() => searchInputRef.current?.focus(), 100);
        }
      } else if (posState === 'payment') {
        // Atajos en modo de pago: Solo si NO estamos escribiendo en un input
        if (document.activeElement?.tagName === 'INPUT') return;

        if (e.key === '1' || e.key === 'ArrowLeft' || e.key === 'ArrowUp') {
          setPaymentMethod('efectivo');
          setTimeout(() => document.getElementById('cash-received-input')?.focus(), 100);
        }
        if (e.key === '2' || e.key === 'ArrowRight' || e.key === 'ArrowDown') setPaymentMethod('credito');
      }
    };
    window.addEventListener('keydown', handleGlobalKeyDown);
    return () => window.removeEventListener('keydown', handleGlobalKeyDown);
  }, [completedSale, posState, isProcessing, cart, paymentMethod, cashReceived, lastCheckoutTime, customerName, selectedCustomerId, isNewCustomer]);


  // Efecto para auto-impresión supervisada por el modal de cambio
  useEffect(() => {
    if (completedSale && tenantData.ticketAutoPrint && !showChangeModal) {
      // Pequeño delay para que el modal de ticket (el primero) logre renderizar sus datos
      const timer = setTimeout(() => {
        handlePrintWithChangeModal();
      }, 600);
      return () => clearTimeout(timer);
    }
  }, [completedSale, tenantData.ticketAutoPrint]);

  // Sugerencias visuales robustas
  const filteredSuggestions = searchTerm.length > 1 
    ? allProducts.filter(p => {
        const term = searchTerm.toLowerCase().trim();
        const nameMatch = p.name.toLowerCase().includes(term);
        const barcodeMatch = p.barcode && p.barcode.toLowerCase().includes(term);
        return nameMatch || barcodeMatch;
      })
    : [];

  // Bloqueo de Caja Cerrada
  if (hasOpenClosure === false && offlineStore.isOnline) {
    return (
      <div className="flex flex-col items-center justify-center h-[calc(100vh-4rem)] bg-slate-950 p-8 text-center">
        <div className="bg-slate-900 border border-slate-800 rounded-[3rem] p-12 shadow-2xl max-w-lg space-y-8 animate-in zoom-in-95 duration-500">
          <div className="bg-amber-500/10 w-24 h-24 rounded-full flex items-center justify-center mx-auto">
            <AlertCircle className="w-12 h-12 text-amber-500" />
          </div>
          <div>
            <h2 className="text-3xl font-black text-white mb-2 uppercase tracking-tighter italic">Caja Cerrada</h2>
            <p className="text-slate-400 font-medium">No puede realizar ventas sin antes haber realizado la apertura de caja.</p>
          </div>
          <button
            onClick={() => router.push('/dashboard/closure')}
            className="w-full bg-blue-600 hover:bg-blue-500 text-white py-5 rounded-3xl font-black text-xl shadow-xl shadow-blue-900/30 active:scale-95 transition-all"
          >
            Ir a Apertura de Caja
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-[calc(100vh-4rem)] flex-col md:flex-row overflow-hidden bg-gray-50 dark:bg-[#0f172a] transition-colors rounded-3xl shadow-sm border border-gray-100 dark:border-slate-800">
      
      {/* Mobile Tabs Switcher */}
      <div className="md:hidden flex border-b border-gray-200 dark:border-slate-800 bg-white dark:bg-slate-900 sticky top-0 z-20">
        <button 
          onClick={() => setActiveTab('products')}
          className={`flex-1 py-4 text-sm font-black transition-all ${activeTab === 'products' ? 'text-blue-600 border-b-2 border-blue-600 bg-blue-50/30' : 'text-slate-500'}`}
        >
          PRODUCTOS
        </button>
        <button 
          onClick={() => setActiveTab('cart')}
          className={`flex-1 py-4 text-sm font-black transition-all relative ${activeTab === 'cart' ? 'text-blue-600 border-b-2 border-blue-600 bg-blue-50/30' : 'text-slate-500'}`}
        >
          CARRITO
          {cart.length > 0 && (
            <span className="absolute top-3 right-8 bg-rose-500 text-white text-[10px] w-4 h-4 rounded-full flex items-center justify-center animate-bounce">
              {cart.length}
            </span>
          )}
        </button>
      </div>

      {/* Lado Izquierdo: Productos y Escáner (65%) */}
      <div className={`flex-1 flex flex-col p-4 md:p-6 overflow-hidden ${activeTab !== 'products' ? 'hidden md:flex' : 'flex'}`}>
        <div className="flex justify-between items-center mb-4">
          <div>
            <h2 className="text-2xl font-bold text-gray-900 dark:text-white">Caja Registradora</h2>
            <p className="text-sm font-semibold text-gray-500 dark:text-gray-400 mt-0.5">{tenantData.name} • {tenantData.location}</p>
          </div>
          <div className="flex items-center gap-3">
            {offlineStore.pendingSales.length > 0 && (
              <div className="flex items-center text-xs font-bold text-blue-600 dark:text-blue-400 bg-blue-50 dark:bg-blue-900/20 px-3 py-1.5 rounded-full animate-pulse">
                <CloudSync className="w-4 h-4 mr-1.5" />
                {offlineStore.pendingSales.length} {offlineStore.pendingSales.length === 1 ? 'venta pendiente' : 'ventas pendientes'}
              </div>
            )}
          </div>
        </div>
        
        {/* Barra Búsqueda / Escáner */}
        <div className="relative mb-6">
          <div className="pointer-events-none absolute inset-y-0 left-0 flex items-center pl-4">
            <Search className="h-5 w-5 text-gray-400" />
          </div>
          <input
            ref={searchInputRef}
            type="text"
            className="block w-full rounded-2xl border-0 py-4 pl-12 pr-4 text-gray-900 shadow-sm ring-1 ring-inset ring-gray-200 dark:bg-slate-900 dark:text-white dark:ring-slate-800 placeholder:text-gray-400 focus:ring-2 focus:ring-inset focus:ring-blue-600 sm:text-lg sm:leading-6 transition-all"
            placeholder="Escanea el código de barras o busca por nombre..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value.replace(/[^a-zA-Z0-9\s]/g, ''))}
            onKeyDown={handleScannerInput}
            autoFocus
          />
          {searchTerm && (
            <div className="absolute right-4 top-4 text-xs font-semibold text-gray-400 bg-gray-100 dark:bg-slate-800 px-2 py-1 rounded">ENTER para agregar</div>
          )}
        </div>

        {/* Resultados Sugeridos (Solo se muestran si escriben manual y no escaner instantáneo) */}
        {searchTerm.length > 1 && (
          <div className="flex-1 overflow-y-auto mb-4 bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-gray-200 dark:border-slate-800 p-2">
            <h3 className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-2 px-3 pt-2">Resultados de búsqueda</h3>
            {filteredSuggestions.length === 0 ? (
              <p className="p-4 text-sm text-gray-500 dark:text-gray-400">No se encontraron productos.</p>
            ) : (
              <ul className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-2">
                {filteredSuggestions.map((product, index) => (
                  <li 
                    key={product.id} 
                    onClick={() => addToCart(product)}
                    className={`flex justify-between items-center p-3 rounded-xl cursor-pointer border transition-colors ${
                      selectedSuggestionIndex === index 
                        ? 'bg-blue-600 text-white border-blue-500 shadow-md ring-2 ring-blue-500/20 scale-[1.02]' 
                        : 'bg-white dark:bg-slate-900 border-transparent hover:bg-blue-50 dark:hover:bg-blue-900/20 hover:border-blue-100 dark:hover:border-blue-800/50'
                    }`}
                  >
                    <div className="overflow-hidden">
                      <p className={`text-sm font-bold truncate ${selectedSuggestionIndex === index ? 'text-white' : 'text-gray-900 dark:text-white'}`}>{product.name}</p>
                      <p className={`text-xs mt-0.5 truncate ${selectedSuggestionIndex === index ? 'text-blue-100' : 'text-gray-500 dark:text-gray-400'}`}>{product.barcode || 'Sin Código'}</p>
                    </div>
                    <p className={`text-sm font-semibold whitespace-nowrap ml-2 ${selectedSuggestionIndex === index ? 'text-white' : 'text-green-600 dark:text-green-400'}`}>
                      ${Math.round(product.price).toLocaleString('es-CO', { maximumFractionDigits: 0 })}
                    </p>
                  </li>
                ))}
              </ul>
            )}
          </div>
        )}

        {/* Botones de Categorías Rápidas (Placeholder) */}
        {!searchTerm && (
            <div className="flex-1 overflow-y-auto bg-gray-100/50 dark:bg-slate-800/30 rounded-2xl border border-gray-200 border-dashed dark:border-slate-800 p-8 flex flex-col items-center justify-center text-center">
              <div className="bg-white dark:bg-slate-800 p-4 rounded-full shadow-sm mb-4">
                <Tag className="h-8 w-8 text-blue-500" />
              </div>
              <h3 className="text-xl font-bold text-gray-900 dark:text-white">¡Bienvenido, {userName}!</h3>
              <p className="text-sm text-blue-600 dark:text-blue-400 font-bold uppercase tracking-widest mt-1">
                Perfil: {userRole === 'OWNER' ? 'Dueño / Administrador' : 'Vendedor / Cajero'}
              </p>
              <div className="mt-4 px-4 py-2 bg-white/50 dark:bg-slate-900/50 rounded-xl border border-gray-200 dark:border-slate-700">
                <p className="text-sm font-black text-gray-700 dark:text-gray-300">{tenantData.name}</p>
                <p className="text-xs font-semibold text-gray-500">{tenantData.location}</p>
              </div>
              <p className="text-sm text-gray-500 dark:text-gray-400 mt-4 max-w-sm">
                El teclado es tu mejor amigo. Escanea un producto, o si la barra está vacía, oprime <strong>ENTER</strong> para ir a cobrar directamente.
              </p>
            </div>
         )}
      </div>

      {/* Lado Derecho: Carrito de Compras (35%) */}
      <div className={`w-full md:w-[400px] lg:w-[450px] bg-white dark:bg-slate-900 border-l border-gray-200 dark:border-slate-800 flex flex-col shadow-xl z-10 transition-all ${activeTab !== 'cart' ? 'hidden md:flex' : 'flex'}`}>
        {/* Cabecera dinámica del Sidebar */}
        <div className={`p-5 border-b border-gray-200 dark:border-slate-800 transition-colors ${posState === 'payment' ? 'bg-blue-600 dark:bg-blue-600' : 'bg-gray-50/50 dark:bg-slate-800/50'}`}>
          <div className="flex justify-between items-center">
            <h2 className={`text-lg font-bold flex items-center ${posState === 'payment' ? 'text-white' : 'text-gray-900 dark:text-white'}`}>
              <ShoppingCart className="w-5 h-5 mr-2" />
              {posState === 'billing' ? 'Carrito de Compras' : 'PASO 2: SELECCIONE PAGO'}
            </h2>
            <span className={`${posState === 'payment' ? 'bg-white/20 text-white' : 'bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-300'} text-xs font-semibold px-2.5 py-0.5 rounded-full`}>
              {cart.reduce((acc, item) => acc + item.quantity, 0)} Items
            </span>
          </div>
        </div>
        
        {/* Lista de Items O Vista de Pago */}
        <div className="flex-1 overflow-y-auto p-4 bg-gray-50 dark:bg-[#0f172a]">
          {posState === 'billing' ? (
            cart.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-gray-400 dark:text-slate-500 space-y-4">
                <ShoppingCart className="w-12 h-12 opacity-20" />
                <p className="text-sm font-medium">El carrito está vacío</p>
              </div>
            ) : (
              <div className="space-y-3">
                {cart.map((item, idx) => (
                  <div 
                    key={item.product.id} 
                    onClick={() => setSelectedCartIndex(idx)}
                    className={`p-3 rounded-xl shadow-sm border flex justify-between items-center transition-all cursor-pointer ${
                      selectedCartIndex === idx 
                        ? 'bg-blue-50 dark:bg-blue-900/20 border-blue-200 dark:border-blue-800 ring-2 ring-blue-500/10' 
                        : 'bg-white dark:bg-slate-800 border-gray-100 dark:border-slate-700'
                    }`}
                  >
                    <div className="flex-1 min-w-0 pr-2">
                      <h4 className={`text-sm font-bold truncate ${selectedCartIndex === idx ? 'text-blue-700 dark:text-blue-400' : 'text-gray-900 dark:text-white'}`} title={item.product.name}>
                        {item.product.name}
                      </h4>
                      <div className="relative mt-1 group">
                        <span className="absolute left-0 top-0 text-[10px] text-gray-400 group-focus-within:text-blue-500 transition-colors font-bold">$</span>
                        <input 
                          type="number"
                          title="Cambiar precio unitario"
                          className="w-full pl-3 bg-transparent text-sm font-black text-green-600 dark:text-green-400 focus:outline-none focus:ring-0 border-none p-0 [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none"
                          value={item.product.price === 0 ? '' : Math.round(item.product.price)}
                          onChange={(e) => updatePrice(item.product.id, e.target.value)}
                          onFocus={(e) => e.target.select()}
                        />
                      </div>
                    </div>
                    
                    <div className="flex items-center gap-3">
                      <div className="flex items-center bg-gray-100 dark:bg-slate-900 rounded-xl p-1 border border-gray-200 dark:border-slate-700">
                        <button onClick={(e) => { e.stopPropagation(); updateQuantity(idx, item.quantity - 1); }} className="p-3 text-gray-500 hover:text-gray-900 dark:text-gray-400 dark:hover:text-white hover:bg-gray-200 dark:hover:bg-slate-700 rounded-xl transition-all active:scale-90">
                          <Minus className="w-5 h-5" />
                        </button>
                        <div className="relative flex items-center">
                          {item.product.sellByWeight && (
                            <span className="absolute -top-3 left-1/2 -translate-x-1/2 text-[8px] font-black text-blue-600 dark:text-blue-400 uppercase tracking-tighter">Peso</span>
                          )}
                          <input 
                            id={`cart-item-input-${idx}`}
                            type="number"
                            step="any"
                            className="w-16 text-center text-base font-black text-gray-900 dark:text-white bg-transparent focus:outline-none focus:ring-2 focus:ring-blue-500 rounded-md p-1 [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none"
                            placeholder="0.00"
                            value={item.quantity || ''}
                            onClick={(e) => e.stopPropagation()}
                            onKeyDown={(e) => {
                              e.stopPropagation();
                              if (e.key === 'Enter') {
                                e.preventDefault();
                                searchInputRef.current?.focus();
                              }
                              if (e.key === 'Delete' || e.key === 'Backspace') {
                                // No dejamos que el evento llegue al listener global que borra el item
                                e.stopPropagation();
                                if (e.key === 'Delete') updateQuantity(idx, 0);
                              }
                            }}
                            onChange={(e) => {
                              const val = e.target.value;
                              const product = item.product;
                              const parsed = product.sellByWeight ? parseFloat(val) : parseInt(val);
                              updateQuantity(idx, isNaN(parsed) ? 0 : parsed);
                            }}
                            onFocus={(e) => e.target.select()}
                          />
                        </div>
                        <button onClick={(e) => { e.stopPropagation(); updateQuantity(idx, item.quantity + (item.product.sellByWeight ? 0.1 : 1)); }} className="p-3 text-gray-500 hover:text-gray-900 dark:text-gray-400 dark:hover:text-white hover:bg-gray-200 dark:hover:bg-slate-700 rounded-xl transition-all active:scale-90">
                          <Plus className="w-5 h-5" />
                        </button>
                      </div>
                      <div className="flex flex-col items-center">
                        <button onClick={(e) => { e.stopPropagation(); removeFromCart(idx); }} className="p-2 text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-colors">
                          <Trash2 className="w-4 h-4" />
                        </button>
                        {item.product.sellByWeight && (
                          <span className="text-[10px] font-black text-gray-400 uppercase">{item.product.unit}</span>
                        )}
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )
          ) : (
            /* Vista de Selección de Pago */
            <div className="h-full flex flex-col items-center justify-start py-8 p-2 animate-in slide-in-from-right-4 duration-300">
              <div className="w-20 h-20 bg-blue-100 dark:bg-blue-900/30 rounded-3xl flex items-center justify-center mb-4 shadow-inner">
                <Banknote className="w-10 h-10 text-blue-600 dark:text-blue-400" />
              </div>
              <p className="text-xs font-bold text-blue-600 dark:text-blue-400 uppercase tracking-[0.2em] mb-2">Paso Final</p>
              <h3 className="text-xl font-black text-gray-900 dark:text-white mb-8 text-center">¿Cómo paga el cliente?</h3>
              
              <div className="grid grid-cols-1 gap-4 w-full px-4 mb-2">
                {/* Opción de Crédito Arriba */}
                <button 
                  onClick={() => setPaymentMethod('credito')}
                  tabIndex={0}
                  onKeyDown={(e) => {
                    if (e.key === 'ArrowDown' || e.key === 'ArrowRight') {
                      e.preventDefault();
                      setPaymentMethod('efectivo');
                      setTimeout(() => document.getElementById('cash-received-input')?.focus(), 100);
                    }
                  }}
                  className={`flex items-center gap-4 p-5 border-2 rounded-3xl font-black transition-all outline-none focus:ring-4 focus:ring-orange-500/40 ${paymentMethod === 'credito' ? 'border-orange-600 bg-orange-50 text-orange-700 dark:bg-orange-900/20 dark:border-orange-500 dark:text-orange-400 ring-4 ring-orange-500/10' : 'border-gray-200 text-gray-500 dark:border-slate-800 dark:text-gray-400'}`}
                >
