              </p>
            </div>
            <p className="mt-8 text-blue-100 text-sm font-bold animate-pulse flex items-center justify-center gap-2">
              <div className="w-2 h-2 bg-blue-200 rounded-full animate-ping" />
              Imprimiendo ticket automáticamente...
            </p>
          </div>
        </div>
      )}
    </div>
  );
}

