'use client';
import { useState, useEffect } from 'react';
import { User, Shield, Mail, Key, Save } from 'lucide-react';

export default function ProfilePage() {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [role, setRole] = useState('');

  useEffect(() => {
    setName(localStorage.getItem('user_name') || '');
    setEmail(localStorage.getItem('user_email') || '');
    setRole(localStorage.getItem('user_role') || '');
  }, []);

  const handleUpdateProfile = (e: React.FormEvent) => {
    e.preventDefault();
    alert('Funcionalidad en desarrollo: Tu perfil ha sido guardado localmente en esta demo.');
    localStorage.setItem('user_name', name);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-in slide-in-from-bottom-4 duration-500">
      <div>
        <h2 className="text-3xl font-black text-slate-900 dark:text-white">Mi Perfil</h2>
        <p className="text-slate-500 dark:text-slate-400">Gestiona tu información personal y seguridad.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
        <div className="col-span-2 space-y-6">
          <form onSubmit={handleUpdateProfile} className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm space-y-6">
            <div className="flex items-center gap-4 mb-4">
              <div className="p-4 bg-blue-100 dark:bg-blue-900/30 rounded-2xl text-blue-600">
                <User className="w-8 h-8" />
              </div>
              <div>
                <p className="font-bold text-slate-900 dark:text-white text-lg">{name}</p>
                <p className="text-xs font-bold uppercase tracking-widest text-blue-600">Configuración Personal</p>
              </div>
            </div>

            <div className="space-y-4">
              <div>
                <label className="text-xs font-bold text-slate-500 uppercase flex items-center gap-2">
                   <User className="w-3 h-3" /> Nombre Completo
                </label>
                <input 
                  className="w-full mt-1 p-4 rounded-2xl bg-slate-50 dark:bg-slate-800 border-none outline-none focus:ring-2 focus:ring-blue-500 transition-all"
                  value={name} 
                  onChange={e => setName(e.target.value)} 
                />
              </div>

              <div>
                <label className="text-xs font-bold text-slate-500 uppercase flex items-center gap-2">
                   <Mail className="w-3 h-3" /> Correo Electrónico
                </label>
                <input 
                  disabled
                  className="w-full mt-1 p-4 rounded-2xl bg-slate-100 dark:bg-slate-800/50 text-slate-400 border-none outline-none cursor-not-allowed"
                  value={email} 
                />
              </div>
            </div>

            <button type="submit" className="w-full py-4 bg-slate-900 dark:bg-blue-600 text-white rounded-2xl font-black text-sm uppercase tracking-widest hover:scale-[1.02] transition-all flex items-center justify-center gap-2">
              <Save className="w-4 h-4" /> Guardar Cambios
            </button>
          </form>

          <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm">
             <h4 className="font-bold text-slate-900 dark:text-white mb-4 flex items-center gap-2">
               <Key className="w-5 h-5 text-amber-500" /> Seguridad
             </h4>
             <button className="text-sm font-bold text-blue-600 hover:underline">Cambiar mi contraseña</button>
          </div>
        </div>

        <div className="space-y-6">
          <div className="bg-slate-900 dark:bg-blue-900/10 p-8 rounded-3xl border border-slate-800 dark:border-blue-900/30">
            <Shield className="w-12 h-12 text-blue-400 mb-4" />
            <h4 className="font-bold text-white mb-2 uppercase text-xs tracking-widest">Tu Rol en el Sistema</h4>
            <p className="text-3xl font-black text-white">{role === 'CASHIER' ? 'Cajero' : role === 'OWNER' ? 'Dueño' : role}</p>
            <p className="text-sm text-slate-400 mt-4 leading-relaxed">
              Tu rol está limitado por el administrador del negocio para garantizar la seguridad de los datos sensibles.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

'use client';
import { useState, useEffect } from 'react';
import { BarChart3, TrendingUp, Calendar, CreditCard, Banknote, Receipt, Tag, FileText, Download, ArrowUpRight } from 'lucide-react';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';
import { utils, writeFile } from 'xlsx';
import { formatCurrency as formatCurrencyUtil } from '@/utils/formatters';


interface SaleItem {
  id: string;
  productName: string;
  quantity: number;
  unitPrice: number;
  subtotal: number;
}

interface Sale {
  id: string;
  invoiceNumber?: string;
  totalAmount: number;
  paymentMethod: string;
  customerName?: string;
  userId?: string;
  sellerName?: string;
  user?: { name: string };
  createdAt: string;
  items: SaleItem[];
}

export default function ReportsPage() {
  const [sales, setSales] = useState<Sale[]>([]);
  const [loading, setLoading] = useState(true);
  const [sortConfig, setSortConfig] = useState<{ key: keyof Sale | 'user'; direction: 'asc' | 'desc' } | null>(null);

  useEffect(() => {
    fetchSales();
  }, []);

  const fetchSales = async () => {
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      if (res.ok) {
        const data = await res.json();
        setSales(data);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };
  const requestSort = (key: keyof Sale | 'user') => {
    let direction: 'asc' | 'desc' = 'asc';
    if (sortConfig && sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
  };

  const sortedSales = [...sales].sort((a, b) => {
    if (!sortConfig) return 0;
    
    let aValue: any = a[sortConfig.key as keyof Sale];
    let bValue: any = b[sortConfig.key as keyof Sale];

    if (sortConfig.key === 'user') {
      aValue = a.sellerName || a.user?.name || '';
      bValue = b.sellerName || b.user?.name || '';
    }

    if (sortConfig.key === 'paymentMethod') {
      aValue = a.paymentMethod + (a.customerName || '');
      bValue = b.paymentMethod + (b.customerName || '');
    }

    if (aValue === null || aValue === undefined) aValue = '';
    if (bValue === null || bValue === undefined) bValue = '';

    if (aValue < bValue) return sortConfig.direction === 'asc' ? -1 : 1;
    if (aValue > bValue) return sortConfig.direction === 'asc' ? 1 : -1;
    return 0;
  });

  const totalRevenue = sales.reduce((acc, sale) => acc + Number(sale.totalAmount), 0);
  const totalCredit = sales.filter(s => s.paymentMethod === 'credito').reduce((acc, sale) => acc + Number(sale.totalAmount), 0);
  const totalItemsSold = sales.reduce((acc, sale) => acc + sale.items.reduce((sum, item) => sum + item.quantity, 0), 0);

  const formatCurrency = (amount: number) => `$${formatCurrencyUtil(amount)}`;

  const exportToPDF = () => {
    const doc = new jsPDF();
    doc.setFontSize(18);
    doc.text('TIENDEO POS - REPORTE DE VENTAS', 14, 20);
    doc.setFontSize(10);
    doc.text(`Generado: ${new Date().toLocaleString('es-CO')}`, 14, 28);
    
    const tableData = sortedSales.map(sale => [
      sale.invoiceNumber || 'S/N',
      new Date(sale.createdAt).toLocaleString('es-CO'),
      sale.sellerName || sale.user?.name || 'Sistema',
      sale.paymentMethod + (sale.customerName ? ` (${sale.customerName})` : ''),
      sale.items.map(i => `${i.quantity}x ${i.productName}`).join(', '),
      `$${formatCurrencyUtil(sale.totalAmount)}`
    ]);
    
    autoTable(doc, {
      startY: 35,
      head: [['Factura #', 'Fecha', 'Vendedor', 'Método / Cliente', 'Resumen Productos', 'Total']],
      body: tableData,
      headStyles: { fillColor: [37, 99, 235] }
    });
    
    doc.save('Historial_Ventas.pdf');
  };

  const exportToExcel = () => {
    const data = sortedSales.map(sale => ({
      'Factura #': sale.invoiceNumber || 'S/N',
      Fecha: new Date(sale.createdAt).toLocaleString('es-CO'),
      Vendedor: sale.sellerName || sale.user?.name || 'Sistema',
      Metodo: sale.paymentMethod,
      Cliente: sale.customerName || 'N/A',
      Productos: sale.items.map(i => `${i.quantity}x ${i.productName}`).join(', '),
      Total: Number(sale.totalAmount)
    }));
    
    const ws = utils.json_to_sheet(data);
    const wb = utils.book_new();
    utils.book_append_sheet(wb, ws, 'Ventas');
    writeFile(wb, 'Ventas_Tiendeo.xlsx');
  };

  if (loading) return <div className="p-8 text-center text-gray-500">Cargando reportes...</div>;

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <h2 className="text-2xl font-bold leading-7 text-gray-900 dark:text-white sm:truncate sm:text-3xl sm:tracking-tight transition-colors flex items-center gap-3">
          <BarChart3 className="w-8 h-8 text-blue-600" />
          Reportes y Ventas Diarias
        </h2>
        
        <div className="flex gap-3">
          <button 
            onClick={exportToPDF}
            className="flex items-center gap-2 bg-gray-100 hover:bg-gray-200 dark:bg-slate-800/50 dark:hover:bg-slate-800 text-slate-700 dark:text-slate-200 px-4 py-2.5 rounded-xl font-bold border border-slate-200 dark:border-slate-700 transition-all active:scale-95 shadow-sm"
          >
            <FileText className="w-4 h-4 text-rose-500" />
            Ventas PDF
          </button>
          <button 
            onClick={exportToExcel}
            className="flex items-center gap-2 bg-gray-100 hover:bg-gray-200 dark:bg-slate-800/50 dark:hover:bg-slate-800 text-slate-700 dark:text-slate-200 px-4 py-2.5 rounded-xl font-bold border border-slate-200 dark:border-slate-700 transition-all active:scale-95 shadow-sm"
          >
            <Download className="w-4 h-4 text-emerald-500" />
            Ventas Excel
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 gap-5 sm:grid-cols-2 lg:grid-cols-4">
        <div className="relative overflow-hidden rounded-2xl bg-white dark:bg-slate-900 px-4 py-5 shadow-sm border border-gray-100 dark:border-slate-800 sm:px-6 transition-all hover:shadow-md">
          <dl>
            <dt>
              <div className="absolute rounded-xl bg-blue-50 dark:bg-blue-900/30 p-3">
                <TrendingUp className="h-6 w-6 text-blue-600 dark:text-blue-400" />
              </div>
              <p className="ml-16 truncate text-sm font-medium text-gray-500 dark:text-gray-400">Total Hoy</p>
            </dt>
            <dd className="ml-16 flex items-baseline pb-1 sm:pb-2">
              <p className="text-2xl font-black text-gray-900 dark:text-white">{formatCurrency(totalRevenue)}</p>
            </dd>
          </dl>
        </div>

        <div className="relative overflow-hidden rounded-2xl bg-white dark:bg-slate-900 px-4 py-5 shadow-sm border border-gray-100 dark:border-slate-800 sm:px-6 transition-all hover:shadow-md">
          <dl>
            <dt>
              <div className="absolute rounded-xl bg-orange-50 dark:bg-orange-900/30 p-3">
                <TrendingUp className="h-6 w-6 text-orange-600 dark:text-orange-400" />
              </div>
              <p className="ml-16 truncate text-sm font-medium text-gray-500 dark:text-gray-400">En Crédito (Deuda)</p>
            </dt>
            <dd className="ml-16 flex items-baseline pb-1 sm:pb-2">
              <p className="text-2xl font-black text-orange-600">{formatCurrency(totalCredit)}</p>
            </dd>
          </dl>
        </div>

        <div className="relative overflow-hidden rounded-2xl bg-white dark:bg-slate-900 px-4 py-5 shadow-sm border border-gray-100 dark:border-slate-800 sm:px-6 transition-all hover:shadow-md">
          <dl>
            <dt>
              <div className="absolute rounded-xl bg-purple-50 dark:bg-purple-900/30 p-3">
                <Receipt className="h-6 w-6 text-purple-600 dark:text-purple-400" />
              </div>
              <p className="ml-16 truncate text-sm font-medium text-gray-500 dark:text-gray-400">Transacciones</p>
            </dt>
            <dd className="ml-16 flex items-baseline pb-1 sm:pb-2">
              <p className="text-2xl font-black text-gray-900 dark:text-white">{sales.length}</p>
            </dd>
          </dl>
        </div>

        <div className="relative overflow-hidden rounded-2xl bg-white dark:bg-slate-900 px-4 py-5 shadow-sm border border-gray-100 dark:border-slate-800 sm:px-6 transition-all hover:shadow-md">
          <dl>
            <dt>
              <div className="absolute rounded-xl bg-green-50 dark:bg-green-900/30 p-3">
                <Tag className="h-6 w-6 text-green-600 dark:text-green-400" />
              </div>
              <p className="ml-16 truncate text-sm font-medium text-gray-500 dark:text-gray-400">Unds. Vendidas</p>
            </dt>
            <dd className="ml-16 flex items-baseline pb-1 sm:pb-2">
              <p className="text-2xl font-black text-gray-900 dark:text-white">{totalItemsSold}</p>
            </dd>
          </dl>
        </div>
      </div>

      <h3 className="text-xl font-bold text-gray-900 dark:text-white mt-10 mb-4 flex items-center">
        <Calendar className="w-5 h-5 mr-2 text-gray-500" /> Historial de Transacciones
      </h3>
      
      <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-gray-100 dark:border-slate-800 overflow-hidden text-left">
        {sales.length === 0 ? (
          <div className="p-4 md:p-8 text-center text-gray-500 dark:text-gray-400">No hay ventas registradas todavía.</div>
        ) : (
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-200 dark:divide-slate-800">
              <thead className="bg-gray-50 dark:bg-slate-800/50">
                <tr>
                  <th 
                    className="px-6 py-4 text-xs font-black text-slate-400 uppercase tracking-widest min-w-[120px] cursor-pointer hover:bg-gray-100 dark:hover:bg-slate-800 transition-colors"
                    onClick={() => requestSort('invoiceNumber')}
                  >
                    Factura {sortConfig?.key === 'invoiceNumber' && (sortConfig.direction === 'asc' ? '↑' : '↓')}
                  </th>
                  <th 
                    className="px-6 py-4 text-xs font-black text-slate-400 uppercase tracking-widest min-w-[170px] cursor-pointer hover:bg-gray-100 dark:hover:bg-slate-800 transition-colors"
                    onClick={() => requestSort('createdAt')}
                  >
                    Fecha / Hora {sortConfig?.key === 'createdAt' && (sortConfig.direction === 'asc' ? '↑' : '↓')}
                  </th>
                  <th 
                    className="px-6 py-4 text-xs font-black text-slate-400 uppercase tracking-widest min-w-[150px] cursor-pointer hover:bg-gray-100 dark:hover:bg-slate-800 transition-colors"
                    onClick={() => requestSort('user')}
                  >
                    Vendedor {sortConfig?.key === 'user' && (sortConfig.direction === 'asc' ? '↑' : '↓')}
                  </th>
                  <th 
                    className="px-6 py-4 text-xs font-black text-slate-400 uppercase tracking-widest min-w-[180px] cursor-pointer hover:bg-gray-100 dark:hover:bg-slate-800 transition-colors"
                    onClick={() => requestSort('paymentMethod')}
                  >
                    Método / Cliente {sortConfig?.key === 'paymentMethod' && (sortConfig.direction === 'asc' ? '↑' : '↓')}
                  </th>
                  <th className="px-6 py-4 text-xs font-black text-slate-400 uppercase tracking-widest min-w-[300px]">Productos</th>
                  <th 
                    className="px-6 py-4 text-xs font-black text-slate-400 uppercase tracking-widest text-right min-w-[120px] cursor-pointer hover:bg-gray-100 dark:hover:bg-slate-800 transition-colors"
                    onClick={() => requestSort('totalAmount')}
                  >
                    Total {sortConfig?.key === 'totalAmount' && (sortConfig.direction === 'asc' ? '↑' : '↓')}
                  </th>
                </tr>
              </thead>
              <tbody className="bg-white dark:bg-slate-900 divide-y divide-gray-100 dark:divide-slate-800">
                {sortedSales.map((sale) => (
                  <tr key={sale.id} className="hover:bg-gray-50 dark:hover:bg-slate-800/50 transition-colors">
                    <td className="px-6 py-4 whitespace-nowrap text-xs font-black text-blue-600 dark:text-blue-400">
                      {sale.invoiceNumber || 'S/N'}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900 dark:text-gray-300 font-medium">
                      {new Date(sale.createdAt).toLocaleString('es-CO')}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center gap-2">
                         <div className="w-7 h-7 rounded-full bg-blue-100 dark:bg-blue-900/30 flex items-center justify-center text-[10px] font-black text-blue-600 dark:text-blue-400 uppercase">
                            {(sale.sellerName || sale.user?.name || 'S')[0]}
                         </div>
                         <span className="text-sm font-bold text-gray-700 dark:text-gray-300">
                           {sale.sellerName || sale.user?.name || <span className="text-gray-400 italic font-medium">Sistema</span>}
                         </span>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-bold ${
                        sale.paymentMethod === 'credito' 
                          ? 'bg-orange-100 text-orange-800 dark:bg-orange-900/30 dark:text-orange-400' 
                          : 'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400'
                      }`}>
                        {sale.paymentMethod === 'credito' ? <ArrowUpRight className="w-3 h-3 mr-1" /> : <Banknote className="w-3 h-3 mr-1" />}
                        {sale.paymentMethod} {sale.customerName ? `(${sale.customerName})` : ''}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-sm text-gray-500 dark:text-gray-400 min-w-[300px]">
                      {sale.items.map(i => `${i.quantity}x ${i.productName}`).join(', ')}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-black text-gray-900 dark:text-white">
                      {formatCurrency(Number(sale.totalAmount))}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

'use client';
import { useState, useEffect, use } from 'react';
import { Utensils, Search, Plus, Trash2, CreditCard, ChevronLeft, User, DollarSign, X, Minus, Printer } from 'lucide-react';
import { useRouter } from 'next/navigation';
import { formatCurrency } from '@/utils/formatters';
import { useRef } from 'react';

interface Product {
  id: string;
  name: string;
  price: number;
}

interface SaleItem {
  id: string;
  productName: string;
  quantity: number;
  unitPrice: number;
  subtotal: number;
}

interface Sale {
  id: string;
  tableName: string;
  totalAmount: number;
  status: string;
  waiter?: { name: string };
  items: SaleItem[];
}

export default function OrderPage({ params }: { params: Promise<{ id: string }> }) {
  const router = useRouter();
  const { id } = use(params);
  const [sale, setSale] = useState<Sale | null>(null);
  const [products, setProducts] = useState<Product[]>([]);
  const [search, setSearch] = useState('');
  const [isLoading, setIsLoading] = useState(true);

  // New Item selection
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [quantity, setQuantity] = useState(1);
  const [isAdding, setIsAdding] = useState(false);
  const [shouldPrintCommand, setShouldPrintCommand] = useState(false);
  const searchInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    fetchOrder();
    fetchProducts();
  }, [id]);

  const fetchOrder = async () => {
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/${id}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      if (res.ok) setSale(await res.json());
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  const fetchProducts = async () => {
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/products`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      if (res.ok) setProducts(await res.json());
    } catch (err) {
      console.error(err);
    }
  };

  const handleAddItem = async () => {
    if (!selectedProduct) return;
    setIsAdding(true);
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/restaurant/order/${id}/items`, {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}` 
        },
        body: JSON.stringify({ 
          items: [{ 
            productId: selectedProduct.id, 
            productName: selectedProduct.name,
            quantity, 
            unitPrice: selectedProduct.price 
          }] 
        })
      });

      if (res.ok) {
        setSelectedProduct(null);
        setQuantity(1);
        setSearch('');
        fetchOrder();
      }
    } catch (err) {
      console.error(err);
    } finally {
      setIsAdding(false);
    }
  };

  useEffect(() => {
    if (!selectedProduct) {
      setTimeout(() => searchInputRef.current?.focus(), 100);
    }
  }, [selectedProduct]);

  const handleRemoveItem = async (itemId: string) => {
    if (!confirm('¿Eliminar este producto de la mesa? El stock será devuelto.')) return;
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/restaurant/order/${id}/items/${itemId}`, {
        method: 'DELETE',
        headers: { Authorization: `Bearer ${token}` }
      });
      if (res.ok) fetchOrder();
    } catch (err) {
      console.error(err);
    }
  };

  const handleUpdateQuantity = async (itemId: string, newQty: number) => {
    if (newQty <= 0) {
      handleRemoveItem(itemId);
      return;
    }
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/restaurant/order/${id}/items/${itemId}`, {
        method: 'PATCH',
        headers: { 
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}` 
        },
        body: JSON.stringify({ quantity: newQty })
      });
      if (res.ok) fetchOrder();
    } catch (err) {
      console.error(err);
    }
  };

  const handleSearchKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && filteredProducts.length > 0) {
      setSelectedProduct(filteredProducts[0]);
    }
  };

  const handleCancelOrder = async () => {
    if (!confirm('¿Realmente deseas cancelar esta mesa? Los productos volverán al inventario.')) return;
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/restaurant/order/${id}`, {
        method: 'DELETE',
        headers: { Authorization: `Bearer ${token}` }
      });
      if (res.ok) router.push('/dashboard/restaurant');
    } catch (err) {
      console.error(err);
    }
  };

  const filteredProducts = products.filter(p => 
    p.name.toLowerCase().includes(search.toLowerCase())
  ).slice(0, 6);

  if (isLoading) return <div className="p-10 text-center animate-pulse text-slate-500">Cargando mesa...</div>;
  if (!sale) return <div className="p-10 text-center text-red-500">Mesa no encontrada</div>;

  return (
    <div className="flex flex-col lg:flex-row h-[calc(100vh-64px)] bg-[#0f172a] overflow-hidden">
      {/* Sidebar: Current Ticket */}
      <div className="w-full lg:w-[400px] border-r border-slate-800 flex flex-col bg-slate-900/50 backdrop-blur-md">
         <div className="p-6 border-b border-slate-800">
            <button onClick={() => router.push('/dashboard/restaurant')} className="flex items-center gap-2 text-slate-500 hover:text-white transition-colors mb-4 text-sm font-bold">
              <ChevronLeft className="w-4 h-4" /> Volver al Dashboard
            </button>
            <h2 className="text-3xl font-black text-white truncate">{sale.tableName}</h2>
            <p className="text-blue-500 text-sm font-black uppercase tracking-wider mt-1">
              Mesero: {sale.waiter?.name || <span className="text-slate-600 italic">No asignado</span>}
            </p>
         </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-4">
           {(sale.items || []).map((item) => (
             <div key={item.id} className="flex justify-between items-center group bg-white/5 p-3 rounded-2xl border border-white/5 hover:border-blue-500/30 transition-all">
                <div className="flex-1 min-w-0 pr-2">
                   <p className="text-white font-bold truncate text-sm">{item.productName}</p>
                   <p className="text-slate-500 text-[10px] font-bold uppercase">${formatCurrency(item.unitPrice)}</p>
                </div>

                <div className="flex items-center gap-2">
                   <div className="flex items-center bg-slate-800 rounded-xl p-1">
                      <button 
                        onClick={() => handleUpdateQuantity(item.id, item.quantity - 1)}
                        className="w-7 h-7 flex items-center justify-center text-slate-400 hover:text-white transition-colors"
                      >
                         <Minus className="w-4 h-4" />
                      </button>
                      <span className="w-8 text-center text-white font-black text-sm">{item.quantity}</span>
                      <button 
                        onClick={() => handleUpdateQuantity(item.id, item.quantity + 1)}
                        className="w-7 h-7 flex items-center justify-center text-slate-400 hover:text-white transition-colors"
                      >
                         <Plus className="w-4 h-4" />
                      </button>
                   </div>

                   <div className="text-right min-w-[70px]">
                      <p className="text-white font-black text-sm">${formatCurrency(item.subtotal)}</p>
                   </div>

                   <button 
                    onClick={() => handleRemoveItem(item.id)}
                    className="p-2 text-slate-600 hover:text-red-500 transition-colors"
                   >
                      <Trash2 className="w-4 h-4" />
                   </button>
                </div>
             </div>
           ))}

           {(!sale.items || sale.items.length === 0) && (
             <div className="py-20 text-center text-slate-600 border-2 border-dashed border-slate-800 rounded-3xl">
                <Utensils className="w-12 h-12 mx-auto mb-4 opacity-10" />
                No hay consumos todavía
             </div>
           )}
        </div>

        <div className="p-8 bg-slate-900 border-t border-slate-800 space-y-4">
           <button 
             onClick={() => setShouldPrintCommand(!shouldPrintCommand)}
             className={`w-full flex items-center justify-between p-3 rounded-2xl border transition-all ${shouldPrintCommand ? 'bg-blue-600/10 border-blue-500 text-blue-400' : 'bg-slate-800 border-slate-700 text-slate-500'}`}
           >
              <div className="flex items-center gap-2">
                 <Printer className="w-4 h-4" />
                 <span className="text-xs font-bold uppercase tracking-wider">Comanda opcional</span>
              </div>
              <div className={`w-8 h-4 rounded-full relative transition-all ${shouldPrintCommand ? 'bg-blue-500' : 'bg-slate-600'}`}>
                 <div className={`absolute top-0.5 w-3 h-3 bg-white rounded-full transition-all ${shouldPrintCommand ? 'right-0.5' : 'left-0.5'}`} />
              </div>
           </button>

           <div className="flex justify-between items-end">
              <span className="text-slate-500 font-bold uppercase tracking-widest text-xs">Total Parcial</span>
              <span className="text-4xl font-black text-blue-400">${formatCurrency(sale.totalAmount)}</span>
           </div>

           <div className="grid grid-cols-2 gap-4">
              <button 
                onClick={handleCancelOrder}
                className="bg-slate-800 hover:bg-red-950/30 hover:text-red-500 border border-slate-700 hover:border-red-500/50 text-slate-400 font-black py-4 rounded-2xl transition-all flex items-center justify-center gap-2"
              >
                <Trash2 className="w-5 h-5" /> Cancelar
              </button>
              <button 
                onClick={() => router.push(`/dashboard/restaurant/pay/${sale.id}`)}
                className="bg-blue-600 hover:bg-blue-500 text-white font-black py-4 rounded-2xl transition-all shadow-xl shadow-blue-900/30 flex items-center justify-center gap-2"
              >
                <CreditCard className="w-5 h-5" /> Cobrar
              </button>
           </div>
        </div>
      </div>

      {/* Main Area: Item Selection */}
      <div className="flex-1 p-8 overflow-y-auto">
        <div className="max-w-4xl mx-auto space-y-8">
            <div className="relative group">
              <Search className="absolute left-6 top-1/2 -translate-y-1/2 w-6 h-6 text-slate-500 group-focus-within:text-blue-500 transition-colors" />
              <input
                ref={searchInputRef}
                type="text"
                placeholder="Busca o Escanea..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                onKeyDown={handleSearchKeyDown}
                className="w-full bg-slate-800/40 border border-slate-700/50 rounded-[2rem] py-6 pl-16 pr-8 text-2xl text-white focus:outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all font-bold"
              />
           </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
               {search && filteredProducts.map((p) => (
                 <button
                   key={p.id}
                   onClick={() => setSelectedProduct(p)}
                   className="bg-slate-800/40 border border-slate-700/50 rounded-3xl p-6 text-left hover:border-blue-500 hover:bg-slate-800 transition-all group scale-100 active:scale-95 animate-in fade-in zoom-in-95"
                 >
                    <div className="flex justify-between items-start mb-2">
                       <div className="bg-blue-500/10 p-3 rounded-2xl text-blue-500 group-hover:bg-blue-500 group-hover:text-white transition-all">
                         <Plus className="w-5 h-5" />
                       </div>
                       <span className="text-xl font-black text-white">${formatCurrency(p.price)}</span>
                    </div>
                    <h4 className="text-lg font-bold text-slate-300 group-hover:text-white truncate">{p.name}</h4>
                 </button>
               ))}

               {search && filteredProducts.length === 0 && (
                 <div className="col-span-full py-12 text-center bg-slate-800/20 border border-dashed border-slate-700 rounded-3xl">
                    <Search className="w-10 h-10 mx-auto mb-3 text-slate-700" />
                    <p className="text-slate-500 font-bold">No se encontraron productos con "{search}"</p>
                 </div>
               )}
            </div>

           {/* Quick Quantity and Add Modal Overlay */}
           {selectedProduct && (
             <div className="fixed inset-0 z-[80] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
                <div className="bg-slate-900 border border-slate-800 w-full max-w-sm p-10 rounded-[3rem] shadow-2xl relative animate-in zoom-in-95 duration-200">
                   <button onClick={() => setSelectedProduct(null)} className="absolute top-6 right-6 p-2 text-slate-500 hover:text-white">
                      <X className="w-6 h-6" />
                   </button>

                   <h3 className="text-xl font-black text-white mb-2">{selectedProduct.name}</h3>
                   <p className="text-slate-500 font-bold mb-8">Selecciona la cantidad</p>

                   <div className="flex items-center justify-center gap-8 mb-10">
                      <button 
                        onClick={() => setQuantity(q => Math.max(1, q - 1))}
                        className="w-16 h-16 rounded-full bg-slate-800 border border-slate-700 flex items-center justify-center text-3xl font-black text-white hover:bg-slate-700 active:scale-90 transition-all"
                      > - </button>
                      <span className="text-6xl font-black text-white">{quantity}</span>
                      <button 
                        onClick={() => setQuantity(q => q + 1)}
                        className="w-16 h-16 rounded-full bg-blue-600 flex items-center justify-center text-3xl font-black text-white hover:bg-blue-500 active:scale-90 transition-all shadow-lg shadow-blue-900/40"
                      > + </button>
                   </div>

                   <button
                     disabled={isAdding}
                     onClick={handleAddItem}
                     className="w-full bg-blue-600 hover:bg-blue-500 disabled:bg-slate-700 text-white font-black py-6 rounded-3xl text-xl shadow-2xl shadow-blue-900/40 transition-all flex items-center justify-center gap-3"
                   >
                     {isAdding ? "Añadiendo..." : "Confirmar Ítem"}
                   </button>
                </div>
             </div>
           )}
        </div>
      </div>
    </div>
  );
}

'use client';
import { useState, useEffect } from 'react';
import { Utensils, Plus, User, Clock, DollarSign, ArrowRight, Trash2, Search, X } from 'lucide-react';
import { useRouter } from 'next/navigation';

interface OpenSale {
  id: string;
  tableName: string;
  totalAmount: number;
  createdAt: string;
  waiter?: { name: string };
}

interface Waiter {
  id: string;
  name: string;
}

export default function RestaurantDashboard() {
  const router = useRouter();
  const [openTables, setOpenTables] = useState<OpenSale[]>([]);
  const [waiters, setWaiters] = useState<Waiter[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');

  // Modals
  const [showOpenModal, setShowOpenModal] = useState(false);
  const [newAlias, setNewAlias] = useState('');
  const [selectedWaiterId, setSelectedWaiterId] = useState('');
  const [waiterPin, setWaiterPin] = useState('');
  const [error, setError] = useState('');

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const token = localStorage.getItem('access_token');
      const [resOpen, resWaiters] = await Promise.all([
        fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/restaurant/open`, {
          headers: { Authorization: `Bearer ${token}` }
        }),
        fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/waiters`, {
          headers: { Authorization: `Bearer ${token}` }
        })
      ]);

      if (resOpen.ok) setOpenTables(await resOpen.json());
      if (resWaiters.ok) setWaiters(await resWaiters.json());
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleOpenTable = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAlias || !selectedWaiterId || waiterPin.length !== 4) {
      setError('Por favor completa todos los campos correctamente');
      return;
    }

    try {
      const token = localStorage.getItem('access_token');
      const resVal = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/waiters/validate-pin`, {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}` 
        },
        body: JSON.stringify({ pin: waiterPin })
      });

      if (!resVal.ok) {
        setError('PIN de mesero incorrecto');
        return;
      }

      const waiter = await resVal.json();
      if (waiter.id !== selectedWaiterId) {
        setError('Ese PIN no pertenece al mesero seleccionado');
        return;
      }

      const resCreate = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/restaurant/order`, {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}` 
        },
        body: JSON.stringify({ tableName: newAlias, waiterId: selectedWaiterId, items: [] })
      });

      if (resCreate.ok) {
        const sale = await resCreate.json();
        router.push(`/dashboard/restaurant/order/${sale.id}`);
      } else {
        setError('Error al abrir la mesa');
      }

    } catch (err) {
      setError('Error de conexión');
    }
  };

  const filteredTables = openTables.filter(t => 
    t.tableName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    t.waiter?.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="p-6 max-w-7xl mx-auto space-y-8 animate-in fade-in duration-700">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-black tracking-tight text-white flex items-center gap-4">
            <Utensils className="w-10 h-10 text-blue-500" />
            Servicio a Mesas
          </h1>
          <p className="text-slate-400 mt-2 text-lg">
            Control de consumos activos y atención en barra.
          </p>
        </div>

        <div className="flex flex-col sm:flex-row gap-4">
          <div className="relative group flex-1 sm:w-80">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-500 group-focus-within:text-blue-500 transition-colors" />
            <input
              type="text"
              placeholder="Buscar mesa o mesero..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full bg-slate-800/50 border border-slate-700 rounded-2xl py-3 pl-12 pr-4 text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all"
            />
          </div>
          <button
            onClick={() => { setNewAlias(''); setSelectedWaiterId(''); setWaiterPin(''); setError(''); setShowOpenModal(true); }}
            className="bg-blue-600 hover:bg-blue-500 text-white px-8 py-3 rounded-2xl font-bold flex items-center justify-center gap-3 transition-all shadow-xl shadow-blue-900/30 active:scale-95"
          >
            <Plus className="w-6 h-6" />
            Abrir Mesa
          </button>
        </div>
      </div>

      {isLoading ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
          {[1,2,3,4].map(i => (
            <div key={i} className="h-48 bg-slate-800/40 rounded-[2rem] animate-pulse" />
          ))}
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
          {filteredTables.map((table) => (
            <div 
              key={table.id}
              onClick={() => router.push(`/dashboard/restaurant/order/${table.id}`)}
              className="group bg-slate-800/40 border border-slate-700/50 p-6 rounded-[2rem] hover:border-blue-500/50 hover:bg-slate-800/60 transition-all cursor-pointer relative overflow-hidden flex flex-col justify-between"
            >
              <div className="absolute top-0 right-0 p-4 opacity-0 group-hover:opacity-100 transition-opacity">
                <div className="bg-blue-600 text-white p-2 rounded-xl">
                  <ArrowRight className="w-4 h-4" />
                </div>
              </div>

              <div>
                <div className="flex items-center gap-3 text-slate-400 text-sm font-bold uppercase tracking-widest mb-3">
                  <User className="w-4 h-4 text-blue-500" />
                  {table.waiter?.name || 'Varios'}
                </div>
                <h3 className="text-2xl font-black text-white truncate leading-tight">
                  {table.tableName}
                </h3>
              </div>

              <div className="mt-8 flex items-end justify-between">
                <div>
                  <div className="flex items-center gap-1.5 text-slate-500 text-xs font-bold mb-1">
                    <Clock className="w-3.5 h-3.5" />
                    {new Date(table.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </div>
                  <div className="text-3xl font-black text-blue-400">
                    ${Number(table.totalAmount).toLocaleString('es-CO')}
                  </div>
                </div>
              </div>
            </div>
          ))}

          {filteredTables.length === 0 && (
            <div className="col-span-full py-32 bg-slate-800/10 border-2 border-dashed border-slate-700/50 rounded-[3rem] flex flex-col items-center justify-center text-slate-500">
               <Utensils className="w-20 h-20 mb-6 opacity-20" />
               <p className="text-xl font-bold">No hay mesas activas en este momento</p>
               <button 
                onClick={() => { setNewAlias(''); setSelectedWaiterId(''); setWaiterPin(''); setError(''); setShowOpenModal(true); }}
                className="mt-4 text-blue-500 hover:text-blue-400 font-bold transition-colors"
               >
                 Abrir mi primera mesa del turno
               </button>
            </div>
          )}
        </div>
      )}

      {showOpenModal && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center p-4 bg-black/80 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-[#0f172a] border border-slate-800 w-full max-w-lg p-10 rounded-[3rem] shadow-2xl relative animate-in zoom-in-95 duration-200">
            <button 
              onClick={() => setShowOpenModal(false)}
              className="absolute top-6 right-6 p-2 text-slate-500 hover:text-white rounded-full transition-colors"
            >
              <X className="w-6 h-6" />
            </button>

            <h2 className="text-3xl font-black text-white mb-8">Abrir Nueva Mesa</h2>

            <form onSubmit={handleOpenTable} className="space-y-8">
              <div className="space-y-2">
                <label className="text-sm font-black uppercase tracking-widest text-slate-500 ml-1">Alias o Nombre</label>
                <input
                  type="text"
                  required
                  placeholder="Ej: Barra Principal / Mesa Terraza 4"
                  value={newAlias}
                  onChange={(e) => setNewAlias(e.target.value)}
                  className="w-full bg-slate-800/50 border border-slate-700 rounded-3xl p-5 text-xl text-white focus:outline-none focus:ring-4 focus:ring-blue-500/20 focus:border-blue-500 transition-all"
                />
              </div>

              <div className="space-y-4">
                 <div className="flex flex-col gap-2">
                    <label className="text-sm font-black uppercase tracking-widest text-slate-500 ml-1">Seleccionar Mesero</label>
                    <select
                      required
                      value={selectedWaiterId}
                      onChange={(e) => setSelectedWaiterId(e.target.value)}
                      className="w-full bg-slate-800/50 border border-slate-700 rounded-3xl p-5 text-lg text-white appearance-none focus:outline-none focus:ring-4 focus:ring-blue-500/20 focus:border-blue-500 transition-all pointer-events-auto"
                    >
                      <option value="">Selecciona tu nombre...</option>
                      {waiters.map(w => (
                        <option key={w.id} value={w.id} className="bg-slate-900">{w.name}</option>
                      ))}
                    </select>
                 </div>

                 <div className="flex flex-col gap-2">
                    <label className="text-sm font-black uppercase tracking-widest text-slate-500 ml-1 text-center">Ingresa tu PIN de 4 dígitos</label>
                    <input
                      type="password"
                      maxLength={4}
                      required
                      value={waiterPin}
                      onChange={(e) => setWaiterPin(e.target.value.replace(/\D/g, ''))}
                      className="w-full bg-slate-900 border-2 border-slate-700 rounded-3xl p-6 text-center text-4xl font-mono tracking-[2rem] text-blue-400 focus:outline-none focus:border-blue-500 transition-all"
                      placeholder="****"
                    />
                 </div>
              </div>

              {error && (
                <div className="bg-red-500/10 border border-red-500/30 text-red-500 p-5 rounded-2xl text-center font-bold">
                  {error}
                </div>
              )}

              <button
                type="submit"
                className="w-full bg-blue-600 hover:bg-blue-500 text-white font-black py-6 rounded-[2rem] text-xl transition-all shadow-2xl shadow-blue-900/40 transform active:scale-[0.98]"
              >
                Comenzar Servicio
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

'use client';
import { useState, useEffect, use } from 'react';
import { CreditCard, DollarSign, ArrowLeft, Printer, CheckCircle2, ChevronRight, Search, User, UserPlus } from 'lucide-react';
import { useRouter } from 'next/navigation';
import { formatCurrency } from '@/utils/formatters';

interface Sale {
  id: string;
  tableName: string;
  totalAmount: number;
  waiter?: { name: string };
  items?: {
    quantity: number;
    productName: string;
    subtotal: number;
  }[];
}

export default function RestaurantPayPage({ params }: { params: Promise<{ id: string }> }) {
  const router = useRouter();
  const { id } = use(params);
  const [sale, setSale] = useState<Sale | null>(null);
  const [paymentMethod, setPaymentMethod] = useState<'efectivo' | 'tarjeta' | 'transferencia' | 'credito'>('efectivo');
  const [shouldPrint, setShouldPrint] = useState(true);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [customers, setCustomers] = useState<any[]>([]);
  const [selectedCustomerId, setSelectedCustomerId] = useState<string>('');
  const [customerSearch, setCustomerSearch] = useState('');

  useEffect(() => {
    fetchOrder();
    fetchCustomers();
  }, [id]);

  const fetchCustomers = async () => {
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/customers`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      if (res.ok) setCustomers(await res.json());
    } catch (err) {
      console.error(err);
    }
  };

  const fetchOrder = async () => {
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/${id}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      if (res.ok) setSale(await res.json());
    } catch (err) {
      console.error(err);
    }
  };

  const handleFinalize = async () => {
    setIsProcessing(true);
    try {
      const token = localStorage.getItem('access_token');
      const selectedCustomer = customers.find(c => c.id === selectedCustomerId);

      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/restaurant/order/${id}/close`, {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}` 
        },
        body: JSON.stringify({ 
          paymentMethod,
          customerId: selectedCustomerId || undefined,
          customerName: selectedCustomer?.name || (paymentMethod === 'credito' ? customerSearch : undefined)
        })
      });

      if (res.ok) {
        setIsSuccess(true);
        if (shouldPrint) {
          setTimeout(() => {
            window.print();
          }, 500);
        }
        setTimeout(() => router.push('/dashboard/restaurant'), 2000);
      } else {
        const errorData = await res.json().catch(() => ({}));
        alert(`Error al procesar la venta: ${errorData.message || 'Error desconocido en el servidor'}`);
      }
    } catch (err) {
      console.error(err);
      alert('Error de conexión al intentar cerrar la cuenta');
    } finally {
      setIsProcessing(false);
    }
  };

  if (!sale) return <div className="p-10 text-center text-slate-500">Cargando datos de cobro...</div>;

  return (
    <>
    <div className="p-6 h-full flex items-center justify-center bg-[#0f172a] print:hidden">
      {isSuccess ? (
        <div className="flex flex-col items-center justify-center h-full space-y-6 animate-in zoom-in-95 duration-500">
          <div className="w-24 h-24 bg-green-500 rounded-full flex items-center justify-center shadow-2xl shadow-green-900/40">
             <CheckCircle2 className="w-14 h-14 text-white" />
          </div>
          <div className="text-center">
            <h2 className="text-4xl font-black text-white">¡Pago Exitoso!</h2>
            <p className="text-slate-400 mt-2">La mesa {sale.tableName} ha sido cerrada correctamente.</p>
          </div>
        </div>
      ) : (
        <div className="w-full max-w-2xl bg-slate-900 border border-slate-800 rounded-[3rem] overflow-hidden shadow-2xl">
        <div className="p-10 border-b border-slate-800 bg-slate-900/50 flex justify-between items-center">
           <div>
              <h1 className="text-3xl font-black text-white">Cerrar Cuenta</h1>
              <p className="text-slate-500 font-bold uppercase tracking-wider text-xs mt-1">
                {sale.tableName} — {sale.waiter?.name}
              </p>
           </div>
           <div className="text-right">
              <p className="text-slate-500 text-sm font-bold">Total a Pagar</p>
              <p className="text-4xl font-black text-blue-400">${Number(sale.totalAmount).toLocaleString('es-CO')}</p>
           </div>
        </div>

        <div className="p-10 space-y-10">
            <div className="space-y-4">
               <label className="text-sm font-black uppercase tracking-widest text-slate-500 ml-1">Método de Pago</label>
               <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                  {[
                    { id: 'efectivo', icon: DollarSign, label: 'Efectivo' },
                    { id: 'credito', icon: User, label: 'Crédito' }
                  ].map((method) => (
                    <button
                     key={method.id}
                     onClick={() => setPaymentMethod(method.id as any)}
                     className={`p-4 rounded-3xl border-2 transition-all flex flex-col items-center gap-2 font-bold ${
                       paymentMethod === method.id 
                       ? 'bg-blue-600 border-blue-400 text-white shadow-lg shadow-blue-900/30' 
                       : 'bg-slate-800/50 border-slate-700 text-slate-500 hover:border-slate-500'
                     }`}
                    >
                       <method.icon className="w-5 h-5" />
                       <span className="text-xs">{method.label}</span>
                    </button>
                  ))}
               </div>
            </div>

            {/* SELECCIÓN DE CLIENTE (Solo si es Crédito) */}
            {paymentMethod === 'credito' && (
              <div className="space-y-4 animate-in slide-in-from-top-4 duration-300">
                <label className="text-sm font-black uppercase tracking-widest text-slate-500 ml-1">Seleccionar Cliente</label>
                <div className="relative group">
                  <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-500" />
                  <input
                    type="text"
                    placeholder="Buscar cliente..."
                    value={customerSearch}
                    onChange={(e) => setCustomerSearch(e.target.value)}
                    className="w-full bg-slate-800/50 border border-slate-700 rounded-2xl py-4 pl-12 pr-4 text-white focus:outline-none focus:border-blue-500 transition-all font-bold"
                  />
                </div>

                <div className="grid grid-cols-1 gap-2 max-h-40 overflow-y-auto">
                   {customers
                     .filter(c => c.name.toLowerCase().includes(customerSearch.toLowerCase()))
                     .slice(0, 4)
                     .map(customer => (
                       <button
                         key={customer.id}
                         onClick={() => {
                           setSelectedCustomerId(customer.id);
                           setCustomerSearch(customer.name);
                         }}
                         className={`flex items-center justify-between p-4 rounded-2xl border transition-all ${
                           selectedCustomerId === customer.id 
                           ? 'bg-blue-600/20 border-blue-500 text-white' 
                           : 'bg-slate-800/30 border-slate-700 text-slate-400 hover:bg-slate-800'
                         }`}
                       >
                         <span className="font-bold">{customer.name}</span>
                         {selectedCustomerId === customer.id && <CheckCircle2 className="w-4 h-4 text-blue-400" />}
                       </button>
                   ))}
                   {customerSearch && !customers.some(c => c.name.toLowerCase() === customerSearch.toLowerCase()) && (
                      <div className="p-4 rounded-2xl border border-dashed border-slate-700 text-slate-500 text-center flex items-center justify-center gap-2">
                         <UserPlus className="w-4 h-4" />
                         <span className="text-xs font-bold">Se creará cliente nuevo: "{customerSearch}"</span>
                      </div>
                   )}
                </div>
              </div>
            )}

           <div className="flex items-center justify-between bg-slate-800/30 p-6 rounded-3xl border border-slate-700/50">
              <div className="flex items-center gap-4">
                 <div className="bg-slate-800 p-3 rounded-2xl text-slate-400">
                    <Printer className="w-6 h-6" />
                 </div>
                 <div>
                    <p className="text-white font-bold">Imprimir Comprobante</p>
                    <p className="text-slate-500 text-xs">Generar ticket de venta física</p>
                 </div>
              </div>
              <button 
                onClick={() => setShouldPrint(!shouldPrint)}
                className={`w-16 h-8 rounded-full transition-all relative ${shouldPrint ? 'bg-blue-600' : 'bg-slate-700'}`}
              >
                 <div className={`absolute top-1 w-6 h-6 bg-white rounded-full transition-all ${shouldPrint ? 'right-1' : 'left-1'}`} />
              </button>
           </div>

           <div className="flex gap-4 pt-4">
              <button
                onClick={() => router.back()}
                className="flex-1 bg-slate-800 hover:bg-slate-700 text-slate-300 font-bold py-5 rounded-3xl transition-all"
              >
                Cancelar
              </button>
              <button
                disabled={isProcessing}
                onClick={handleFinalize}
                className="flex-[2] bg-blue-600 hover:bg-blue-500 text-white font-black py-5 rounded-3xl text-xl transition-all shadow-2xl shadow-blue-900/40 flex items-center justify-center gap-3 active:scale-95"
              >
                {isProcessing ? "Procesando..." : "Confirmar y Cobrar"}
              </button>
           </div>
        </div>
      </div>
      )}
    </div>

    {/* TICKET DE IMPRESIÓN (Solo visible al imprimir) */}
    <div id="printable-receipt" className="hidden print:block text-black bg-white p-4 font-mono text-sm leading-tight w-[58mm]">
      <div className="text-center mb-4">
        <h2 className="font-bold text-lg border-b border-black pb-2 mb-2 z-10 relative">Servicio a Mesas</h2>
        <p className="font-bold border border-black rounded inline-block px-2 mb-2">{sale.tableName}</p>
        <p className="text-xs">Atiende: {sale.waiter?.name || 'Varios'}</p>
        <p className="text-xs">{new Date().toLocaleString('es-CO')}</p>
      </div>

      <div className="border-b border-black border-dashed pb-2 mb-2 text-xs">
        <table className="w-full text-left">
          <thead>
            <tr className="border-b border-black">
              <th className="w-8 pb-1">Cant</th>
              <th className="pb-1">Prod</th>
              <th className="text-right pb-1">Total</th>
            </tr>
          </thead>
          <tbody>
            {(sale.items || []).map((item, idx) => (
              <tr key={idx}>
                <td className="align-top font-bold">{item.quantity}</td>
                <td className="align-top truncate">{item.productName}</td>
                <td className="text-right align-top">${Number(item.subtotal).toLocaleString('es-CO')}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      <div className="text-right pb-2 border-b border-black border-dashed">
        <p className="font-bold text-lg tracking-tight">TOTAL: ${Number(sale.totalAmount).toLocaleString('es-CO')}</p>
        <p className="text-xs mt-1">PAGO EN: {paymentMethod.toUpperCase()}</p>
      </div>

      <div className="text-center mt-4 text-[10px]">
        <p className="font-bold">¡Gracias por su visita!</p>
        <p className="mt-1">Sistema POS Tiendeo</p>
      </div>
    </div>
    </>
  );
}

'use client';
import { useState, useEffect } from 'react';
import { Plus, User, Trash2, Key, Info, Edit2 } from 'lucide-react';

interface Waiter {
  id: string;
  name: string;
  pin: string;
}

export default function WaitersPage() {
  const [waiters, setWaiters] = useState<Waiter[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [showAddModal, setShowAddModal] = useState(false);
  const [newWaiterName, setNewWaiterName] = useState('');
  const [newWaiterPin, setNewWaiterPin] = useState('');
  const [editingWaiter, setEditingWaiter] = useState<Waiter | null>(null);
  const [error, setError] = useState('');

  useEffect(() => {
    fetchWaiters();
  }, []);

  const fetchWaiters = async () => {
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/waiters`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      if (res.ok) {
        const data = await res.json();
        setWaiters(data);
      }
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleCreateWaiter = async (e: React.FormEvent) => {
    e.preventDefault();
    if (newWaiterPin.length !== 4) {
      setError('El PIN debe tener 4 dígitos');
      return;
    }

    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/waiters`, {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}` 
        },
        body: JSON.stringify({ name: newWaiterName, pin: newWaiterPin })
      });

      if (res.ok) {
        setShowAddModal(false);
        setNewWaiterName('');
        setNewWaiterPin('');
        setError('');
        fetchWaiters();
      } else {
        const data = await res.json();
        setError(data.message || 'Error al crear mesero');
      }
    } catch (err) {
      setError('Fallo de conexión');
    }
  };

  const handleUpdateWaiter = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingWaiter) return;
    if (editingWaiter.pin.length !== 4) {
      setError('El PIN debe tener 4 dígitos');
      return;
    }

    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/waiters/${editingWaiter.id}`, {
        method: 'PATCH',
        headers: { 
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}` 
        },
        body: JSON.stringify({ name: editingWaiter.name, pin: editingWaiter.pin })
      });

      if (res.ok) {
        setEditingWaiter(null);
        setError('');
        fetchWaiters();
      } else {
        const data = await res.json();
        setError(data.message || 'Error al actualizar mesero');
      }
    } catch (err) {
      setError('Fallo de conexión');
    }
  };

  const handleDeleteWaiter = async (id: string) => {
    if (!confirm('¿Estás seguro de eliminar a este mesero?')) return;

    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/waiters/${id}`, {
        method: 'DELETE',
        headers: { Authorization: `Bearer ${token}` }
      });
      if (res.ok) fetchWaiters();
    } catch (err) {
      console.error(err);
    }
  };

  return (
    <div className="p-6 max-w-6xl mx-auto space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-3xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-slate-400">
            Gestión de Meseros
          </h1>
          <p className="text-slate-400 mt-1 flex items-center gap-2">
            <Info className="w-4 h-4" />
            Configura los accesos rápidos por PIN para tu personal de mesas.
          </p>
        </div>
        <button
          onClick={() => setShowAddModal(true)}
          className="flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-500 text-white px-6 py-3 rounded-2xl font-bold transition-all shadow-lg shadow-blue-900/20 active:scale-95"
        >
          <Plus className="w-5 h-5" />
          Nuevo Mesero
        </button>
      </div>

      {isLoading ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {[1, 2, 3].map(i => (
            <div key={i} className="h-40 bg-slate-800/50 rounded-3xl animate-pulse" />
          ))}
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {waiters.map((waiter) => (
            <div 
              key={waiter.id} 
              className="group bg-slate-800/40 border border-slate-700/50 hover:border-blue-500/50 p-6 rounded-3xl transition-all hover:shadow-2xl hover:shadow-blue-900/10 flex flex-col justify-between"
            >
              <div className="flex items-start justify-between">
                <div className="bg-blue-600/10 p-4 rounded-2xl text-blue-500">
                  <User className="w-8 h-8" />
                </div>
                <div className="flex gap-2">
                  <button
                    onClick={() => setEditingWaiter(waiter)}
                    className="p-2 text-slate-500 hover:text-blue-400 hover:bg-blue-400/10 rounded-xl transition-colors"
                  >
                    <Edit2 className="w-5 h-5" />
                  </button>
                  <button
                    onClick={() => handleDeleteWaiter(waiter.id)}
                    className="p-2 text-slate-500 hover:text-red-500 hover:bg-red-500/10 rounded-xl transition-colors"
                  >
                    <Trash2 className="w-5 h-5" />
                  </button>
                </div>
              </div>
              <div className="mt-6">
                <h3 className="text-xl font-bold text-white group-hover:text-blue-400 transition-colors">
                  {waiter.name}
                </h3>
                <div className="mt-2 flex items-center gap-2 text-slate-400 font-mono">
                  <Key className="w-4 h-4 text-orange-500" />
                  PIN: <span className="bg-slate-900/50 px-2 py-0.5 rounded-lg text-white tracking-widest">****</span>
                </div>
              </div>
            </div>
          ))}

          {waiters.length === 0 && (
            <div className="col-span-full py-20 bg-slate-800/20 border-2 border-dashed border-slate-700 rounded-3xl flex flex-col items-center text-slate-500 font-medium">
              <User className="w-16 h-16 mb-4 opacity-20" />
              Todavía no has creado ningún mesero.
            </div>
          )}
        </div>
      )}

      {/* Modal Agregar Mesero */}
      {showAddModal && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-slate-900 border border-slate-800 w-full max-w-md p-8 rounded-[2.5rem] shadow-2xl animate-in zoom-in-95 duration-200">
            <h2 className="text-2xl font-bold text-white mb-6">Nuevo Mesero</h2>
            <form onSubmit={handleCreateWaiter} className="space-y-6">
              <div>
                <label className="block text-sm font-semibold text-slate-400 mb-2 px-1">Nombre Completo</label>
                <input
                  type="text"
                  required
                  value={newWaiterName}
                  onChange={(e) => setNewWaiterName(e.target.value)}
                  className="w-full bg-slate-800 border border-slate-700 rounded-2xl p-4 text-white focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all"
                  placeholder="Ej: Juan Pérez"
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-400 mb-2 px-1">PIN de Acceso (4 dígitos)</label>
                <input
                  type="text"
                  maxLength={4}
                  required
                  value={newWaiterPin}
                  onChange={(e) => setNewWaiterPin(e.target.value.replace(/\D/g, ''))}
                  className="w-full bg-slate-800 border border-slate-700 rounded-2xl p-4 text-white text-center text-3xl font-mono tracking-[1rem] focus:outline-none focus:ring-2 focus:ring-orange-500 transition-all font-bold"
                  placeholder="0000"
                />
              </div>

              {error && (
                <div className="bg-red-500/10 border border-red-500/50 text-red-500 p-4 rounded-xl text-sm font-semibold">
                  {error}
                </div>
              )}

              <div className="flex gap-4 pt-4">
                <button
                  type="button"
                  onClick={() => setShowAddModal(false)}
                  className="flex-1 bg-slate-800 hover:bg-slate-700 text-slate-300 font-bold py-4 rounded-2xl transition-all"
                >
                  Cancelar
                </button>
                <button
                  type="submit"
                  className="flex-1 bg-blue-600 hover:bg-blue-500 text-white font-bold py-4 rounded-2xl transition-all shadow-lg shadow-blue-900/20"
                >
                  Guardar
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Modal Editar Mesero */}
      {editingWaiter && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-slate-900 border border-slate-800 w-full max-w-md p-8 rounded-[2.5rem] shadow-2xl animate-in zoom-in-95 duration-200">
            <h2 className="text-2xl font-bold text-white mb-6">Editar Mesero</h2>
            <form onSubmit={handleUpdateWaiter} className="space-y-6">
              <div>
                <label className="block text-sm font-semibold text-slate-400 mb-2 px-1">Nombre Completo</label>
                <input
                  type="text"
                  required
                  value={editingWaiter.name}
                  onChange={(e) => setEditingWaiter({ ...editingWaiter, name: e.target.value })}
                  className="w-full bg-slate-800 border border-slate-700 rounded-2xl p-4 text-white focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all"
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-400 mb-2 px-1">Nuevo PIN (4 dígitos)</label>
                <input
                  type="text"
                  maxLength={4}
                  required
                  value={editingWaiter.pin}
                  onChange={(e) => setEditingWaiter({ ...editingWaiter, pin: e.target.value.replace(/\D/g, '') })}
                  className="w-full bg-slate-800 border border-slate-700 rounded-2xl p-4 text-white text-center text-3xl font-mono tracking-[1rem] focus:outline-none focus:ring-2 focus:ring-orange-500 transition-all font-bold"
                />
              </div>

              {error && (
                <div className="bg-red-500/10 border border-red-500/50 text-red-500 p-4 rounded-xl text-sm font-semibold">
                  {error}
                </div>
              )}

              <div className="flex gap-4 pt-4">
                <button
                  type="button"
                  onClick={() => { setEditingWaiter(null); setError(''); }}
                  className="flex-1 bg-slate-800 hover:bg-slate-700 text-slate-300 font-bold py-4 rounded-2xl transition-all"
                >
                  Cancelar
                </button>
                <button
                  type="submit"
                  className="flex-1 bg-blue-600 hover:bg-blue-500 text-white font-bold py-4 rounded-2xl transition-all shadow-lg shadow-blue-900/20"
                >
                  Actualizar
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

'use client';
import { useState, useEffect } from 'react';
import { Search, RotateCcw, Package, AlertCircle, CheckCircle2, Hash, Trash2 } from 'lucide-react';
import { formatCurrency as curr } from '@/utils/formatters';


export default function RefundsPage() {
  const [searchQuery, setSearchQuery] = useState('');
  const [sale, setSale] = useState<any>(null);
  const [searchResults, setSearchResults] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [refundItems, setRefundItems] = useState<any[]>([]);
  const [reason, setReason] = useState('');
  const [processing, setProcessing] = useState(false);
  const [notification, setNotification] = useState<{message: string, type: 'success' | 'error'} | null>(null);

  const showNotification = (message: string, type: 'success' | 'error' = 'success') => {
    setNotification({ message, type });
    setTimeout(() => setNotification(null), 5000);
  };

  const searchSale = async () => {
    if (!searchQuery) return;
    setLoading(true);
    setSale(null);
    setSearchResults([]);
    try {
      const token = localStorage.getItem('access_token');
      const apiUrl = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001';
      
      const res = await fetch(`${apiUrl}/sales`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      
      if (!res.ok) throw new Error('Error al buscar ventas');
      const data = await res.json();
      
      const query = searchQuery.toLowerCase();
      const filteredSales = data.filter((s: any) => {
        const invMatch = s.invoiceNumber ? s.invoiceNumber.toLowerCase().includes(query) : false;
        const idMatch = s.id === searchQuery;
        const productMatch = s.items?.some((item: any) => 
          item.productName && item.productName.toLowerCase().includes(query)
        );
        return invMatch || idMatch || productMatch;
      });

      if (filteredSales.length === 1) {
        selectSale(filteredSales[0]);
      } else if (filteredSales.length > 1) {
        setSearchResults(filteredSales);
      } else {
        showNotification('No se encontraron ventas con esos criterios', 'error');
      }
    } catch (error) {
      console.error(error);
      showNotification('Error al buscar la venta', 'error');
    } finally {
      setLoading(false);
    }
  };

  const selectSale = (s: any) => {
    setSale(s);
    setSearchResults([]);
    setRefundItems(s.items.map((item: any) => ({
      ...item,
      refundQuantity: 0,
      returnsToInventory: true
    })));
  };

  const handleQuantityChange = (index: number, val: number) => {
    const updated = [...refundItems];
    const max = updated[index].quantity;
    const newVal = Math.max(0, Math.min(max, val));
    updated[index].refundQuantity = newVal;
    setRefundItems(updated);
  };

  const toggleInventoryReturn = (index: number) => {
    const updated = [...refundItems];
    updated[index].returnsToInventory = !updated[index].returnsToInventory;
    setRefundItems(updated);
  };

  const calculateTotalRefund = () => {
    return refundItems.reduce((sum, item) => sum + (item.refundQuantity * item.unitPrice), 0);
  };

  const processRefund = async () => {
    const totalAmount = calculateTotalRefund();
    if (totalAmount <= 0) {
      showNotification('Selecciona al menos un producto para devolver', 'error');
      return;
    }

    setProcessing(true);
    try {
      const token = localStorage.getItem('access_token');
      const apiUrl = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001';
      
      const itemsToRefund = refundItems
        .filter(item => item.refundQuantity > 0)
        .map(item => ({
          productId: item.productId,
          productName: item.productName,
          quantity: item.refundQuantity,
          unitPrice: item.unitPrice,
          subtotal: item.refundQuantity * item.unitPrice,
          returnsToInventory: item.returnsToInventory
        }));

      const res = await fetch(`${apiUrl}/sales/refunds`, {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}` 
        },
        body: JSON.stringify({
          saleId: sale.id,
          totalAmount,
          reason,
          items: itemsToRefund
        })
      });

      if (!res.ok) throw new Error('Error al procesar devolución');

      showNotification('Devolución procesada con éxito');
      
      // Limpiar después de un momento
      setTimeout(() => {
        setSale(null);
        setSearchQuery('');
        setReason('');
        window.location.reload();
      }, 2000);
      
    } catch (error) {
      console.error(error);
      showNotification('Error al procesar la devolución', 'error');
    } finally {
      setProcessing(false);
    }
  };

  return (
    <div className="max-w-6xl mx-auto space-y-6 pb-20 relative">
      {/* Notificación flotante */}
      {notification && (
        <div className={`fixed top-24 right-8 z-[100] p-4 rounded-2xl shadow-2xl animate-in slide-in-from-right duration-300 border ${
          notification.type === 'success' 
            ? 'bg-emerald-50 border-emerald-200 text-emerald-800 dark:bg-emerald-900/30 dark:border-emerald-800 dark:text-emerald-400' 
            : 'bg-rose-50 border-rose-200 text-rose-800 dark:bg-rose-900/30 dark:border-rose-800 dark:text-rose-400'
        } flex items-center gap-3 font-bold`}>
          {notification.type === 'success' ? <CheckCircle2 className="w-6 h-6" /> : <AlertCircle className="w-6 h-6" />}
          {notification.message}
        </div>
      )}

      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-3xl font-extrabold text-slate-900 dark:text-white flex items-center gap-3">
            <div className="p-2 bg-blue-100 dark:bg-blue-900/30 rounded-2xl">
              <RotateCcw className="w-8 h-8 text-blue-600" />
            </div>
            Devoluciones y Cambios
          </h1>
          <p className="text-slate-500 dark:text-slate-400 mt-2 font-medium">
            Ingresa el número de ticket para iniciar un proceso de retorno.
          </p>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] p-8 shadow-2xl border border-slate-100 dark:border-slate-800 transition-all hover:shadow-blue-500/5">
        <div className="flex flex-col md:flex-row gap-4">
          <div className="relative flex-1 group">
            <div className="absolute inset-y-0 left-5 flex items-center pointer-events-none">
              <Search className="w-6 h-6 text-slate-400 group-focus-within:text-blue-500 transition-colors" />
            </div>
            <input
              type="text"
              placeholder="Buscar Ticket o Producto..."
              className="w-full pl-14 pr-6 py-5 bg-slate-50 dark:bg-slate-800/50 border-2 border-transparent focus:border-blue-500 focus:bg-white dark:focus:bg-slate-800 rounded-3xl transition-all text-xl font-bold placeholder:font-medium placeholder:text-slate-400 dark:text-white outline-none"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && searchSale()}
            />
          </div>
          <button
            onClick={searchSale}
            disabled={loading}
            className="px-10 py-5 bg-blue-600 hover:bg-blue-700 text-white rounded-3xl font-black text-lg transition-all shadow-xl shadow-blue-500/20 disabled:opacity-50 active:scale-95 flex items-center justify-center gap-2"
          >
            {loading ? (
               <div className="w-6 h-6 border-4 border-white/30 border-t-white rounded-full animate-spin"></div>
            ) : 'Buscar'}
          </button>
        </div>
      </div>

      {/* Resultados de búsqueda (Múltiples ventas) */}
      {searchResults.length > 0 && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 animate-in fade-in zoom-in duration-300">
          {searchResults.map((s) => (
            <button
              key={s.id}
              onClick={() => selectSale(s)}
              className="p-6 bg-white dark:bg-slate-900 rounded-3xl border border-slate-100 dark:border-slate-800 text-left hover:border-blue-500 hover:shadow-xl transition-all group"
            >
              <div className="flex justify-between items-start mb-4">
                <div className="p-3 bg-blue-50 dark:bg-blue-900/20 rounded-2xl text-blue-600 group-hover:bg-blue-600 group-hover:text-white transition-colors">
                  <Hash className="w-5 h-5" />
                </div>
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{new Date(s.createdAt).toLocaleDateString()}</span>
              </div>
              <h3 className="font-extrabold text-xl dark:text-white mb-1 uppercase tracking-tight">{s.invoiceNumber}</h3>
              <p className="text-sm text-slate-500 dark:text-slate-400 font-bold mb-4">${curr(s.totalAmount)}</p>
              <div className="space-y-1">
                {s.items.slice(0, 2).map((item: any, i: number) => (
                  <p key={i} className="text-xs text-slate-400 truncate tracking-tight">• {item.productName}</p>
                ))}
                {s.items.length > 2 && <p className="text-[10px] text-blue-500 font-black">+{s.items.length - 2} productos más</p>}
              </div>
            </button>
          ))}
        </div>
      )}

      {sale && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 animate-in fade-in slide-in-from-bottom-10 duration-700">
          {/* Detalles de la Venta */}
          <div className="lg:col-span-2 space-y-8">
            <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] shadow-2xl border border-slate-100 dark:border-slate-800 overflow-hidden">
              <div className="p-8 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between bg-slate-50/50 dark:bg-slate-800/30">
                <div className="flex items-center gap-4">
                  <div className="p-3 bg-white dark:bg-slate-800 rounded-2xl shadow-sm text-blue-600">
                    <Hash className="w-6 h-6" />
                  </div>
                  <div>
                    <span className="block text-[10px] font-black uppercase tracking-[0.2em] text-slate-400">Comprobante</span>
                    <span className="font-extrabold text-2xl dark:text-white uppercase tracking-tight">{sale.invoiceNumber}</span>
                  </div>
                </div>
                <div className="text-right">
                  <span className="block text-[10px] font-black uppercase tracking-[0.2em] text-slate-400">Fecha Emisión</span>
                  <span className="text-sm font-bold text-slate-600 dark:text-slate-300">
                    {new Date().toLocaleString('es-CO')}
                  </span>
                </div>
              </div>

              <div className="p-8">
                <div className="overflow-x-auto">
                  <table className="w-full text-left">
                    <thead>
                      <tr className="text-xs font-black text-slate-400 uppercase tracking-[0.2em]">
                        <th className="pb-6">Producto</th>
                        <th className="pb-6 text-center">C. Orig.</th>
                        <th className="pb-6 text-center">A Devolver</th>
                        <th className="pb-6 text-right">Precio</th>
                        <th className="pb-6 text-center">Stock</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                      {refundItems.map((item, idx) => (
                        <tr key={idx} className="group transition-colors hover:bg-slate-50/50 dark:hover:bg-slate-800/30">
                          <td className="py-6">
                            <div className="font-bold text-slate-900 dark:text-white text-lg">{item.productName}</div>
                            <div className="text-xs text-slate-400 font-medium">SKU: {item.productId.slice(-8)}</div>
                          </td>
                          <td className="py-6 text-center font-black text-slate-400">
                            {item.quantity}
                          </td>
                          <td className="py-6">
                            <div className="flex items-center justify-center gap-4">
                              <button
                                onClick={() => handleQuantityChange(idx, item.refundQuantity - 1)}
                                className="w-10 h-10 rounded-2xl bg-slate-100 dark:bg-slate-800 flex items-center justify-center hover:bg-blue-500 hover:text-white transition-all active:scale-90 font-black"
                              >
                                -
                              </button>
                              <span className="w-10 text-center font-black text-2xl text-blue-600 dark:text-blue-400">
                                {item.refundQuantity}
                              </span>
                              <button
                                onClick={() => handleQuantityChange(idx, item.refundQuantity + 1)}
                                className="w-10 h-10 rounded-2xl bg-slate-100 dark:bg-slate-800 flex items-center justify-center hover:bg-blue-500 hover:text-white transition-all active:scale-90 font-black"
                              >
                                +
                              </button>
                            </div>
                          </td>
                          <td className="py-6 text-right font-black text-slate-900 dark:text-white text-lg">
                            ${curr(item.unitPrice)}
                          </td>
                          <td className="py-6 text-center">
                            <button
                              onClick={() => toggleInventoryReturn(idx)}
                              className={`p-3 rounded-2xl transition-all active:scale-90 border-2 ${
                                item.returnsToInventory
                                  ? 'bg-emerald-50 border-emerald-100 text-emerald-600 dark:bg-emerald-900/20 dark:border-emerald-900/50'
                                  : 'bg-slate-50 border-slate-100 text-slate-400 dark:bg-slate-800 dark:border-slate-700'
                              }`}
                              title={item.returnsToInventory ? "Regresa al stock" : "No regresa al stock"}
                            >
                              <Package className="w-6 h-6" />
                            </button>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
          </div>

          {/* Resumen de Devolución */}
          <div className="space-y-8">
            <div className="bg-slate-900 rounded-[2.5rem] p-8 shadow-2xl text-white sticky top-10 border border-slate-800">
              <h2 className="text-2xl font-black mb-8 flex items-center gap-3">
                <div className="p-2 bg-white/10 rounded-xl">
                  <AlertCircle className="w-6 h-6 text-blue-400" />
                </div>
                Liquidación
              </h2>
              
              <div className="space-y-6 mb-8">
                <div className="flex justify-between items-center pb-4 border-b border-white/10">
                  <span className="text-slate-400 font-bold uppercase text-[10px] tracking-widest">Medio de Pago</span>
                  <span className="font-black uppercase bg-blue-500/20 px-3 py-1 rounded-lg text-blue-400 text-sm">
                    {sale.paymentMethod}
                  </span>
                </div>
                <div className="flex justify-between items-center pb-4 border-b border-white/10">
                  <span className="text-slate-400 font-bold uppercase text-[10px] tracking-widest">Titular</span>
                  <span className="font-black text-sm">{sale.customerName || 'Consumidor Final'}</span>
                </div>
                
                <div className="pt-4">
                  <span className="block text-slate-400 font-bold uppercase text-[10px] tracking-widest mb-2">Total Ajuste</span>
                  <div className="flex items-baseline gap-2">
                    <span className="text-5xl font-black text-white">
                      ${curr(calculateTotalRefund())}
                    </span>
                  </div>
                </div>
              </div>

              <div className="space-y-4 mb-8">
                <label className="block text-[10px] font-black uppercase tracking-widest text-slate-400">Observaciones / Motivo</label>
                <textarea
                  className="w-full p-5 bg-white/5 border border-white/10 rounded-3xl focus:ring-2 focus:ring-blue-500 outline-none transition-all placeholder:text-slate-600 font-medium"
                  rows={4}
                  placeholder="Explica el motivo (ej: Mismo cambio, daño fábrica)..."
                  value={reason}
                  onChange={(e) => setReason(e.target.value)}
                />
              </div>

              <button
                onClick={processRefund}
                disabled={processing || calculateTotalRefund() <= 0}
                className="w-full py-5 bg-gradient-to-r from-blue-600 to-blue-500 hover:from-blue-500 hover:to-blue-400 text-white rounded-3xl font-black text-lg transition-all shadow-xl shadow-blue-900/40 flex items-center justify-center gap-3 disabled:opacity-30 active:scale-95 group"
              >
                {processing ? (
                   <div className="w-6 h-6 border-4 border-white/30 border-t-white rounded-full animate-spin"></div>
                ) : (
                  <>
                    <CheckCircle2 className="w-6 h-6 group-hover:scale-110 transition-transform" />
                    Finalizar Retorno
                  </>
                )}
              </button>
              
              <p className="text-[10px] text-center text-slate-500 font-bold uppercase mt-6 tracking-tight">
                * Esta operación afectará inventario y cierre de caja activo
              </p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

'use client';
import { useState, useEffect } from 'react';
import { Store, Users, User, Settings as SettingsIcon, Save, Key, Printer, Phone, Eye, EyeOff, MapPin, X, Edit2, Trash2, ToggleLeft, ToggleRight } from 'lucide-react';
import { useRouter } from 'next/navigation';

export default function SettingsPage() {
  const router = useRouter();
  const [activeTab, setActiveTab] = useState('business');
  const [userName, setUserName] = useState('');
  const [userRole, setUserRole] = useState('');
  
  // Business State (from DB)
  const [tenantData, setTenantData] = useState({
    name: 'TIENDA LAS MARGARITAS',
    rutNit: '',
    ticketPaperSize: '58mm',
    ticketAutoPrint: false,
    ticketHeaderMessage: '',
    ticketFooterMessage: '',
    location: '',
    phone: '',
    address: ''
  });

  const [isSaving, setIsSaving] = useState(false);

  // Modules state
  const ALL_MODULES = [
    { id: 'POS', name: 'Caja Registradora (POS)', description: 'Venta rápida e impresión de tickets' },
    { id: 'CLOSURE', name: 'Cierre de Caja', description: 'Control de turnos y arqueos' },
    { id: 'INVENTORY', name: 'Control de Inventario', description: 'Stock, categorías y alertas' },
    { id: 'REPORTS', name: 'Reportes y Estadísticas', description: 'Análisis de ventas y ganancias' },
    { id: 'SUPPLIERS', name: 'Proveedores y Gastos', description: 'Gestión de compras y facturas' },
    { id: 'CUSTOMERS', name: 'Base de Datos de Clientes', description: 'Historial y fidelización' },
    { id: 'CREDITS', name: 'Créditos (Cuentas por Cobrar)', description: 'Venta a crédito y abonos' },
    { id: 'REFUNDS', name: 'Devoluciones y Reembolsos', description: 'Gestión de cambios de productos' },
    { id: 'ACCOUNTING', name: 'Módulo Contable', description: 'Libro de ingresos y egresos' },
    { id: 'RESTAURANT', name: 'Servicio a Mesas', description: 'Atención por mesas, barra y PIN para meseros' },
  ];
  const [activeModules, setActiveModules] = useState<string[]>(['POS', 'CLOSURE', 'INVENTORY', 'REPORTS', 'SUPPLIERS', 'CUSTOMERS', 'CREDITS', 'REFUNDS', 'ACCOUNTING']);

  const toggleModule = (id: string) => {
    setActiveModules(prev =>
      prev.includes(id) ? prev.filter(m => m !== id) : [...prev, id]
    );
  };
  
  // Users management state
  const [users, setUsers] = useState<any[]>([]);
  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [editingUser, setEditingUser] = useState<any>(null);
  const [showPassword, setShowPassword] = useState(false);
  const [newUser, setNewUser] = useState({ name: '', email: '', password: '', role: 'CASHIER' });
  const [isResetModalOpen, setIsResetModalOpen] = useState(false);
  const [resetConfirmText, setResetConfirmText] = useState('');
  const [isResetting, setIsResetting] = useState(false);
  const [isCleaning, setIsCleaning] = useState(false);

  useEffect(() => {
    const savedName = localStorage.getItem('user_name');
    const savedRole = localStorage.getItem('user_role');
    
    if (savedName) setUserName(savedName);
    if (savedRole) setUserRole(savedRole);
    
    fetchTenant();
    fetchUsers();
  }, []);

  const fetchTenant = async () => {
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/tenants/me`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      if (res.ok) {
        const data = await res.json();
        setTenantData({
          ...tenantData,
          name: data.name,
          rutNit: data.rutNit || '',
          ticketPaperSize: data.ticketPaperSize || '58mm',
          ticketAutoPrint: data.ticketAutoPrint || false,
          ticketHeaderMessage: data.ticketHeaderMessage || '',
          ticketFooterMessage: data.ticketFooterMessage || '',
          location: data.location || '',
          phone: data.phone || '',
          address: data.address || '',
        });
        // Load modules from backend or fall back to all if null
        const defaultModules = ['POS', 'CLOSURE', 'INVENTORY', 'REPORTS', 'SUPPLIERS', 'CUSTOMERS', 'CREDITS', 'REFUNDS', 'ACCOUNTING'];
        setActiveModules(data.modules || defaultModules);
      }
    } catch (error) {
      console.error("Error fetching tenant", error);
    }
  };

  const fetchUsers = async () => {
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/users`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      if (res.ok) {
        const data = await res.json();
        setUsers(data);
      }
    } catch (error) {
      console.error("Error fetching users", error);
    }
  };

  const handleEditUser = (user: any) => {
    setEditingUser({ ...user, password: '' });
    setIsEditModalOpen(true);
  };

  const handleUpdateUser = async () => {
    try {
      const token = localStorage.getItem('access_token');
      const payload: any = {
        name: editingUser.name,
        email: editingUser.email,
        role: editingUser.role
      };
      if (editingUser.password) {
        payload.passwordHash = editingUser.password;
      }

      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/users/${editingUser.id}`, {
        method: 'PATCH',
        headers: { 
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}` 
        },
        body: JSON.stringify(payload)
      });

      if (res.ok) {
        setIsEditModalOpen(false);
        fetchUsers();
        alert('Usuario actualizado correctamente');
      } else {
        const err = await res.json();
        alert(`Error: ${err.message || 'No se pudo actualizar el usuario'}`);
      }
    } catch (error) {
      alert('Error de conexión al actualizar usuario');
    }
  };
  
  const handleDeleteUser = async (id: string) => {
    if (!confirm('¿Estás seguro de eliminar este usuario?')) return;
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/users/${id}`, {
        method: 'DELETE',
        headers: { Authorization: `Bearer ${token}` }
      });

      if (res.ok) {
        fetchUsers();
        alert('Usuario eliminado');
      } else {
        alert('No se pudo eliminar el usuario');
      }
    } catch (error) {
      alert('Error de conexión al eliminar');
    }
  };

  const handleCreateUser = async () => {
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/users`, {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}` 
        },
        body: JSON.stringify({
          name: newUser.name,
          email: newUser.email,
          passwordHash: newUser.password,
          role: newUser.role
        })
      });

      if (res.ok) {
        setIsCreateModalOpen(false);
        setNewUser({ name: '', email: '', password: '', role: 'CASHIER' });
        setShowPassword(false);
        fetchUsers();
        alert('Usuario creado correctamente');
      } else {
        const err = await res.json();
        alert(`Error: ${err.message || 'No se pudo crear el usuario'}`);
      }
    } catch (error) {
      alert('Error de conexión al crear usuario');
    }
  };

  const handleSaveBusiness = async () => {
    setIsSaving(true);
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/tenants/me`, {
        method: 'PATCH',
        headers: { 
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}` 
        },
        body: JSON.stringify({
          name: tenantData.name,
          rutNit: tenantData.rutNit,
          ticketPaperSize: tenantData.ticketPaperSize,
          ticketAutoPrint: tenantData.ticketAutoPrint,
          ticketHeaderMessage: tenantData.ticketHeaderMessage,
          ticketFooterMessage: tenantData.ticketFooterMessage,
          location: tenantData.location,
          phone: tenantData.phone,
          address: tenantData.address,
          modules: activeModules,
        })
      });

      if (res.ok) {
        localStorage.setItem('store_name', tenantData.name);
        localStorage.setItem('tenant_modules', JSON.stringify(activeModules));
        // Reload so the sidebar reflects module changes immediately
        window.location.reload();
      } else {
        alert('Error al guardar la configuración.');
      }
    } catch (error) {
      alert('Error de conexión al guardar.');
    } finally {
      setIsSaving(false);
    }
  };

  const handleResetData = async () => {
    if (resetConfirmText !== 'REINICIAR_TODO_A_CEROS') {
      alert('Por favor escriba la frase de confirmación exacta: REINICIAR_TODO_A_CEROS');
      return;
    }

    setIsResetting(true);
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/maintenance/reset-my-data`, {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}` 
        },
        body: JSON.stringify({ 
          confirmText: resetConfirmText,
          cleanSales: true,
          cleanCredits: true,
          cleanCashClosures: true,
          cleanRefunds: true,
          cleanSupplierInvoices: false // Protect these by default as requested
        })
      });

      if (res.ok) {
        alert('Los datos han sido reiniciados correctamente. El sistema se redirigirá al inicio.');
        setIsResetModalOpen(false);
        setResetConfirmText('');
        router.push('/dashboard');
      } else {
        const err = await res.json();
        alert(`Error: ${err.message || 'No se pudo reiniciar los datos'}`);
      }
    } catch (error) {
      alert('Error de conexión al reiniciar datos');
    } finally {
      setIsResetting(false);
    }
  };

  const handleCleanupDuplicates = async () => {
    if (!confirm('Este proceso eliminará los registros de ventas duplicados (manteniendo el más reciente). ¿Deseas continuar?')) return;
    
    setIsCleaning(true);
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/maintenance/cleanup-duplicates`, {
        method: 'POST',
        headers: { 
          'Authorization': `Bearer ${token}` 
        }
      });

      if (res.ok) {
        const data = await res.json();
        alert(data.message || 'Limpieza completada correctamente.');
      } else {
        const err = await res.json();
        alert(`Error: ${err.message || 'No se pudo realizar la limpieza'}`);
      }
    } catch (error) {
      alert('Error de conexión al realizar limpieza');
    } finally {
      setIsCleaning(false);
    }
  };

  return (
    <div className="p-4 md:p-8 max-w-5xl mx-auto">
      <div className="flex flex-col md:flex-row gap-8">
        
        {/* Sidebar Mini - Tabs */}
        <div className="w-full md:w-64 space-y-2">
          <h2 className="text-2xl font-black text-gray-900 dark:text-white mb-6">Configuración</h2>
          
          <button 
            onClick={() => setActiveTab('business')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-2xl font-bold transition-all ${activeTab === 'business' ? 'bg-blue-600 text-white shadow-lg' : 'hover:bg-gray-100 dark:hover:bg-slate-800 text-gray-600 dark:text-gray-400'}`}
          >
            <Store className="w-5 h-5" />
            Mi Negocio
          </button>
          
          <button 
            onClick={() => setActiveTab('profile')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-2xl font-bold transition-all ${activeTab === 'profile' ? 'bg-blue-600 text-white shadow-lg' : 'hover:bg-gray-100 dark:hover:bg-slate-800 text-gray-600 dark:text-gray-400'}`}
          >
            <User className="w-5 h-5" />
            Mi Perfil
          </button>

          {(userRole === 'OWNER' || userRole === 'SUPER_ADMIN') && (
            <button 
              onClick={() => setActiveTab('users')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-2xl font-bold transition-all ${activeTab === 'users' ? 'bg-blue-600 text-white shadow-lg' : 'hover:bg-gray-100 dark:hover:bg-slate-800 text-gray-600 dark:text-gray-400'}`}
            >
              <Users className="w-5 h-5" />
              Empresa / Usuarios
            </button>
          )}

          <button 
            onClick={() => setActiveTab('ticket')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-2xl font-bold transition-all ${activeTab === 'ticket' ? 'bg-blue-600 text-white shadow-lg' : 'hover:bg-gray-100 dark:hover:bg-slate-800 text-gray-600 dark:text-gray-400'}`}
          >
            <Printer className="w-5 h-5" />
            Formato Ticket
          </button>
        </div>

        {/* Content Area */}
        <div className="flex-1 bg-white dark:bg-slate-900 rounded-3xl p-6 md:p-8 border border-gray-100 dark:border-slate-800 shadow-sm">
          
          {activeTab === 'business' && (
            <div className="animate-in fade-in duration-300">
              <h3 className="text-xl font-bold text-gray-900 dark:text-white mb-6 flex items-center gap-2">
                <Store className="w-6 h-6 text-blue-500" />
                Información del Negocio
              </h3>
              
              <div className="space-y-6">
                <div>
                  <label className="block text-sm font-bold text-gray-700 dark:text-gray-300 mb-2">Nombre de la Tienda</label>
                  <input 
                    type="text" 
                    value={tenantData.name}
                    onChange={(e) => setTenantData({...tenantData, name: e.target.value})}
                    className="w-full bg-gray-50 dark:bg-slate-800 border-0 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 transition-all font-bold dark:text-white"
                  />
                </div>

                <div>
                  <label className="block text-sm font-bold text-gray-700 dark:text-gray-300 mb-2">NIT / RUT</label>
                  <input 
                    type="text" 
                    placeholder="Ej. 901.234.567-1"
                    value={tenantData.rutNit}
                    onChange={(e) => setTenantData({...tenantData, rutNit: e.target.value})}
                    className="w-full bg-gray-50 dark:bg-slate-800 border-0 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 transition-all font-bold dark:text-white"
                  />
                </div>
                
                <div>
                  <label className="block text-sm font-bold text-gray-700 dark:text-gray-300 mb-2">Teléfono de Contacto</label>
                  <div className="relative">
                    <Phone className="absolute left-3 top-3.5 w-5 h-5 text-gray-400" />
                    <input 
                      type="text" 
                      value={tenantData.phone}
                      onChange={(e) => setTenantData({...tenantData, phone: e.target.value})}
                      className="w-full bg-gray-50 dark:bg-slate-800 border-0 rounded-xl pl-10 pr-4 py-3 focus:ring-2 focus:ring-blue-500 transition-all font-bold dark:text-white"
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-bold text-gray-700 dark:text-gray-300 mb-2">Ubicación / Ciudad</label>
                  <div className="relative">
                    <MapPin className="absolute left-3 top-3.5 w-5 h-5 text-gray-400" />
                    <input 
                      type="text" 
                      value={tenantData.location}
                      onChange={(e) => setTenantData({...tenantData, location: e.target.value})}
                      className="w-full bg-gray-50 dark:bg-slate-800 border-0 rounded-xl pl-10 pr-4 py-3 focus:ring-2 focus:ring-blue-500 transition-all font-bold dark:text-white"
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-bold text-gray-700 dark:text-gray-300 mb-2">Dirección Local</label>
                  <div className="relative">
                    <MapPin className="absolute left-3 top-3.5 w-5 h-5 text-gray-400" />
                    <input 
                      type="text" 
                      placeholder="Ej. Calle 10 # 5-20"
                      value={tenantData.address}
                      onChange={(e) => setTenantData({...tenantData, address: e.target.value})}
                      className="w-full bg-gray-50 dark:bg-slate-800 border-0 rounded-xl pl-10 pr-4 py-3 focus:ring-2 focus:ring-blue-500 transition-all font-bold dark:text-white"
                    />
                  </div>
                </div>

                {/* Modules section */}
                <div className="border-t border-gray-100 dark:border-slate-800 pt-6">
                  <h4 className="text-sm font-black text-gray-700 dark:text-gray-300 mb-1 flex items-center gap-2">
                    <ToggleRight className="w-5 h-5 text-blue-500" />
                    Módulos Activos del Negocio
                  </h4>
                  <p className="text-xs text-gray-400 dark:text-gray-500 mb-4">Activa o desactiva las secciones que necesita tu negocio. El menú lateral se actualizará al guardar.</p>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-2">
                    {ALL_MODULES.map(mod => (
                      <button
                        key={mod.id}
                        type="button"
                        onClick={() => toggleModule(mod.id)}
                        className={`flex items-center gap-3 text-left p-3 rounded-xl border-2 transition-all ${activeModules.includes(mod.id) ? 'border-blue-500 bg-blue-50 dark:bg-blue-500/10' : 'border-gray-100 dark:border-slate-800 hover:border-gray-200 dark:hover:border-slate-700'}`}
                      >
                        <div className={`w-10 h-10 rounded-xl flex items-center justify-center shrink-0 transition-colors ${activeModules.includes(mod.id) ? 'bg-blue-600 text-white' : 'bg-gray-100 dark:bg-slate-800 text-gray-400'}`}>
                          {activeModules.includes(mod.id) 
                            ? <ToggleRight className="w-5 h-5" />
                            : <ToggleLeft className="w-5 h-5" />
                          }
                        </div>
                        <div>
                          <p className={`text-sm font-black ${activeModules.includes(mod.id) ? 'text-blue-700 dark:text-blue-400' : 'text-gray-600 dark:text-gray-400'}`}>{mod.name}</p>
                          <p className="text-[10px] text-gray-400 font-medium leading-tight">{mod.description}</p>
                        </div>
                      </button>
                    ))}
                  </div>
                </div>

                {/* Maintenance Section */}
                <div className="border-t border-gray-100 dark:border-slate-800 pt-6">
                  <h4 className="text-sm font-black text-gray-700 dark:text-gray-300 mb-1 flex items-center gap-2">
                    <Edit2 className="w-5 h-5 text-orange-500" />
                    Herramientas de Mantenimiento
                  </h4>
                  <p className="text-xs text-gray-400 dark:text-gray-500 mb-4">Usa estas herramientas para corregir problemas de integridad o errores de datos.</p>
                  
                  <div className="flex flex-wrap gap-3">
                    <button 
                      onClick={handleCleanupDuplicates}
                      disabled={isCleaning}
                      className="bg-orange-50 dark:bg-orange-900/20 text-orange-700 dark:text-orange-400 px-4 py-3 rounded-xl text-sm font-bold border border-orange-200 dark:border-orange-800/50 hover:bg-orange-100 transition-all flex items-center gap-2 disabled:opacity-50"
