                      <tr key={u.id}>
                        <td className="px-6 py-4 font-bold text-gray-900 dark:text-white uppercase">{u.name}</td>
                        <td className="px-6 py-4 text-gray-500">{u.email}</td>
                        <td className="px-6 py-4">
