                <label className="flex items-center gap-3 p-4 bg-rose-500/5 rounded-2xl border border-rose-500/20 cursor-pointer hover:bg-rose-500/10 transition-all col-span-2">
                  <input 
                    type="checkbox" 
                    className="w-5 h-5 rounded border-rose-900 bg-gray-800 text-rose-600 focus:ring-rose-500"
                    checked={resetOptions.cleanSupplierInvoices} 
                    onChange={e => setResetOptions({...resetOptions, cleanSupplierInvoices: e.target.checked})}
                  />
                  <div>
                    <p className="text-sm font-bold text-rose-500">Limpiar Facturas de Proveedores (Gastos/Costos)</p>
                    <p className="text-[10px] text-rose-700 uppercase font-black tracking-tight">¡CUIDADO! Esta opción borra todos los gastos. Usar solo si es estrictamente necesario.</p>
                  </div>
                </label>
              </div>

              <div className="space-y-6">
                <div>
                  <label className="block text-[10px] font-black uppercase tracking-[0.2em] text-gray-500 mb-4 text-center">Escriba para confirmar ejecución: <span className="text-rose-500">REINICIAR_SISTEMA_GLOBAL</span></label>
                  <input 
                    type="text" 
                    value={adminResetConfirmText}
                    onChange={(e) => setAdminResetConfirmText(e.target.value)}
                    placeholder="Frase de seguridad obligatoria"
                    className="w-full bg-white/5 border border-white/5 rounded-3xl px-8 py-5 focus:ring-2 focus:ring-rose-500/50 text-white font-black text-center text-xl tracking-tight transition-all"
                  />
                </div>
              </div>

              <div className="flex gap-4 mt-12 bg-white/5 -mx-10 -mb-10 p-8 border-t border-white/5">
                <button 
                  onClick={() => setIsMaintenanceModalOpen(false)}
                  className="flex-1 px-6 py-4 rounded-2xl font-black text-gray-400 hover:bg-white/5 transition-all text-xs uppercase tracking-widest"
                >
                  Mejor No, Cancelar
                </button>
                
                <button 
                  onClick={handleAdminCleanupDuplicates}
                  disabled={isCleaningData || isResettingData}
                  className="flex-1 bg-orange-600/20 hover:bg-orange-600/40 text-orange-400 border border-orange-500/20 px-6 py-4 rounded-2xl font-black transition-all text-xs uppercase tracking-widest disabled:opacity-50"
                >
                  {isCleaningData ? 'Limpiando...' : 'Limpiar Duplicados'}
                </button>

                <button 
                  onClick={handleAdminResetData}
                  disabled={isResettingData || isCleaningData || adminResetConfirmText !== 'REINICIAR_SISTEMA_GLOBAL' || Object.values(resetOptions).every(v => !v)}
                  className="flex-[2] bg-rose-600 hover:bg-rose-700 text-white px-6 py-4 rounded-2xl font-black shadow-2xl shadow-rose-600/30 transition-all text-sm uppercase tracking-widest disabled:bg-gray-800 disabled:text-gray-600 disabled:shadow-none"
                >
                  {isResettingData ? 'VACIANDO BASE DE DATOS...' : 'EJECUTAR REINICIO'}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Modules Configuration Modal */}
      {isModulesModalOpen && selectedTenantForModules && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-50 flex items-center justify-center p-4">
          <div className="bg-[#0a0a1a] border border-white/10 w-full max-w-xl rounded-[40px] p-10 shadow-3xl animate-in zoom-in-95 duration-200">
            <div className="flex items-center gap-4 mb-2">
              <div className="w-12 h-12 bg-blue-500/20 rounded-2xl flex items-center justify-center">
                <ToggleRight className="w-7 h-7 text-blue-400" />
              </div>
              <div>
                <h3 className="text-2xl font-black text-white">Módulos del Negocio</h3>
                <p className="text-[10px] font-bold uppercase tracking-widest text-gray-500">{selectedTenantForModules.name}</p>
              </div>
            </div>
            <p className="text-gray-500 text-sm font-medium mb-6">Activa o desactiva las funciones que este negocio puede usar. El menú lateral del negocio se actualizará en el próximo login.</p>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mb-8">
              {ALL_MODULES.map(mod => {
                const active = editingModules.includes(mod.id);
                return (
                  <button
                    key={mod.id}
                    onClick={() => setEditingModules(prev => active ? prev.filter(m => m !== mod.id) : [...prev, mod.id])}
                    className={`flex items-center gap-3 p-3 rounded-2xl border-2 transition-all text-left ${
                      active ? 'border-blue-500 bg-blue-500/10' : 'border-white/5 hover:border-white/10'
                    }`}
                  >
                    <div className={`w-9 h-9 rounded-xl flex items-center justify-center shrink-0 transition-colors ${
                      active ? 'bg-blue-600 text-white' : 'bg-white/5 text-gray-600'
                    }`}>
                      {active ? <ToggleRight className="w-5 h-5" /> : <ToggleLeft className="w-5 h-5" />}
                    </div>
                    <span className={`text-sm font-bold ${
                      active ? 'text-blue-400' : 'text-gray-500'
                    }`}>{mod.name}</span>
                  </button>
                );
              })}
            </div>

            <div className="flex gap-4">
              <button 
                onClick={() => setIsModulesModalOpen(false)}
                className="flex-1 px-6 py-4 rounded-2xl font-black text-gray-500 hover:bg-white/5 transition-all text-sm uppercase tracking-widest"
              >
                Cancelar
              </button>
              <button 
                onClick={handleSaveModules}
                disabled={isSavingModules || editingModules.length === 0}
                className="flex-[2] bg-blue-600 hover:bg-blue-700 text-white px-6 py-4 rounded-2xl font-black shadow-xl shadow-blue-500/20 transition-all text-sm uppercase tracking-widest disabled:bg-gray-800 disabled:text-gray-600"
              >
                {isSavingModules ? 'Guardando...' : 'Guardar Módulos'}
              </button>
            </div>
          </div>
        </div>
      )}

    </div>
  );
}

'use client';
import { useState, useEffect } from 'react';
import { 
  Database, 
  Download, 
  Trash2, 
  RefreshCw, 
  Calendar, 
  HardDrive,
  Loader2,
  FileArchive,
  AlertCircle
} from 'lucide-react';

interface Backup {
  name: string;
  size: number;
  lastModified: string;
}

export default function BackupsManager() {
  const [backups, setBackups] = useState<Backup[]>([]);
  const [loading, setLoading] = useState(true);
  const [creating, setCreating] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fetchBackups = async () => {
    try {
      setLoading(true);
      const token = localStorage.getItem('access_token');
      const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/backups`, {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      if (!response.ok) throw new Error('Error al obtener respaldos');
      const data = await response.json();
      setBackups(data);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Error desconocido');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchBackups();
  }, []);

  const handleCreateBackup = async () => {
    try {
      setCreating(true);
      const token = localStorage.getItem('access_token');
      const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/backups`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      if (!response.ok) throw new Error('Error al crear respaldo');
      alert('Respaldo creado con éxito');
      fetchBackups();
    } catch (err) {
      alert(err instanceof Error ? err.message : 'Error al crear respaldo');
    } finally {
      setCreating(false);
    }
  };

  const handleDownload = async (filename: string) => {
    try {
      const token = localStorage.getItem('access_token');
      const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/backups/${filename}/download`, {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      const data = await response.json();
      window.open(data.url, '_blank');
    } catch (err) {
      alert('Error al descargar');
    }
  };

  const handleDelete = async (filename: string) => {
    if (!confirm('¿Está seguro de que desea eliminar este respaldo?')) return;
    try {
      const token = localStorage.getItem('access_token');
      const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/backups/${filename}`, {
        method: 'DELETE',
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      if (response.ok) {
        fetchBackups();
      }
    } catch (err) {
      alert('Error al eliminar');
    }
  };

  const formatSize = (bytes: number) => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-4xl font-black text-white flex items-center gap-3 tracking-tight">
            <Database className="w-10 h-10 text-emerald-500" />
            Respaldos de Seguridad
          </h1>
          <p className="text-slate-400 mt-2 font-medium italic">Gestión de copias de seguridad de la base de datos (PGSQL)</p>
        </div>
        <button
          onClick={handleCreateBackup}
          disabled={creating}
          className="bg-emerald-600 hover:bg-emerald-500 text-white px-8 py-4 rounded-2xl font-bold flex items-center gap-2 shadow-lg shadow-emerald-900/20 transition-all active:scale-95 disabled:opacity-50"
        >
          {creating ? <Loader2 className="w-5 h-5 animate-spin" /> : <RefreshCw className="w-5 h-5" />}
          {creating ? 'Generando...' : 'Generar Respaldo Ahora'}
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white/5 border border-white/5 p-6 rounded-3xl shadow-xl">
          <div className="flex items-center gap-3 mb-2">
            <Calendar className="w-5 h-5 text-blue-400" />
            <span className="text-slate-400 font-bold text-sm uppercase">Frecuencia</span>
          </div>
          <p className="text-xl font-bold text-white">Diaria (Medianoche)</p>
        </div>
        <div className="bg-white/5 border border-white/5 p-6 rounded-3xl shadow-xl">
          <div className="flex items-center gap-3 mb-2">
            <HardDrive className="w-5 h-5 text-purple-400" />
            <span className="text-slate-400 font-bold text-sm uppercase">Destino</span>
          </div>
          <p className="text-xl font-bold text-white">Minio S3 Local</p>
        </div>
        <div className="bg-white/5 border border-white/5 p-6 rounded-3xl shadow-xl">
          <div className="flex items-center gap-3 mb-2">
            <FileArchive className="w-5 h-5 text-orange-400" />
            <span className="text-slate-400 font-bold text-sm uppercase">Total Archivos</span>
          </div>
          <p className="text-xl font-bold text-white">{backups.length} Respaldos</p>
        </div>
      </div>

      <div className="bg-white/5 border border-white/5 rounded-[40px] overflow-hidden shadow-2xl">
        <div className="px-8 py-6 border-b border-white/5 bg-white/5 flex items-center justify-between">
          <h2 className="text-xl font-bold text-white">Historial de Respaldos</h2>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="border-b border-white/5 bg-white/5">
                <th className="px-8 py-6 text-[10px] font-black uppercase tracking-widest text-gray-500">Nombre del Archivo</th>
                <th className="px-8 py-6 text-[10px] font-black uppercase tracking-widest text-gray-500">Fecha</th>
                <th className="px-8 py-6 text-[10px] font-black uppercase tracking-widest text-gray-500">Tamaño</th>
                <th className="px-8 py-6 text-[10px] font-black uppercase tracking-widest text-gray-500 text-right">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-white/5">
              {loading ? (
                <tr>
                  <td colSpan={4} className="px-8 py-12 text-center text-slate-500">
                    <Loader2 className="w-8 h-8 animate-spin mx-auto mb-2" />
                    Cargando respaldos...
                  </td>
                </tr>
              ) : backups.length === 0 ? (
                <tr>
                  <td colSpan={4} className="px-8 py-12 text-center text-slate-500 italic">
                    {error || 'No se han generado respaldos todavía.'}
                  </td>
                </tr>
              ) : (
                backups.map((backup) => (
                  <tr key={backup.name} className="hover:bg-white/[0.02] transition-colors group">
                    <td className="px-8 py-6">
                      <span className="text-sm font-bold text-white">{backup.name}</span>
                    </td>
                    <td className="px-8 py-6">
                      <span className="text-sm text-slate-400">{new Date().toLocaleString('es-CO')}</span>
                    </td>
                    <td className="px-8 py-6">
                      <span className="text-sm text-slate-400">{formatSize(backup.size)}</span>
                    </td>
                    <td className="px-8 py-6 text-right flex items-center justify-end gap-2">
                      <button
                        onClick={() => handleDownload(backup.name)}
                        className="p-2 hover:bg-blue-500/20 text-blue-400 rounded-xl transition-all"
                        title="Descargar"
                      >
                        <Download className="w-5 h-5" />
                      </button>
                      <button
                        onClick={() => handleDelete(backup.name)}
                        className="p-2 hover:bg-red-500/20 text-red-400 rounded-xl transition-all"
                        title="Eliminar"
                      >
                        <Trash2 className="w-5 h-5" />
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      <div className="bg-blue-900/20 border border-blue-500/30 p-8 rounded-[40px] flex items-start gap-4 shadow-xl">
        <AlertCircle className="w-6 h-6 text-blue-400 shrink-0 mt-1" />
        <div className="space-y-1">
          <p className="text-sm font-bold text-blue-100 uppercase tracking-widest">Información Global</p>
          <p className="text-sm text-blue-200/70 leading-relaxed font-medium">
            Este módulo genera una copia completa de la base de datos de **Tiendeo POS**, incluyendo todos los negocios registrados en la red. 
            Los respaldos automáticos se realizan todos los días a las 00:00 (hora del servidor).
          </p>
        </div>
      </div>
    </div>
  );
}

'use client';
import { useState, useEffect } from 'react';
import { X, DollarSign, Calendar, FileText, Loader2, ArrowDownCircle, History, User } from 'lucide-react';
import { useOfflineStore } from '@/store/useOfflineStore';
import { formatCurrency, parseCurrency } from '@/utils/formatters';


interface AbonoModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: () => void;
  credit: any;
}

export default function AbonoModal({ isOpen, onClose, onSave, credit }: AbonoModalProps) {
  const { isOnline, addPendingPayment, rawCredits, setCache } = useOfflineStore();
  const [amount, setAmount] = useState<string>('');
  const [notes, setNotes] = useState('');
  const [loading, setLoading] = useState(false);
  const [history, setHistory] = useState<any[]>([]);
  const [loadingHistory, setLoadingHistory] = useState(false);

  useEffect(() => {
    if (isOpen && credit) {
      setAmount('');
      setNotes('');
      fetchHistory();
    }
  }, [isOpen, credit]);

  const fetchHistory = async () => {
    if (!credit) return;
    setLoadingHistory(true);
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/credits/${credit.id}/history`, {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      if (res.ok) {
        const data = await res.json();
        setHistory(data.payments || []);
      }
    } catch (error) {
      console.error(error);
    } finally {
      setLoadingHistory(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const amountVal = parseCurrency(amount);
    if (!amount || amountVal <= 0) return;
    
    setLoading(true);
    try {
      if (!isOnline) {
        const uuid = crypto.randomUUID();
        const localId = `temp-pay-${uuid}`;
        
        const newPayment = {
          localId,
          creditSaleId: credit.id, // Puede ser un ID real o temp-prod-...
          amount: amountVal,
          notes,
          paymentDate: new Date().toISOString(),
          paymentMethod: 'efectivo'
        };
        
        addPendingPayment(newPayment);

        // Actualizar el saldo localmente en el cache para feedback inmediato
        const updatedCredits = rawCredits.map((c: any) => {
          if (c.id === credit.id) {
            return {
              ...c,
              remainingAmount: (Number(c.remainingAmount || c.amount) - amountVal).toString(),
              status: 'PARTIAL'
            };
          }
          return c;
        });
        setCache({ rawCredits: updatedCredits });

        onSave();
        onClose();
        return;
      }

      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/credits/${credit.id}/partial-payment`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify({ 
          amount: amountVal,
          notes 
        })
      });

      if (res.ok) {
        onSave();
        onClose();
      } else {
        const err = await res.json();
        alert('Error: ' + (err.message || 'No se pudo registrar el abono'));
      }
    } catch (error) {
      console.error(error);
      alert('Error de conexión');
    } finally {
      setLoading(false);
    }
  };

  if (!isOpen || !credit) return null;

  const remaining = Number(credit.remainingAmount || credit.amount);

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-950/60 backdrop-blur-md animate-in fade-in duration-300">
      <div className="bg-white dark:bg-slate-900 w-full max-w-4xl rounded-[3rem] shadow-2xl border border-gray-100 dark:border-slate-800 overflow-hidden flex flex-col md:flex-row h-full max-h-[85vh] animate-in zoom-in-95 duration-300">
        
        {/* Left Side: Abono Form */}
        <div className="w-full md:w-1/2 p-10 flex flex-col justify-center border-b md:border-b-0 md:border-r border-gray-100 dark:border-slate-800 bg-gray-50/50 dark:bg-slate-950/50">
          <div className="mb-8">
            <h3 className="text-2xl font-black text-gray-900 dark:text-white flex items-center gap-3">
              <div className="bg-blue-600 p-3 rounded-2xl shadow-xl shadow-blue-600/20">
                <ArrowDownCircle className="w-6 h-6 text-white" />
              </div>
              Registrar Abono
            </h3>
            <div className="mt-6 p-6 bg-white dark:bg-slate-900 rounded-[2rem] border border-gray-200 dark:border-slate-800 shadow-sm">
                <p className="text-xs font-black text-gray-400 dark:text-slate-500 uppercase tracking-widest mb-1">Saldo Pendiente</p>
                <p className="text-4xl font-black text-rose-600 dark:text-rose-500">${formatCurrency(remaining)}</p>
                <div className="mt-4 flex flex-col gap-2">
                   <div className="flex items-center gap-2 text-sm font-bold text-gray-600 dark:text-slate-400">
                      <User className="w-4 h-4 text-blue-500" />
                      {credit.customerName || 'Cliente Genérico'}
                   </div>
                   <div className="flex items-center gap-2 text-[10px] font-black text-blue-500 bg-blue-500/10 px-2 py-1 rounded-lg w-fit">
                      <FileText className="w-3 h-3" />
                      FACTURA: {credit.sale?.invoiceNumber || 'S/N'}
                   </div>
                </div>
            </div>
          </div>

          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="space-y-2">
              <label className="text-xs font-black text-slate-500 uppercase tracking-widest ml-4">Monto a abonar</label>
              <div className="relative">
                <DollarSign className="absolute left-6 top-5 w-6 h-6 text-blue-600" />
                <input
                  required
                  type="text"
                  placeholder="0"
                  className="w-full bg-white dark:bg-slate-900 border-2 border-slate-200 dark:border-slate-800 rounded-3xl pl-16 pr-6 py-5 text-2xl font-black text-gray-900 dark:text-white focus:border-blue-500 outline-none transition-all"
                  value={formatCurrency(amount)}
                  onChange={(e) => setAmount(parseCurrency(e.target.value).toString())}
                  autoFocus
                />
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-xs font-black text-slate-500 uppercase tracking-widest ml-4">Nota / Observación</label>
              <div className="relative">
                <FileText className="absolute left-6 top-5 w-6 h-6 text-gray-400" />
                <textarea
                  placeholder="Ej: Pago en efectivo parte de la deuda..."
                  rows={2}
                  className="w-full bg-white dark:bg-slate-900 border-2 border-slate-200 dark:border-slate-800 rounded-3xl pl-16 pr-6 py-5 text-lg font-bold text-gray-900 dark:text-white focus:border-blue-500 outline-none transition-all resize-none"
                  value={notes}
                  onChange={(e) => setNotes(e.target.value)}
                />
              </div>
            </div>

            <button
              disabled={loading}
              type="submit"
              className="w-full bg-blue-600 hover:bg-blue-500 text-white py-5 rounded-3xl font-black text-xl shadow-2xl shadow-blue-600/30 active:scale-[0.98] transition-all disabled:opacity-50 flex items-center justify-center gap-3"
            >
              {loading ? <Loader2 className="w-6 h-6 animate-spin" /> : <>Confirmar Abono</>}
            </button>
          </form>
        </div>

        {/* Right Side: History */}
        <div className="w-full md:w-1/2 p-10 flex flex-col overflow-hidden">
          <div className="flex items-center justify-between mb-8">
            <h3 className="text-xl font-black text-gray-900 dark:text-white flex items-center gap-3">
              <History className="w-6 h-6 text-slate-400" />
              Historial de Pagos
            </h3>
            <button onClick={onClose} className="p-2 hover:bg-gray-100 dark:hover:bg-slate-800 rounded-full transition-colors md:hidden">
                <X className="w-6 h-6 text-gray-400" />
            </button>
          </div>

          <div className="flex-1 overflow-y-auto pr-2 space-y-4 custom-scrollbar">
            {loadingHistory ? (
              <div className="flex flex-col items-center justify-center h-40 opacity-50">
                <Loader2 className="w-8 h-8 animate-spin mb-2" />
                <p className="text-xs font-bold uppercase tracking-widest">Cargando historial...</p>
              </div>
            ) : history.length === 0 ? (
              <div className="border-2 border-dashed border-gray-100 dark:border-slate-800 rounded-[2.5rem] p-12 text-center">
                <p className="text-gray-400 dark:text-slate-500 font-bold">No hay abonos registrados para esta deuda.</p>
              </div>
            ) : (
              history.map((h) => (
                <div key={h.id} className="p-6 bg-gray-50 dark:bg-slate-800/50 rounded-3xl border border-gray-100 dark:border-slate-800 transition-all hover:shadow-lg">
                  <div className="flex justify-between items-start mb-2">
                    <p className="text-xl font-black text-green-600 dark:text-green-500">+ ${formatCurrency(h.amount)}</p>
                    <div className="flex items-center gap-1.5 px-3 py-1 bg-white dark:bg-slate-900 rounded-full border border-gray-200 dark:border-slate-800 shadow-sm">
                      <Calendar className="w-3 h-3 text-blue-500" />
                      <span className="text-[10px] font-black text-gray-500 dark:text-slate-400">
                        {new Date(h.paymentDate).toLocaleDateString()}
                      </span>
                    </div>
                  </div>
                  {h.notes && (
                    <p className="text-sm font-medium text-gray-600 dark:text-slate-400 italic">&quot;{h.notes}&quot;</p>
                  )}
                </div>
              ))
            )}
          </div>

          <button 
            onClick={onClose} 
            className="hidden md:flex mt-8 w-full bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-600 dark:text-slate-300 py-4 rounded-2xl font-black text-sm uppercase tracking-widest transition-all"
          >
            Cerrar Ventana
          </button>
        </div>
      </div>
    </div>
  );
}

'use client';
import { useState, useEffect, useCallback } from 'react';
import { 
  X, 
  History, 
  FileText, 
  DollarSign, 
  Calendar, 
  Loader2, 
  Download, 
  ArrowUpRight,
  TrendingDown,
  Clock
} from 'lucide-react';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';
import { formatCurrency as curr } from '@/utils/formatters';


interface Payment {
  id: string;
  amount: number;
  paymentDate: string;
  notes?: string;
}

interface CreditSale {
  id: string;
  amount: number;
  remainingAmount: number;
  status: string;
  createdAt: string;
  sale?: {
    invoiceNumber?: string;
  };
  payments?: Payment[];
}

interface CustomerHistory {
  id: string;
  name: string;
  idNumber?: string;
  phone?: string;
  email?: string;
  address?: string;
  creditSales?: CreditSale[];
}

interface CustomerHistoryModalProps {
  isOpen: boolean;
  onClose: () => void;
  customerId: string;
  customerName: string;
}

export default function CustomerHistoryModal({ isOpen, onClose, customerId, customerName }: CustomerHistoryModalProps) {
  const [loading, setLoading] = useState(true);
  const [history, setHistory] = useState<CustomerHistory | null>(null);

  const fetchHistory = useCallback(async () => {
    if (!customerId) return;
    setLoading(true);
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/customers/${customerId}`, {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      if (res.ok) {
        const data = await res.json();
        setHistory(data);
      }
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  }, [customerId]);

  useEffect(() => {
    if (isOpen && customerId) {
      fetchHistory();
    }
  }, [isOpen, customerId, fetchHistory]);

  const generatePDF = () => {
    if (!history) return;

    const doc = new jsPDF();
    
    // Header
    doc.setFillColor(30, 41, 59); // Dark slate
    doc.rect(0, 0, 210, 40, 'F');
    
    doc.setTextColor(255, 255, 255);
    doc.setFontSize(22);
    doc.text('ESTADO DE CUENTA DE CLIENTE', 14, 25);
    
    doc.setFontSize(10);
    doc.text(`TIENDEO POS - Software de Gestión`, 150, 25);
    doc.text(`Fecha: ${new Date().toLocaleString('es-CO')}`, 150, 32);

    // Customer Info
    doc.setTextColor(30, 41, 59);
    doc.setFontSize(14);
    doc.text('INFORMACIÓN DEL CLIENTE', 14, 50);
    doc.setFontSize(10);
    doc.text(`Nombre: ${history.name}`, 14, 58);
    doc.text(`ID/NIT: ${history.idNumber || 'N/A'}`, 14, 64);
    doc.text(`Teléfono: ${history.phone || 'N/A'}`, 14, 70);
    doc.text(`Email: ${history.email || 'N/A'}`, 14, 76);

    // Summary Box
    doc.setDrawColor(226, 232, 240);
    doc.setFillColor(248, 250, 252);
    doc.roundedRect(140, 45, 55, 35, 3, 3, 'FD');
    
    doc.setTextColor(100, 116, 139);
    doc.text('SALDO TOTAL PENDIENTE', 145, 55);
    doc.setTextColor(225, 29, 72); // Rose 600
    doc.setFontSize(16);
    const totalDebt = history.creditSales?.reduce((sum: number, cs: CreditSale) => sum + Number(cs.remainingAmount), 0) || 0;
    doc.text(`$${curr(totalDebt)}`, 145, 65);

    // Invoices Table
    doc.setTextColor(30, 41, 59);
    doc.setFontSize(12);
    doc.text('DETALLE DE FACTURAS A CRÉDITO', 14, 90);

    const invoiceData = history.creditSales?.map((cs: CreditSale) => [
      cs.sale?.invoiceNumber || 'S/N',
      new Date(cs.createdAt).toLocaleDateString(),
      `$${curr(cs.amount)}`,
      `$${curr(cs.remainingAmount)}`,
      cs.status === 'PAID' ? 'PAGADO' : cs.status === 'PARTIAL' ? 'ABONADO' : 'PENDIENTE'
    ]) || [];

    autoTable(doc, {
      startY: 95,
      head: [['Factura #', 'Fecha', 'Monto Original', 'Saldo Pendiente', 'Estado']],
      body: invoiceData,
      headStyles: { fillColor: [59, 130, 246] }, // Blue 500
      styles: { fontSize: 9 }
    });

    // Payments detail
    let currentY = (doc as any).lastAutoTable.finalY + 15;
    if (currentY > 250) {
      doc.addPage();
      currentY = 20;
    }

    doc.setFontSize(12);
    doc.text('HISTORIAL DE ABONOS RECIBIDOS', 14, currentY);
    
    const paymentData: any[] = [];
    history.creditSales?.forEach((cs: CreditSale) => {
      cs.payments?.forEach((p: Payment) => {
        paymentData.push([
          new Date(p.paymentDate).toLocaleDateString(),
          cs.sale?.invoiceNumber || 'S/N',
          `$${curr(p.amount)}`,
          p.notes || '-'
        ]);
      });
    });

    autoTable(doc, {
      startY: currentY + 5,
      head: [['Fecha Abono', 'Factura Ref.', 'Monto Abonado', 'Notas']],
      body: paymentData,
      headStyles: { fillColor: [16, 185, 129] }, // Emerald 500
      styles: { fontSize: 9 }
    });

    doc.save(`Estado_Cuenta_${history.name.replace(/\s+/g, '_')}.pdf`);
  };

  if (!isOpen) return null;

  const creditSales = history?.creditSales || [];
  const totalDebt = creditSales.reduce((sum: number, cs: CreditSale) => sum + Number(cs.remainingAmount), 0);

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-950/60 backdrop-blur-md animate-in fade-in duration-300">
      <div className="bg-white dark:bg-slate-900 w-full max-w-5xl rounded-[3rem] shadow-2xl border border-gray-100 dark:border-slate-800 overflow-hidden flex flex-col h-full max-h-[90vh] animate-in zoom-in-95 duration-300">
        
        {/* Header */}
        <div className="px-10 py-8 border-b border-gray-100 dark:border-slate-800 flex items-center justify-between bg-gray-50/50 dark:bg-slate-950/50">
          <div className="flex items-center gap-4">
            <div className="bg-blue-600 p-3 rounded-2xl shadow-xl shadow-blue-600/20">
              <History className="w-6 h-6 text-white" />
            </div>
            <div>
              <h3 className="text-2xl font-black text-gray-900 dark:text-white leading-none">Historial del Cliente</h3>
              <p className="text-gray-500 dark:text-slate-400 mt-1 font-bold">{customerName}</p>
            </div>
          </div>
          
          <div className="flex items-center gap-3">
            <button 
              onClick={generatePDF}
              disabled={loading || !history}
              className="bg-emerald-600 hover:bg-emerald-500 text-white px-6 py-3 rounded-2xl font-black flex items-center gap-2 shadow-lg shadow-emerald-600/20 transition-all active:scale-95 disabled:opacity-50"
            >
              <Download className="w-5 h-5" />
              Estado de Cuenta PDF
            </button>
            <button 
              onClick={onClose} 
              className="p-3 hover:bg-gray-200 dark:hover:bg-slate-800 rounded-2xl transition-all"
              title="Cerrar"
              aria-label="Cerrar modal"
            >
              <X className="w-6 h-6 text-gray-400" />
            </button>
          </div>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-10 space-y-8 custom-scrollbar">
          {loading ? (
            <div className="flex flex-col items-center justify-center py-20 opacity-50">
              <Loader2 className="w-12 h-12 text-blue-600 animate-spin mb-4" />
              <p className="font-black uppercase tracking-widest text-gray-500">Cargando información detallada...</p>
            </div>
          ) : (
            <>
              {/* Summary Cards */}
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div className="bg-rose-50 dark:bg-rose-900/20 p-6 rounded-[2.5rem] border border-rose-100 dark:border-rose-900/30">
                  <p className="text-[10px] font-black text-rose-400 dark:text-rose-500 uppercase tracking-widest mb-1">Deuda Total Pendiente</p>
                  <p className="text-3xl font-black text-rose-600 dark:text-rose-400">${curr(totalDebt)}</p>
                  <TrendingDown className="w-8 h-8 text-rose-200 dark:text-rose-900/50 absolute right-8 bottom-8" />
                </div>
                
                <div className="bg-blue-50 dark:bg-blue-900/20 p-6 rounded-[2.5rem] border border-blue-100 dark:border-blue-900/30">
                  <p className="text-[10px] font-black text-blue-400 dark:text-blue-500 uppercase tracking-widest mb-1">Facturas Pendientes</p>
                  <p className="text-3xl font-black text-blue-600 dark:text-blue-400">
                    {creditSales.filter((cs: CreditSale) => cs.status !== 'PAID').length}
                  </p>
                  <FileText className="w-8 h-8 text-blue-200 dark:text-blue-900/50 absolute right-8 bottom-8" />
                </div>

                <div className="bg-emerald-50 dark:bg-emerald-900/20 p-6 rounded-[2.5rem] border border-emerald-100 dark:border-emerald-900/30">
                  <p className="text-[10px] font-black text-emerald-400 dark:text-emerald-500 uppercase tracking-widest mb-1">Total Abonos Realizados</p>
                  <p className="text-3xl font-black text-emerald-600 dark:text-emerald-400">
                    {creditSales.reduce((acc: number, cs: CreditSale) => acc + (cs.payments?.length || 0), 0)}
                  </p>
                  <ArrowUpRight className="w-8 h-8 text-emerald-200 dark:text-emerald-900/50 absolute right-8 bottom-8" />
                </div>
              </div>

              {/* Detailed List */}
              <div className="space-y-6">
                <h4 className="text-xl font-black text-gray-900 dark:text-white flex items-center gap-3">
                  <FileText className="w-6 h-6 text-blue-500" />
                  Detalle de Facturas y Abonos
                </h4>
                
                <div className="space-y-4">
                  {creditSales.length === 0 ? (
                    <div className="py-20 text-center border-2 border-dashed border-gray-100 dark:border-slate-800 rounded-[3rem]">
                      <p className="text-gray-400 font-bold italic">Este cliente no tiene historial de créditos.</p>
                    </div>
                  ) : (
                    creditSales.map((cs: CreditSale) => (
                      <div key={cs.id} className="bg-white dark:bg-slate-900 border border-gray-100 dark:border-slate-800 rounded-[2.5rem] overflow-hidden hover:shadow-xl transition-all">
                        <div className="p-6 bg-gray-50/50 dark:bg-slate-950/50 border-b border-gray-100 dark:border-slate-800 flex flex-wrap items-center justify-between gap-4">
                          <div className="flex items-center gap-4">
                            <div className="bg-blue-100 dark:bg-blue-900/30 p-2 rounded-xl text-blue-600 dark:text-blue-400">
                              <FileText className="w-5 h-5" />
                            </div>
                            <div>
                              <p className="text-sm font-black text-gray-400 dark:text-slate-500 uppercase tracking-tighter">Factura No.</p>
                              <p className="text-xl font-black text-gray-900 dark:text-white">{cs.sale?.invoiceNumber || 'S/N'}</p>
                            </div>
                          </div>
                          
                          <div className="flex items-center gap-8">
                            <div className="text-center">
                              <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Monto Original</p>
                              <p className="text-lg font-black text-gray-600 dark:text-slate-300">${curr(cs.amount)}</p>
                            </div>
                            <div className="text-center">
                              <p className="text-[10px] font-black text-rose-400 uppercase tracking-widest">Saldo Pendiente</p>
                              <p className="text-2xl font-black text-rose-600 dark:text-rose-500">${curr(cs.remainingAmount)}</p>
                            </div>
                            <div className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase border ${
                              cs.status === 'PAID' ? 'bg-green-500/10 text-green-500 border-green-500/20' :
                              cs.status === 'PARTIAL' ? 'bg-blue-500/10 text-blue-500 border-blue-500/20' :
                              'bg-orange-500/10 text-orange-500 border-orange-500/20'
                            }`}>
                              {cs.status === 'PAID' ? 'Totalmente Pagada' : cs.status === 'PARTIAL' ? 'Abonos Pendientes' : 'Pendiente Total'}
                            </div>
                          </div>
                        </div>
                        
                        {/* Sub-table of payments */}
                        {cs.payments && cs.payments.length > 0 && (
                          <div className="p-6 bg-white dark:bg-slate-900">
                            <p className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-4 ml-2 flex items-center gap-2">
                              <Clock className="w-3.5 h-3.5" />
                              Historial de Abonos para esta Factura
                            </p>
                            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
                              {cs.payments.map((p: Payment) => (
                                <div key={p.id} className="p-4 bg-gray-50 dark:bg-slate-800/50 rounded-2xl border border-gray-100 dark:border-slate-800 flex items-center justify-between">
                                  <div>
                                    <p className="text-sm font-black text-emerald-600 dark:text-emerald-400">+ ${curr(p.amount)}</p>
                                    <div className="flex items-center gap-1.5 mt-0.5 opacity-60">
                                      <Calendar className="w-3 h-3" />
                                      <span className="text-[10px] font-bold">{new Date(p.paymentDate).toLocaleDateString()}</span>
                                    </div>
                                  </div>
                                  {p.notes && (
                                    <div title={p.notes} className="bg-gray-200 dark:bg-slate-700 p-1.5 rounded-lg cursor-help">
                                      <FileText className="w-4 h-4 text-gray-500 dark:text-slate-400" />
                                    </div>
                                  )}
                                </div>
                              ))}
                            </div>
                          </div>
                        )}
                      </div>
                    ))
                  )}
                </div>
              </div>
            </>
          )}
        </div>

        {/* Footer */}
        <div className="p-6 bg-gray-50 dark:bg-slate-950/50 border-t border-gray-100 dark:border-slate-800 flex justify-center">
           <p className="text-xs font-bold text-gray-400 dark:text-slate-500 uppercase tracking-widest flex items-center gap-2">
             <TrendingDown className="w-4 h-4" />
             Información sincronizada con el módulo de contabilidad y créditos
           </p>
        </div>
      </div>
    </div>
  );
}

'use client';
import { useState, useEffect } from 'react';
import { X, User, Phone, Mail, MapPin, CreditCard, Loader2, Banknote, ArrowDownCircle } from 'lucide-react';
import { useOfflineStore } from '@/store/useOfflineStore';
import AbonoModal from './AbonoModal';
import { formatCurrency, parseCurrency } from '@/utils/formatters';


interface CustomerModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: () => void;
  customer?: any;
}

export default function CustomerModal({ isOpen, onClose, onSave, customer }: CustomerModalProps) {
  const { isOnline, addPendingCustomer } = useOfflineStore();
  const [formData, setFormData] = useState({
    name: '',
    idNumber: '',
    phone: '',
    email: '',
    address: '',
    initialDebt: '',
  });
  const [loading, setLoading] = useState(false);
  const [debts, setDebts] = useState<any[]>([]);
  const [loadingDebts, setLoadingDebts] = useState(false);
  const [selectedCredit, setSelectedCredit] = useState<any>(null);
  const [isAbonoModalOpen, setIsAbonoModalOpen] = useState(false);
  const [processingId, setProcessingId] = useState<string | null>(null);

  useEffect(() => {
    if (customer) {
      setFormData({
        name: customer.name || '',
        idNumber: customer.idNumber || '',
        phone: customer.phone || '',
        email: customer.email || '',
        address: customer.address || '',
        initialDebt: '',
      });
      if (isOpen) fetchCustomerDebts();
    } else {
      setFormData({
        name: '',
        idNumber: '',
        phone: '',
        email: '',
        address: '',
        initialDebt: '',
      });
      setDebts([]);
    }
  }, [customer, isOpen]);

  const fetchCustomerDebts = async () => {
    if (!customer?.id) return;
    setLoadingDebts(true);
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/customers/${customer.id}`, {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      if (res.ok) {
        const data = await res.json();
        setDebts(data.creditSales || []);
      }
    } catch (error) {
      console.error(error);
    } finally {
      setLoadingDebts(false);
    }
  };

  const handlePay = async (creditId: string) => {
    if (!confirm('¿Confirmar que el cliente ha pagado esta factura totalmente en efectivo?')) return;
    
    setProcessingId(creditId);
    try {
      const token = localStorage.getItem('access_token');
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/sales/credits/${creditId}/pay`, {
        method: 'POST',
        headers: { Authorization: `Bearer ${token}` }
      });

      if (res.ok) {
        alert('Pago registrado correctamente.');
        fetchCustomerDebts();
        onSave(); // Refrescar lista principal también
      } else {
        alert('Error al procesar el pago');
      }
    } catch (e) {
      console.error(e);
      alert('Error de conexión');
    } finally {
      setProcessingId(null);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      if (!isOnline && !customer) {
        // MODO OFFLINE - CREACIÓN
        const uuid = crypto.randomUUID();
        const localId = `temp-cust-${uuid}`;
        const newCustomer = {
          ...formData,
          id: localId,
          localId,
          totalDebt: 0,
          pendingInvoices: 0
        };
        addPendingCustomer(newCustomer);
        onSave();
        onClose();
        return;
      }

      if (!isOnline && customer) {
        alert('No se pueden editar clientes existentes en modo offline todavía.');
        return;
      }

      const token = localStorage.getItem('access_token');
      const url = customer 
        ? `${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/customers/${customer.id}`
        : `${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/customers`;
      
      const res = await fetch(url, {
        method: customer ? 'PATCH' : 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify(formData)
      });

      if (res.ok) {
        onSave();
        onClose();
      } else {
        alert('Error al guardar el cliente');
      }
    } catch (error) {
      console.error(error);
      alert('Error de conexión');
    } finally {
      setLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-950/40 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white dark:bg-slate-900 w-full max-w-2xl rounded-[2.5rem] shadow-2xl border border-gray-100 dark:border-slate-800 overflow-hidden animate-in zoom-in-95 duration-200 max-h-[95vh] flex flex-col">
        <div className="px-8 py-6 border-b border-gray-100 dark:border-slate-800 flex items-center justify-between bg-gray-50/50 dark:bg-slate-900/50 shrink-0">
          <h3 className="text-xl font-black text-gray-900 dark:text-white flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-xl shadow-lg shadow-blue-600/20">
              <User className="w-5 h-5 text-white" />
            </div>
            {customer ? 'Editar Cliente' : 'Nuevo Cliente'}
          </h3>
          <button onClick={onClose} className="p-2 hover:bg-gray-100 dark:hover:bg-slate-800 rounded-full transition-colors">
            <X className="w-6 h-6 text-gray-400" />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto custom-scrollbar">
          <form id="customer-form" onSubmit={handleSubmit} className="p-8 space-y-6">
            <div className="space-y-4">
              <div className="relative">
                <User className="absolute left-4 top-3.5 w-5 h-5 text-gray-400" />
                <input
                  required
                  type="text"
                  placeholder="Nombre Completo"
                  className="w-full bg-white text-black border border-gray-200 rounded-2xl pl-12 pr-4 py-3.5 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all font-bold"
                  value={formData.name}
                  onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                />
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="relative">
                  <CreditCard className="absolute left-4 top-3.5 w-5 h-5 text-gray-400" />
                  <input
