'use client';
import { useEffect, useState } from 'react';
import { useOfflineStore } from '@/store/useOfflineStore';

export default function SyncManager() {
  const { 
    isOnline, 
    pendingSales, 
    pendingProducts, 
    pendingCategories,
    pendingCustomers,
    pendingPayments,
    removePendingSale,
    removePendingProduct,
    removePendingCategory,
    removePendingCustomer,
    removePendingPayment,
    clearPendingSales,
    clearPendingProducts,
    clearPendingCategories
  } = useOfflineStore();

  const [isSyncing, setIsSyncing] = useState(false);

  useEffect(() => {
    const handleManualSync = () => {
      if (isOnline) {
        performSync();
      } else {
        alert('No se puede sincronizar sin conexión a internet.');
      }
    };

    window.addEventListener('manual-sync', handleManualSync);
    return () => window.removeEventListener('manual-sync', handleManualSync);
  }, [isOnline, pendingSales, pendingProducts, pendingCategories, pendingCustomers, pendingPayments]);

  const performSync = async () => {
    if (isSyncing) return;
    
    const totalItems = pendingSales.length + pendingProducts.length + pendingCategories.length + pendingCustomers.length + pendingPayments.length;
    if (totalItems === 0) return;

    setIsSyncing(true);
    console.log('Iniciando sincronización manual...');

    // Resumen de resultados
    const results = {
      success: [] as string[],
      failed: [] as string[]
    };

    try {
      const token = localStorage.getItem('access_token');
      const apiUrl = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001';

      // Mapeos para traducir IDs temporales a reales
      const categoryIdMapping: Record<string, string> = {};
      const customerIdMapping: Record<string, string> = {};
      const salesCreditIdMapping: Record<string, string> = {};

      // 1. Sincronizar Categorías
      for (const cat of pendingCategories) {
        try {
          const res = await fetch(`${apiUrl}/categories`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
            body: JSON.stringify({ name: cat.name, localId: cat.localId })
          });
          if (res.ok) {
            const savedCat = await res.json();
            if (cat.localId && savedCat.id) categoryIdMapping[cat.localId] = savedCat.id;
            removePendingCategory(cat.localId);
            results.success.push(`Categoría: ${cat.name}`);
          } else {
            results.failed.push(`Categoría: ${cat.name} (Error servidor)`);
          }
        } catch (e) { 
          results.failed.push(`Categoría: ${cat.name} (Error conexión)`);
          console.error('Error sincronizando categoría', e); 
        }
      }

      // 2. Sincronizar Productos
      if (pendingProducts.length > 0) {
        try {
          const productsToSync = pendingProducts.map(p => ({
              ...p,
              categoryId: p.categoryId && categoryIdMapping[p.categoryId] ? categoryIdMapping[p.categoryId] : (p.categoryId?.startsWith('temp-') ? null : p.categoryId)
          }));
          const res = await fetch(`${apiUrl}/products/bulk`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
            body: JSON.stringify(productsToSync)
          });
          if (res.ok) {
            results.success.push(`${pendingProducts.length} Productos sincronizados`);
            clearPendingProducts();
          } else {
            results.failed.push(`Lote de productos (${pendingProducts.length})`);
          }
        } catch (e) { 
          results.failed.push(`Lote de productos (Error conexión)`);
          console.error('Error sincronizando productos', e); 
        }
      }

      // 3. Sincronizar Clientes
      for (const cust of pendingCustomers) {
        try {
          const res = await fetch(`${apiUrl}/customers`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
            body: JSON.stringify({
              name: cust.name,
              idNumber: cust.idNumber,
              phone: cust.phone,
              email: cust.email,
              address: cust.address,
              initialDebt: cust.initialDebt, // Campo corregido: se envía deuda inicial
              localId: cust.localId
            })
          });
          if (res.ok) {
            const savedCust = await res.json();
            if (cust.localId && savedCust.id) customerIdMapping[cust.localId] = savedCust.id;
            removePendingCustomer(cust.localId);
            results.success.push(`Cliente: ${cust.name}`);
          } else {
            results.failed.push(`Cliente: ${cust.name} (Error servidor)`);
          }
        } catch (e) { 
          results.failed.push(`Cliente: ${cust.name} (Error conexión)`);
          console.error('Error sincronizando cliente', e); 
        }
      }

      // 4. Sincronizar Ventas
      for (const sale of pendingSales) {
        try {
          const isTempCustomer = !!sale.customerId?.startsWith('temp-cust-');
          const finalCustomerId = isTempCustomer ? customerIdMapping[sale.customerId as string] : sale.customerId;

          // Si el cliente era temporal y NO se pudo sincronizar, saltamos esta venta para evitar error de FK
          if (isTempCustomer && !finalCustomerId) {
            results.failed.push(`Venta: $${sale.total} (Cliente no sincronizado)`);
            continue;
          }
          
          const res = await fetch(`${apiUrl}/sales`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
            body: JSON.stringify({ ...sale, customerId: finalCustomerId })
          });
          if (res.ok) {
            const savedSale = await res.json();
            if (sale.paymentMethod === 'credito' && savedSale.creditSale?.id) {
               salesCreditIdMapping[sale.localId] = savedSale.creditSale.id;
            }
            removePendingSale(sale.localId);
            results.success.push(`Venta: $${sale.total}`);
          } else {
            results.failed.push(`Venta: $${sale.total} (Error servidor)`);
          }
        } catch (e) { 
          results.failed.push(`Venta: $${sale.total} (Error conexión)`);
          console.error('Error sincronizando venta', e); 
        }
      }

      // 5. Sincronizar Abonos
      for (const pay of pendingPayments) {
        try {
          const finalCreditId = (pay.creditSaleId && salesCreditIdMapping[pay.creditSaleId as string]) ? salesCreditIdMapping[pay.creditSaleId as string] : pay.creditSaleId;

          if (pay.creditSaleId?.startsWith('temp-') && !finalCreditId) {
             results.failed.push(`Abono: $${pay.amount} (Crédito original no sincronizado)`);
             continue;
          }

          const res = await fetch(`${apiUrl}/sales/credits/${finalCreditId}/partial-payment`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
            body: JSON.stringify({ amount: pay.amount, notes: pay.notes, localId: pay.localId })
          });
          if (res.ok) {
            removePendingPayment(pay.localId);
            results.success.push(`Abono: $${pay.amount}`);
          } else {
            results.failed.push(`Abono: $${pay.amount} (Error servidor)`);
          }
        } catch (e) { 
          results.failed.push(`Abono: $${pay.amount} (Error conexión)`);
          console.error('Error sincronizando abono', e); 
        }
      }

      console.log('Sincronización completa finalizada.');
      
      // Mostrar resumen detallado
      let summary = 'PROCESO DE SINCRONIZACIÓN FINALIZADO\n\n';
      if (results.success.length > 0) {
        summary += `✅ ÉXITOS (${results.success.length}):\n- ${results.success.join('\n- ')}\n\n`;
      }
      if (results.failed.length > 0) {
        summary += `❌ FALLOS (${results.failed.length}):\n- ${results.failed.join('\n- ')}\n\n`;
        summary += 'Los elementos fallidos permanecerán marcados como "Pendiente" para intentarlo más tarde.';
      } else {
        summary += '¡Todos los datos se sincronizaron correctamente!';
      }
      
      alert(summary);

    } catch (error) {
      console.error('Error general en sincronización', error);
      alert('Error inesperado durante la sincronización. Por favor intente de nuevo.');
    } finally {
      setIsSyncing(false);
      // Notificar a otros componentes que la sincronización terminó
      window.dispatchEvent(new Event('sync-finished'));
    }
  };

  return null; // Componente lógico, no renderiza nada
}

import { useState, useCallback } from 'react';

export const useUSBScale = () => {
  const [weight, setWeight] = useState<number>(0);
  const [isReading, setIsReading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const connectAndRead = useCallback(async () => {
    if (!('serial' in navigator)) {
      setError('Tu navegador no soporta comunicación USB Serial (Usa Chrome o Edge).');
      return;
    }

    setIsReading(true);
    setError(null);

    let port: any = null;
    let reader: any = null;

    try {
      // Solicitar acceso al puerto
      port = await (navigator as any).serial.requestPort();
      
      // Abrir con configuración estándar (BaudRate 9600 es muy común en pesas)
      await port.open({ baudRate: 9600, dataBits: 8, stopBits: 1, parity: 'none' });

      // Preparar el lector de texto
      const textDecoder = new TextDecoderStream();
      const readableStreamClosed = port.readable?.pipeTo(textDecoder.writable);
      reader = textDecoder.readable.getReader();

      let buffer = '';
      
      // Leer durante un breve periodo (ej: 2 segundos de ráfaga) para capturar el peso actual
      const timeout = setTimeout(() => {
        if (reader) reader.cancel();
      }, 3000);

      while (true) {
        const { value, done } = await reader.read();
        if (done) break;
        if (value) {
          buffer += value;
          
          // Intentar extraer el peso si detectamos un cambio de línea o fin de trama
          if (buffer.includes('\n') || buffer.includes('\r')) {
            const lines = buffer.split(/[\r\n]+/);
            // Tomamos la última línea completa (que suele ser la más reciente)
            for (let i = lines.length - 2; i >= 0; i--) {
              const cleaned = lines[i].replace(/[^\d.]/g, ''); // Limpiar todo menos números y punto
              const parsed = parseFloat(cleaned);
              if (!isNaN(parsed) && parsed > 0) {
                setWeight(parsed);
                clearTimeout(timeout);
                await reader.cancel();
                break;
              }
            }
          }
        }
      }

      await readableStreamClosed?.catch(() => { /* Ignore */ });
      await port.close();
      
    } catch (err: any) {
      console.error('Error leyendo la pesa:', err);
      if (err.name === 'NotFoundError') {
        setError('No se seleccionó ninguna pesa.');
      } else if (err.name === 'SecurityError') {
        setError('Permiso denegado para el puerto serial.');
      } else {
        setError('Error al conectar con la pesa. Verifica la conexión.');
      }
    } finally {
      setIsReading(false);
    }
  }, []);

  return { weight, isReading, error, connectAndRead, setWeight };
};

import { create } from 'zustand';
import { persist, StateStorage, createJSONStorage } from 'zustand/middleware';
import { get, set, del } from 'idb-keyval';

// Adaptador de idb-keyval para Zustand
const storage: StateStorage = {
  getItem: async (name: string): Promise<string | null> => {
    return (await get(name)) || null;
  },
  setItem: async (name: string, value: string): Promise<void> => {
    await set(name, value);
  },
  removeItem: async (name: string): Promise<void> => {
    await del(name);
  },
};

export interface OfflineSale {
  localId: string;
  items: any[];
  total: number;
  paymentMethod: string;
  receivedAmount: number;
  changeAmount: number;
  customerId?: string | null;
  isCredit: boolean;
  timestamp: number;
}

interface OfflineState {
  isOnline: boolean;
  products: any[];
  categories: any[];
  customers: any[];
  rawCredits: any[]; // Para caché de deudas
  pendingSales: OfflineSale[];
  pendingProducts: any[];
  pendingCategories: any[];
  pendingCustomers: any[];
  pendingPayments: any[];
  lastSyncTime: number | null;
  setIsOnline: (status: boolean) => void;
  setCache: (data: { products?: any[]; categories?: any[]; customers?: any[]; rawCredits?: any[] }) => void;

  addPendingSale: (sale: OfflineSale) => void;
  removePendingSale: (localId: string) => void;
  clearPendingSales: () => void;

  addPendingProduct: (product: any) => void;
  removePendingProduct: (localId: string) => void;
  clearPendingProducts: () => void;

  addPendingCategory: (category: any) => void;
  removePendingCategory: (localId: string) => void;
  clearPendingCategories: () => void;

  addPendingCustomer: (customer: any) => void;
  removePendingCustomer: (localId: string) => void;
  clearPendingCustomers: () => void;

  addPendingPayment: (payment: any) => void;
  removePendingPayment: (localId: string) => void;
  clearPendingPayments: () => void;

  setLastSyncTime: (time: number) => void;
}

export const useOfflineStore = create<OfflineState>()(
  persist(
    (set) => ({
      isOnline: typeof window !== 'undefined' ? navigator.onLine : true,
      products: [],
      categories: [],
      customers: [],
      rawCredits: [],
      pendingSales: [],
      pendingProducts: [],
      pendingCategories: [],
      pendingCustomers: [],
      pendingPayments: [],
      lastSyncTime: null,
      setIsOnline: (status) => set({ isOnline: status }),
      setCache: (data) => set((state) => ({ ...state, ...data })),
      addPendingSale: (sale) =>
        set((state) => ({ pendingSales: [...state.pendingSales, sale] })),
      removePendingSale: (localId) =>
        set((state) => ({
          pendingSales: state.pendingSales.filter((s) => s.localId !== localId),
        })),
      clearPendingSales: () => set({ pendingSales: [] }),

      // Productos
      addPendingProduct: (product) => set((state) => ({
        pendingProducts: [...state.pendingProducts, product],
        // También lo metemos al caché local para que se vea inmediatamente
        products: [product, ...state.products]
      })),
      removePendingProduct: (localId) => set((state) => ({
        pendingProducts: state.pendingProducts.filter((p) => p.localId !== localId),
      })),
      clearPendingProducts: () => set({ pendingProducts: [] }),

      // Categorías
      addPendingCategory: (category) => set((state) => ({
        pendingCategories: [...state.pendingCategories, category],
        categories: [category, ...state.categories]
      })),
      removePendingCategory: (localId) => set((state) => ({
        pendingCategories: state.pendingCategories.filter((c) => c.localId !== localId),
      })),
      clearPendingCategories: () => set({ pendingCategories: [] }),

      // Clientes
      addPendingCustomer: (customer) => set((state) => ({
        pendingCustomers: [...state.pendingCustomers, customer],
        customers: [customer, ...state.customers]
      })),
      removePendingCustomer: (localId) => set((state) => ({
        pendingCustomers: state.pendingCustomers.filter((c) => c.localId !== localId),
      })),
      clearPendingCustomers: () => set({ pendingCustomers: [] }),

      // Pagos
      addPendingPayment: (payment) => set((state) => ({
        pendingPayments: [...state.pendingPayments, payment]
      })),
      removePendingPayment: (localId) => set((state) => ({
        pendingPayments: state.pendingPayments.filter((p) => p.localId !== localId),
      })),
      clearPendingPayments: () => set({ pendingPayments: [] }),

      setLastSyncTime: (time) => set({ lastSyncTime: time }),
    }),
    {
      name: 'tiendeo-offline-storage', // key in IndexedDB
      storage: createJSONStorage(() => storage),
    }
  )
);
